-- Poems batch 392
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('song-ci-972','西江月','张伯端','宋','宋词','song-ci','西江月','[]','若要真铅留汞，亲中不离家臣。',58,'宋词/ci.song.0.json','["若要真铅留汞，亲中不离家臣。", "木金间隔会无因。", "须仗媒人勾引。", "本性爱金顺义，金情恋木慈仁。", "相吞相陷却相亲。", "始觉男儿有孕。"]'),
('song-ci-973','西江月','张伯端','宋','宋词','song-ci','西江月','[]','二八谁家姹女，九三何处郎君。',58,'宋词/ci.song.0.json','["二八谁家姹女，九三何处郎君。", "自称木液与金精。", "遇土却成三性。", "更假丁公煅炼，夫妻始结欢情。", "河车不敢暂留停。", "运入昆仑峰顶。"]'),
('song-ci-974','西江月','张伯端','宋','宋词','song-ci','西江月','[]','七返朱砂反本，九还金液还真。',58,'宋词/ci.song.0.json','["七返朱砂反本，九还金液还真。", "休将寅子数坤申。", "但要五行成准。", "本是水银一味，周流遍历诸辰。", "阴阳数足自通神。", "出入岂离玄牝。"]'),
('song-ci-975','西江月','张伯端','宋','宋词','song-ci','西江月','[]','雄里内含雌质，负阴抱却阳精。',58,'宋词/ci.song.0.json','["雄里内含雌质，负阴抱却阳精。", "两般和合药方成。", "点化魄纤魂胜。", "信道金丹一粒，蛇吞立变龙形。", "鸡餐亦乃化鸾鹏。", "飞入真阳清境。"]'),
('song-ci-976','西江月','张伯端','宋','宋词','song-ci','西江月','[]','天地才经否泰，朝昏好识屯蒙。',58,'宋词/ci.song.0.json','["天地才经否泰，朝昏好识屯蒙。", "辐来辏毂水朝宗。", "妙在抽添运用。", "得一万般皆毕，休分南北西东。", "损之又损慎前功。", "命宝不宜轻弄。"]'),
('song-ci-977','西江月','张伯端','宋','宋词','song-ci','西江月','[]','冬至一阳来服，三旬增一阳爻。',58,'宋词/ci.song.0.json','["冬至一阳来服，三旬增一阳爻。", "月中复卦溯晨潮。", "望罢乾终姤兆。", "日又别为寒暑，阳生复起中宵。", "午时姤象一阴朝。", "炼药须知昏晓。"]'),
('song-ci-978','西江月','张伯端','宋','宋词','song-ci','西江月','[]','不辨五行四象，那分朱汞铅银。',58,'宋词/ci.song.0.json','["不辨五行四象，那分朱汞铅银。", "修丹火候未曾闻。", "早便称呼居隐。", "不背自思己错，更将错路教人。", "误他永劫在迷津。", "似恁欺心安忍。"]'),
('song-ci-979','西江月','张伯端','宋','宋词','song-ci','西江月','[]','德行修逾八百，阴功积满三千。',58,'宋词/ci.song.0.json','["德行修逾八百，阴功积满三千。", "均齐物我与亲冤。", "始合神仙本愿。", "虎兕刀兵不害，无常火宅难牵。", "宝符降后去朝天。", "稳驾鸾车凤辇。"]'),
('song-ci-980','西江月','张伯端','宋','宋词','song-ci','西江月','[]','牛女情缘道合，龟蛇类秉天然。',58,'宋词/ci.song.0.json','["牛女情缘道合，龟蛇类秉天然。", "蟾乌遇朔合婵娟。", "二气相资运转。", "本是乾坤妙用，谁能达此深渊。", "阳阴否隔却成愆。", "怎得天长地远。"]'),
('song-ci-981','西江月','张伯端','宋','宋词','song-ci','西江月','[]','丹是色身至宝，炼成变化无穷。',58,'宋词/ci.song.0.json','["丹是色身至宝，炼成变化无穷。", "更於性上究真宗。", "决了死生妙用。", "不待他身后世，现前获福神通。", "自从龙虎著斯功。", "尔后谁能继踵。"]'),
('song-ci-982','西江月','张伯端','宋','宋词','song-ci','西江月','[]','妄想不须强灭，真如何必希求。',58,'宋词/ci.song.0.json','["妄想不须强灭，真如何必希求。", "本源自性佛齐修。", "迷悟岂拘先后。", "悟则刹那成佛。", "迷则万劫沦流。", "若能一念契真修。", "灭尽恒沙罪垢。"]'),
('song-ci-983','西江月','张伯端','宋','宋词','song-ci','西江月','[]','本自无生无灭，强将生灭区分。',58,'宋词/ci.song.0.json','["本自无生无灭，强将生灭区分。", "只如罪福亦何根。", "妙体何曾增损。", "我有一轮明镜，从来只为蒙分。", "今朝磨莹照乾坤。", "万象超然难隐。"]'),
('song-ci-984','西江月','张伯端','宋','宋词','song-ci','西江月','[]','我性入诸佛性，诸方佛性皆然。',58,'宋词/ci.song.0.json','["我性入诸佛性，诸方佛性皆然。", "亭亭蟾影照寒泉。", "一月千潭普现。", "小则毫分莫识，大时遍满三千。", "高低不约信方圆。", "说甚短长深浅。"]'),
('song-ci-985','西江月','张伯端','宋','宋词','song-ci','西江月','[]','法法法元无法，空空空亦非空。',58,'宋词/ci.song.0.json','["法法法元无法，空空空亦非空。", "静喧语默本来同。", "梦里何曾说梦。", "有用用中无用，无功功里施功。", "还如果熟自然红。", "莫问如何修种。"]'),
('song-ci-986','西江月','张伯端','宋','宋词','song-ci','西江月','[]','善恶一时妄念，荣枯都不关心。',58,'宋词/ci.song.0.json','["善恶一时妄念，荣枯都不关心。", "晦明隐显任浮沈。", "随分肌餐渴饮。", "神静湛然常寂，不妨坐卧歌吟。", "一池秋水碧仍深。", "风动鱼惊尽任。"]'),
('song-ci-987','西江月','张伯端','宋','宋词','song-ci','西江月','[]','对镜不须强灭，假名权立菩提。',58,'宋词/ci.song.0.json','["对镜不须强灭，假名权立菩提。", "色空明暗本来齐。", "真妄体分两种。", "悟则便名静土，更无天竺曹溪。", "谁言极乐在天西。", "了则弥陀出世。"]'),
('song-ci-988','西江月','张伯端','宋','宋词','song-ci','西江月','[]','人我众生寿者，宁分彼此高低。',58,'宋词/ci.song.0.json','["人我众生寿者，宁分彼此高低。", "法身通照没吾伊。", "念念体分同异。", "见是何曾是是，闻非未必非非。", "往来诸用不相知。", "生死谁能碍你。"]'),
('song-ci-989','西江月','张伯端','宋','宋词','song-ci','西江月','[]','住想修行布施，果报不离天人。',58,'宋词/ci.song.0.json','["住想修行布施，果报不离天人。", "恰如仰箭射浮云。", "坠落祗缘力尽。", "争似无为实相，还须返朴归淳。", "境忘情性任天真。", "以证无生法忍。"]'),
('song-ci-990','西江月','张伯端','宋','宋词','song-ci','西江月','[]','鱼兔若还入手，自然忘却筌蹄。',58,'宋词/ci.song.0.json','["鱼兔若还入手，自然忘却筌蹄。", "渡河筏子上天梯。", "到彼悉皆遗弃。", "未悟须凭言说，悟来言说皆非。", "虽然四句属无为。", "此等何须脱离。"]'),
('song-ci-991','西江月','张伯端','宋','宋词','song-ci','西江月','[]','悟了莫求寂灭，随缘只接群迷。',58,'宋词/ci.song.0.json','["悟了莫求寂灭，随缘只接群迷。", "寻常邪见及提携。", "方便指归实际。", "五眼三身四智，六度万行修齐。", "圆光一颗好摩尼。", "利物兼能自利。"]'),
('song-ci-992','西江月','张伯端','宋','宋词','song-ci','西江月','[]','我见时人说性，只夸口急酬机。',58,'宋词/ci.song.0.json','["我见时人说性，只夸口急酬机。", "及逢境界转痴迷。", "又与愚人何异。", "说得便须行得，方名言行无亏。", "能将慧剑斩魔魑。", "此号如来正智。"]'),
('song-ci-993','西江月','张伯端','宋','宋词','song-ci','西江月','[]','欲了无生妙道，莫如自见真心。',58,'宋词/ci.song.0.json','["欲了无生妙道，莫如自见真心。", "真心无相亦无音。", "清净法身只恁。", "此道非无外有，非中亦莫求寻。", "二边俱遣弃中心。", "见了名为上品。"]'),
('song-ci-994','满庭芳','张伯端','宋','宋词','song-ci','满庭芳','[]','真铁牛儿，形容丑恶，性刚偏好争驰。',116,'宋词/ci.song.0.json','["真铁牛儿，形容丑恶，性刚偏好争驰。", "人人皆有，那角解牵骑。", "种就黄芽满院，更须用、神水浇之。", "宫里，若无此兽，安得似婴儿。", "乾坤真动静，生成家活，总赖於伊。", "饥餐虎髓，渴饮水银池。", "夜半牵车进火，霞光迸、海底腾辉。", "牧童笑，华池宴罢，乘个月明归。"]'),
('song-ci-995','凤栖梧・蝶恋花','卢氏','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','蜀道青天烟霭翳。',70,'宋词/ci.song.0.json','["蜀道青天烟霭翳。", "帝里繁华、迢递何时至。", "回望锦川挥粉泪。", "凤钗斜亸乌云腻。", "钿带双垂金缕细。", "玉珮玎珰，露滴寒如水。", "从此鸾妆添远意。", "画眉学得遥山翠。"]'),
('song-ci-996','家山好','刘述','宋','宋词','song-ci','家山好','[]','挂冠归去旧烟萝。',69,'宋词/ci.song.0.json','["挂冠归去旧烟萝。", "闲身健，养天和。", "功名富贵非由我，莫贪他。", "这歧路、足风波。", "水晶宫里家山好，物外胜游多。", "晴溪短棹，时时醉唱里棱罗。", "天公奈我何。"]'),
('song-ci-997','合宫歌','赵祯','宋','宋词','song-ci','合宫歌','[]','缵重明。',161,'宋词/ci.song.0.json','["缵重明。", "端拱保凝命。", "广大孝休德，永锡四海有庆。", "觚坛寓礼正典名。", "幔室雅奏，彩仗崇制定。", "五位仿古甚盛。", "蒿宫光符辰星。", "高秋嘉时款芎灵。", "交累圣。", "上下来顾，寅畏歆纯诚。", "三阶平。", "金气肃，转和景。", "翠葆御双观，巽风兑泽布令。", "脂茶剗荡墨索清。", "远迩向附，动植咸遂性。", "表里穆悦，庶政醇醲，熙然胥庭。", "唐舜华封祝，如南山寿永。", "愿今广怀宁延，昌基扃。"]'),
('song-ci-998','沁园春','王拱辰','宋','宋词','song-ci','沁园春','[]','华发青云。',5,'宋词/ci.song.0.json','["华发青云。"]'),
('song-ci-999','好事近','蔡襄','宋','宋词','song-ci','好事近','[]','瑞雪满京都，宫殿尽成银阙。',53,'宋词/ci.song.0.json','["瑞雪满京都，宫殿尽成银阙。", "常对素光遥望，是江梅时节。", "如今江上见寒梅，幽香自清绝。", "重看落英残艳，想飘零如雪。"]'),
('song-ci-0','踏莎行','韩绛','宋','宋词','song-ci','踏莎行','[]','嵩峤云高，洛川波暖。',68,'宋词/ci.song.1000.json','["嵩峤云高，洛川波暖。", "举头乔木森无断。", "□□□雨绝风尘，小桥频过春渠满。", "□□离宫，□棱斗焕。", "万家罗绮多游伴。", "□□□□自风□，□□是处喧弦管。"]'),
('song-ci-1','菩萨蛮','李师中','宋','宋词','song-ci','菩萨蛮','[]','子规啼破城楼月。',52,'宋词/ci.song.1000.json','["子规啼破城楼月。", "画船晓载笙歌发。", "两岸荔枝红。", "万家烟雨中。", "佳人相对泣。", "泪下罗衣湿。", "从此信音稀。", "岭南无雁飞。"]'),
('song-ci-2','喜迁莺','蔡挺','宋','宋词','song-ci','喜迁莺','[]','霜天清晓。',126,'宋词/ci.song.1000.json','["霜天清晓。", "望紫塞古垒，寒云衰草。", "汗马嘶风，边鸿翻月，垅上铁衣寒早。", "剑歌骑曲悲壮，尽道君恩难报。", "塞垣乐，尽双鞬锦带，山西年少。", "谈笑。", "刁斗静。", "烽火一把，常送平安耗。", "圣主忧边，威灵遐布，骄虏且宽天讨。", "岁华向晚愁思，谁念玉关人老。", "太平也，且欢娱，不惜金尊频倒。"]'),
('song-ci-3','喜长新','王益柔','宋','宋词','song-ci','喜长新','[]','秋云朔吹晓徘徊。',55,'宋词/ci.song.1000.json','["秋云朔吹晓徘徊。", "雪照楼台。", "梁王宴召有邹枚。", "相如独逞雄才。", "明烛薰炉香暖，深劝金杯。", "庭前粉艳有寒梅。", "一枝昨夜先开。"]'),
('song-ci-4','西江月','韩维','宋','宋词','song-ci','西江月','[]','早岁相期林下，高年同在尊前。',58,'宋词/ci.song.1000.json','["早岁相期林下，高年同在尊前。", "风花绣舞乍晴天。", "绿蚁新浮酒面。", "身外虚名电转，人间急景梭传。", "当筵莫惜听朱弦。", "一品归来强健。"]'),
('song-ci-5','踏莎行','韩维','宋','宋词','song-ci','踏莎行','[]','归雁低空，游蜂趁暖。',68,'宋词/ci.song.1000.json','["归雁低空，游蜂趁暖。", "凭高目向西云断。", "具茨山外夕阳多，展江亭下春波满。", "双桂情深，千花明焕。", "良辰谁是同游伴。", "辛夷花谢早梅开。", "应须次第调弦管。"]'),
('song-ci-6','减字木兰花','韩维','宋','宋词','song-ci','减字木兰花','[]','和风动□。',52,'宋词/ci.song.1000.json','["和风动□。", "□□新年□入手。", "世事尘□。", "□□□情近酒□。", "水开湖□。", "□□笙歌波面起。", "相与排□。", "□□□胜特地□。"]'),
('song-ci-7','浪淘沙','韩维','宋','宋词','song-ci','浪淘沙','[]','饱食日□□。',64,'宋词/ci.song.1000.json','["饱食日□□。", "□上危亭。", "东风昨夜入□□。", "□□雪晴云□□，□遍银屏。", "回首叹劳生。", "□鼎相承。", "皇恩早晚□□□。", "□□陂边垂钓手，不负幽情。"]'),
('song-ci-8','胡捣练令・胡捣练','韩维','宋','宋词','song-ci','胡捣练令・胡捣练','[]','夜来风横雨飞狂，满地闲花衰草。',56,'宋词/ci.song.1000.json','["夜来风横雨飞狂，满地闲花衰草。", "燕子渐归春悄。", "帘幕垂清晓。", "天将佳景与闲人，美酒宁嫌华皓。", "留取旧时欢笑。", "莫共秋光老。"]'),
('song-ci-9','失调名','韩维','宋','宋词','song-ci','失调名','[]','轻云薄雾。',11,'宋词/ci.song.1000.json','["轻云薄雾。", "散作催花雨。"]'),
('song-ci-10','失调名','韩维','宋','宋词','song-ci','失调名','[]','兄弟对举杯。',6,'宋词/ci.song.1000.json','["兄弟对举杯。"]'),
('song-ci-11','赏南枝','曾巩','宋','宋词','song-ci','赏南枝','[]','暮冬天地闭，正柔木冻折，瑞雪飘飞。',133,'宋词/ci.song.1000.json','["暮冬天地闭，正柔木冻折，瑞雪飘飞。", "对景见南山，岭梅露、几点清雅容姿。", "丹染萼、玉缀枝。", "又岂是、一阳有私。", "大抵是、化工独许，使占却先时。", "霜威莫苦凌持。", "此花根性，想群卉争知。", "贵用在和羹，三春里、不管绿是红非。", "攀赏处、宜酒卮。", "醉拈嗅、幽香更奇。", "倚阑干、仗何人去，嘱羌管休吹。"]'),
('song-ci-12','阮郎归','司马光','宋','宋词','song-ci','阮郎归','[]','渔舟容易入春山。',56,'宋词/ci.song.1000.json','["渔舟容易入春山。", "仙家日月闲。", "绮窗纱幌映朱颜。", "相逢醉梦间。", "松露冷，海霞殷。", "匆匆整棹还。", "落花寂寂水潺潺。", "重寻此路难。"]'),
('song-ci-13','西江月','司马光','宋','宋词','song-ci','西江月','[]','宝髻松松挽就，铅华淡淡妆成。',58,'宋词/ci.song.1000.json','["宝髻松松挽就，铅华淡淡妆成。", "青烟翠雾罩轻盈。", "飞絮游丝无定。", "相见争如不见，有情何似无情。", "笙歌散后酒初醒。", "深院月斜人静。"]'),
('song-ci-14','锦堂春・锦堂春慢','司马光','宋','宋词','song-ci','锦堂春・锦堂春慢','[]','红日迟迟，虚廊转影，槐阴迤逦西斜。',122,'宋词/ci.song.1000.json','["红日迟迟，虚廊转影，槐阴迤逦西斜。", "彩笔工夫，难状晚景烟霞。", "蝶尚不知春去，漫绕幽砌寻花。", "奈猛风过后，纵有残红，飞向谁家。", "始知青鬓无价，叹飘零官路，荏苒年华。", "今日笙歌丛里，特地咨嗟。", "席上青衫湿透，算感旧、何止琵琶。", "怎不教人易老，多少离愁，散在天涯。"]'),
('song-ci-15','临江仙','苏氏','宋','宋词','song-ci','临江仙','[]','一夜东风穿绣户，融融暖应佳时。',70,'宋词/ci.song.1000.json','["一夜东风穿绣户，融融暖应佳时。", "春来何处最先知。", "平明堤上柳。", "染遍郁金枝。", "姊妹嬉游时节近，今朝应怨来迟。", "凭谁说与到家期。", "玉钗头上胜，留待远人归。"]'),
('song-ci-16','更漏子','苏氏','宋','宋词','song-ci','更漏子','[]','小阑干，深院宇。',58,'宋词/ci.song.1000.json','["小阑干，深院宇。", "依旧当时别处。", "朱户锁，玉楼空。", "一帘霜日红。", "弄珠江，何处是，望断碧云无际。", "凝泪眼，出重城。", "隔溪羌笛声。"]'),
('song-ci-17','鹊桥仙','苏氏','宋','宋词','song-ci','鹊桥仙','[]','星移斗转，玉蟾西下，渐觉东郊向晓。',68,'宋词/ci.song.1000.json','["星移斗转，玉蟾西下，渐觉东郊向晓。", "马嘶人语隔霜林，望千里、长安古道。", "珠宫姊妹，相逢方信，别后十分瘦了。", "上林归去正花时，争奈向、花前又老。"]'),
('song-ci-18','踏莎行','苏氏','宋','宋词','song-ci','踏莎行','[]','孤馆深沈，晓寒天气。',68,'宋词/ci.song.1000.json','["孤馆深沈，晓寒天气。", "解鞍独自阑干倚。", "暗香浮动月黄昏，落梅风送沾衣袂。", "待写红笺，凭谁与寄。", "先教觅取嬉游地。", "到家正是早春时，小桃花下拼沈醉。"]'),
('song-ci-19','清平乐','刘敞','宋','宋词','song-ci','清平乐','[]','小山丛桂。',54,'宋词/ci.song.1000.json','["小山丛桂。", "最有留人意。", "拂叶攀花无限思。", "雨湿浓香满袂。", "别来过了秋光。", "翠帘昨夜新霜。", "多少月宫闲地，姮娥与借微芳。"]'),
('song-ci-20','踏莎行','刘敞','宋','宋词','song-ci','踏莎行','[]','蜡炬高高，龙烟细细。',68,'宋词/ci.song.1000.json','["蜡炬高高，龙烟细细。", "玉楼十二门初闭。", "疏帘不卷水晶寒，小屏半掩琉璃翠。", "桃叶新声，榴花美味。", "南山宾客东山妓。", "利名不肯放人闲，忙中偷取工夫醉。"]'),
('song-ci-21','导引','王','宋','宋词','song-ci','导引','[]','忆玉清景，繁盛极当时。',59,'宋词/ci.song.1000.json','["忆玉清景，繁盛极当时。", "千古事难追。", "汉家别庙秋风起，空出奉宸衣。", "三山浮海日晖晖。", "羽盖共云飞。", "灵宫旧是栖真处，还望玉舆归。"]'),
('song-ci-22','发引','王','宋','宋词','song-ci','发引','[]','玉宸朝晚，忽掩赭黄衣。',59,'宋词/ci.song.1000.json','["玉宸朝晚，忽掩赭黄衣。", "愁雾锁金扉。", "蓬莱待得仙丹至，人世已成非。", "龙轩天仗转西畿。", "旌旆入云飞。", "望陵宫女垂红泪，不见翠舆归。"]'),
('song-ci-23','发引','王','宋','宋词','song-ci','发引','[]','上林春晚，曾是奉宸游。',59,'宋词/ci.song.1000.json','["上林春晚，曾是奉宸游。", "水殿戏龙舟。", "玉箫吹断催仙驭，一去隔千秋。", "游人重到曲江头。", "事往涕难收。", "空馀御幄传觞处，依旧水东流。"]'),
('song-ci-24','凤箫吟・芳草','韩缜','宋','宋词','song-ci','凤箫吟・芳草','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','锁离愁，连绵无际，来时陌上初熏。',123,'宋词/ci.song.1000.json','["锁离愁，连绵无际，来时陌上初熏。", "绣帏人念远，暗垂珠泪，泣送征轮。", "长亭长在眼，更重重、远水孤云。", "但望极楼高，尽日目断王孙。", "消魂。", "池塘别后，曾行处、绿妒轻裙。", "恁时携素手，乱花飞絮里，缓步香裀。", "朱颜空自改，向年年、芳意长新。", "遍绿野，嬉游醉眠，莫负青春。"]'),
('song-ci-25','蝶恋花','韩缜姬','宋','宋词','song-ci','蝶恋花','[]','香作风光浓著露。',35,'宋词/ci.song.1000.json','["香作风光浓著露。", "正恁双栖，又遣分飞去。", "密诉东君应不许。", "泪波一洒奴衷素。"]'),
('song-ci-26','浪淘沙','裴湘','宋','宋词','song-ci','浪淘沙','[]','雁塞说并门。',64,'宋词/ci.song.1000.json','["雁塞说并门。", "郡枕西汾。", "山形高下远相吞。", "古寺楼台依碧嶂，烟景遥分。", "晋庙锁溪云。", "箫鼓仍存。", "牛羊斜日自归村。", "惟有故城禾黍地，前事消魂。"]'),
('song-ci-27','浪淘沙','裴湘','宋','宋词','song-ci','浪淘沙','[]','万国仰神京。',64,'宋词/ci.song.1000.json','["万国仰神京。", "礼乐纵横。", "葱葱佳气锁龙城。", "日御明堂天子圣，朝会簪缨。", "九陌六街平。", "万国充盈。", "青楼弦管酒如渑。", "别有隋堤烟柳暮，千古含情。"]'),
('song-ci-28','花心动','阮逸女','宋','宋词','song-ci','花心动','[]','仙苑春浓，小桃开，枝枝已堪攀折。',127,'宋词/ci.song.1000.json','["仙苑春浓，小桃开，枝枝已堪攀折。", "乍雨乍晴，轻暖轻寒，渐近赏花时节。", "柳摇台榭东风软，帘栊静、幽禽调舌。", "断魂远、闲寻翠径，顿成愁结。", "此恨无人共说。", "还立尽黄昏，寸心空切。", "强整绣衾，独掩朱扉，簟枕为谁铺设。", "夜长更漏传声远，纱窗映、银缸明灭。", "梦回处，梅梢半笼淡月。"]'),
('song-ci-29','蝶恋花','滕甫','宋','宋词','song-ci','蝶恋花','[]','叶底无风池面静。',70,'宋词/ci.song.1000.json','["叶底无风池面静。", "掬水佳人，拍破青铜镜。", "残月朦胧花弄影。", "新梳斜插乌云鬓。", "拍索闷怀添酒兴。", "旋撷园蔬，随分成盘饤。", "说与翠微休急性。", "功名富贵皆前定。"]'),
('song-ci-30','蝶恋花','滕甫','宋','宋词','song-ci','蝶恋花','[]','昼永无人深院静。',70,'宋词/ci.song.1000.json','["昼永无人深院静。", "一枕春醒，犹未忺临镜。", "帘卷新蟾光射影。", "速忙掠起蓬松鬓。", "对景沈吟嗟没兴。", "薄幸不来，空把杯盘饤。", "休道妇人多水性。", "今宵独自言无定。"]'),
('song-ci-31','桂枝香','王安石','宋','宋词','song-ci','桂枝香','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','登临送目。',124,'宋词/ci.song.1000.json','["登临送目。", "正故国晚秋，天气初肃。", "千里澄江似练，翠峰如簇。", "归帆去棹残阳里，背西风、酒旗斜矗。", "彩舟云淡，星河鹭起，画图难足。", "念往昔、繁华竞逐。", "叹门外楼头，悲恨相续。", "千古凭高，对此漫嗟荣辱。", "六朝旧事随流水，但寒烟、芳草凝绿。", "至今商女，时时犹唱，后庭遗曲。"]'),
('song-ci-32','甘露歌','王安石','宋','宋词','song-ci','甘露歌','[]','折得一枝香在手。',28,'宋词/ci.song.1000.json','["折得一枝香在手。", "人间应未有。", "疑是经春雪未消。", "今日是何朝。"]'),
('song-ci-33','甘露歌','王安石','宋','宋词','song-ci','甘露歌','[]','尽日含毫难比兴。',28,'宋词/ci.song.1000.json','["尽日含毫难比兴。", "都无色可并。", "万里晴天何处来。", "真是屑琼瑰。"]'),
('song-ci-34','甘露歌','王安石','宋','宋词','song-ci','甘露歌','[]','天寒日暮山谷里。',28,'宋词/ci.song.1000.json','["天寒日暮山谷里。", "的砾愁成水。", "池上渐多枝上稀。", "唯有故人知。"]'),
('song-ci-35','菩萨蛮','王安石','宋','宋词','song-ci','菩萨蛮','[]','数家茅屋闲临水。',52,'宋词/ci.song.1000.json','["数家茅屋闲临水。", "单衫短帽垂杨里。", "今日是何朝。", "看予度石桥。", "梢梢新月偃。", "午醉醒来晚。", "何物最关情。", "黄鹂三两声。"]'),
('song-ci-36','渔家傲','王安石','宋','宋词','song-ci','渔家傲','[]','灯火已收正月半。',72,'宋词/ci.song.1000.json','["灯火已收正月半。", "山南山北花撩乱。", "闻说洊亭新水漫。", "骑款段。", "穿云入坞寻游伴。", "却拂僧床褰素幔。", "千岩万壑春风暖。", "一弄松声悲急管。", "吹梦断。", "西看窗日犹嫌短。"]'),
('song-ci-37','渔家傲','王安石','宋','宋词','song-ci','渔家傲','[]','平岸小桥千嶂抱。',72,'宋词/ci.song.1000.json','["平岸小桥千嶂抱。", "柔蓝一水萦花草。", "茅屋数间窗窈窕。", "尘不到。", "时时自有春风扫。", "午枕觉来闻语鸟。", "敧眠似听朝鸡早。", "忽忆故人今总老。", "贪梦好。", "茫然忘了邯郸道。"]'),
('song-ci-38','雨霖铃','王安石','宋','宋词','song-ci','雨霖铃','[]','孜孜矻矻。',125,'宋词/ci.song.1000.json','["孜孜矻矻。", "向无明里、强作窠窟。", "浮名浮利何济，堪留恋处，轮回仓猝。", "幸有明空妙觉，可弹指超出。", "缘底事、抛了全潮，认一浮沤作瀛渤。", "本源自性天真佛。", "祗些些、妄想中埋没。", "贪他眼花阳艳，谁信道、本来无物。", "一旦茫然，终被阎罗老子相屈。", "便纵有、千种机筹，怎免伊唐突。"]'),
('song-ci-39','清平乐','王安石','宋','宋词','song-ci','清平乐','[]','云垂平野。',55,'宋词/ci.song.1000.json','["云垂平野。", "掩映竹篱茅舍。", "阒寂幽居实潇洒。", "是处绿娇红冶。", "丈夫运用堂堂。", "且莫五角六张。", "若有一卮芳酒，逍遥自在无妨。"]'),
('song-ci-40','浣溪沙','王安石','宋','宋词','song-ci','浣溪沙','[]','百亩中庭半是苔。',48,'宋词/ci.song.1000.json','["百亩中庭半是苔。", "门前白道水萦回。", "爱闲能有几人来。", "小院回廊春寂寂，山桃溪杏两三栽。", "为谁零落为谁开。"]'),
('song-ci-41','诉衷情','王安石','宋','宋词','song-ci','诉衷情','[]','常时黄色见眉间。',54,'宋词/ci.song.1000.json','["常时黄色见眉间。", "松桂我同攀。", "每言天上辛苦，不肯饵金丹。", "怜水静，爱云闲。", "便忘还。", "高歌一曲，岩谷迤逦，宛似商山。"]'),
('song-ci-42','诉衷情','王安石','宋','宋词','song-ci','诉衷情','[]','练巾藜杖白云间。',54,'宋词/ci.song.1000.json','["练巾藜杖白云间。", "有兴即跻攀。", "追思往昔如梦，华毂也曾丹。", "尘自扰，性长闲。", "更无还。", "达如周召，穷似丘轲，祗个山山。"]'),
('song-ci-43','诉衷情','王安石','宋','宋词','song-ci','诉衷情','[]','茫然不肯住林间。',54,'宋词/ci.song.1000.json','["茫然不肯住林间。", "有处即追攀。", "将他死语图度，怎得离真丹。", "浆水价，匹如闲。", "也须还。", "何如直截，踢倒军持，赢取沩山。"]'),
('song-ci-44','诉衷情','王安石','宋','宋词','song-ci','诉衷情','[]','营巢燕子逞翱翔。',54,'宋词/ci.song.1000.json','["营巢燕子逞翱翔。", "微志在雕梁。", "碧云举翮千里，其奈有鸾皇。", "临济处，德山行。", "果承当。", "自时降住，一切天魔，扫地焚香。"]'),
('song-ci-45','诉衷情','王安石','宋','宋词','song-ci','诉衷情','[]','莫言普化祗颠狂。',54,'宋词/ci.song.1000.json','["莫言普化祗颠狂。", "真解作津梁。", "蓦然打个筋斗，直跳过羲皇。", "临济处，德山行。", "果承当。", "将他建立，认作心诚，也是寻香。"]'),
('song-ci-46','南乡子','王安石','宋','宋词','song-ci','南乡子','[]','嗟见世间人。',66,'宋词/ci.song.1000.json','["嗟见世间人。", "但有纤毫即是尘。", "不住旧时无相貌，沈沦。", "祗为从来认识神。", "作麽有疏亲。", "我自降魔转法轮。", "不是摄心除妄想，求真。", "幻化空身即法身。"]'),
('song-ci-47','南乡子','王安石','宋','宋词','song-ci','南乡子','["\u957f\u6c5f"]','自古帝王州。',66,'宋词/ci.song.1000.json','["自古帝王州。", "郁郁葱葱佳气浮。", "四百年来成一梦，堪愁。", "晋代衣冠成古丘。", "绕水恣行游。", "上尽层城更上楼。", "往事悠悠君莫问，回头。", "槛外长江空自流。"]'),
('song-ci-48','浪淘沙令','王安石','宋','宋词','song-ci','浪淘沙令','[]','伊吕两衰翁。',64,'宋词/ci.song.1000.json','["伊吕两衰翁。", "历遍穷通。", "一为钓叟一耕佣。", "若使当时身不遇，老了英雄。", "汤武偶相逢。", "风虎云龙。", "兴王祗在笑谈中。", "直至如今千载后，谁与争功。"]'),
('song-ci-49','望江南・忆江南','王安石','宋','宋词','song-ci','望江南・忆江南','[]','归依众，梵行四威仪。',32,'宋词/ci.song.1000.json','["归依众，梵行四威仪。", "愿我遍游诸佛土。", "十方贤圣不相离。", "永灭世间痴。"]'),
('song-ci-50','望江南・忆江南','王安石','宋','宋词','song-ci','望江南・忆江南','[]','归依法，法法不思议。',32,'宋词/ci.song.1000.json','["归依法，法法不思议。", "愿我六根常寂静，心如宝月映琉璃。", "了法更无疑。"]'),
('song-ci-51','望江南・忆江南','王安石','宋','宋词','song-ci','望江南・忆江南','[]','归依佛，弹指越三祗。',32,'宋词/ci.song.1000.json','["归依佛，弹指越三祗。", "愿我速登无上觉，还如佛坐道场时。", "能智又能悲。"]'),
('song-ci-52','望江南・忆江南','王安石','宋','宋词','song-ci','望江南・忆江南','[]','三界里，有取总灾危。',32,'宋词/ci.song.1000.json','["三界里，有取总灾危。", "普愿众生同我愿，能於空有善思惟。", "三宝共住持。"]'),
('song-ci-53','西江月','王安石','宋','宋词','song-ci','西江月','[]','梅好惟嫌淡伫，天教薄与胭脂。',58,'宋词/ci.song.1000.json','["梅好惟嫌淡伫，天教薄与胭脂。", "真妃初出华清池。", "酒入琼姬半醉。", "东阁诗情易动，高楼玉管休吹。", "北人浑作杏花疑。", "惟有青枝不似。"]'),
('song-ci-54','渔家傲','王安石','宋','宋词','song-ci','渔家傲','[]','隔岸桃花红未半。',36,'宋词/ci.song.1000.json','["隔岸桃花红未半。", "枝头已有蜂儿乱。", "惆怅武陵人不管。", "清梦断。", "亭亭伫立春宵短。"]'),
('song-ci-55','清平乐','王安石','宋','宋词','song-ci','清平乐','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','留春不住。',54,'宋词/ci.song.1000.json','["留春不住。", "费尽莺儿语。", "满地残红宫锦污。", "昨夜南园风雨。", "小怜初上琵琶。", "晓来思绕天涯。", "不肯画堂朱户，春风自在杨花。"]'),
('song-ci-56','生查子','王安石','宋','宋词','song-ci','生查子','[]','雨打江南树。',52,'宋词/ci.song.1000.json','["雨打江南树。", "一夜花开无数。", "绿叶渐成阴，下有游人归路。", "与君相逢处。", "不道春将暮。", "把酒祝东风，且莫恁、匆匆去。"]'),
('song-ci-57','谒金门','王安石','宋','宋词','song-ci','谒金门','[]','春又老。',54,'宋词/ci.song.1000.json','["春又老。", "南陌酒香梅小。", "遍地落花浑不扫。", "梦回情意悄。", "红笺寄与添烦恼。", "细写相思多少。", "醉后几行书字小。", "泪痕都搵了。"]'),
('song-ci-58','菩萨蛮','王安石','宋','宋词','song-ci','菩萨蛮','[]','海棠乱发皆临水。',52,'宋词/ci.song.1000.json','["海棠乱发皆临水。", "君知此处花何似。", "凉月白纷纷。", "香风隔岸闻。", "啭枝黄鸟近。", "隔岸声相应。", "随意坐莓苔。", "飘零酒一杯。"]'),
('song-ci-59','千秋岁引','王安石','宋','宋词','song-ci','千秋岁引','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','别馆寒砧，孤城画角。',98,'宋词/ci.song.1000.json','["别馆寒砧，孤城画角。", "一派秋声入寥廓。", "东归燕从海上去，南来雁向沙头落。", "楚台风，庾楼月，宛如昨。", "无奈被些名利缚。", "无奈被他情担阁。", "可惜风流总闲却。", "当初漫留华表语，而今误我秦楼约。", "梦阑时，酒醒后，思量著。"]'),
('song-ci-60','定风波','吴氏1','宋','宋词','song-ci','定风波','[]','待得明年重把酒。',19,'宋词/ci.song.1000.json','["待得明年重把酒。", "携手。", "那知无雨又无风。"]'),
('song-ci-61','蜡梅香','吴师孟','宋','宋词','song-ci','蜡梅香','[]','锦里阳和，看万木凋时，早梅独秀。',124,'宋词/ci.song.1000.json','["锦里阳和，看万木凋时，早梅独秀。", "珍馆琼楼畔，正降跗初吐，秾华将茂。", "国艳天葩，真澹伫、雪肌清瘦。", "似广寒宫，铅华未御，自然妆就。", "凝睇倚朱阑，喷清香暗度，易袭襟袖。", "好与花为主，宜秉烛、频观泛湘酎。", "莫待南枝，随乐府、新声吹后。", "对赏心人，良辰好景，须信难偶。"]'),
('song-ci-62','阮郎归','俞紫芝','宋','宋词','song-ci','阮郎归','[]','钓鱼船上谢三郎。',54,'宋词/ci.song.1000.json','["钓鱼船上谢三郎。", "双鬓已苍苍。", "蓑衣未必清贵，不肯换金章。", "汀草畔，浦花旁。", "静鸣榔。", "自来好个，渔父家风，一片潇湘。"]'),
('song-ci-63','临江仙','俞紫芝','宋','宋词','song-ci','临江仙','[]','弄水亭前千万景，登临不忍空回。',68,'宋词/ci.song.1000.json','["弄水亭前千万景，登临不忍空回。", "水轻墨澹写蓬莱。", "莫教世眼，容易洗尘埃。", "收去雨昏都不见，展时还似云开。", "先生高趣更多才。", "人人尽道，小杜却重来。"]'),
('song-ci-64','苏幕遮','俞紫芝','宋','宋词','song-ci','苏幕遮','[]','地锺灵，天应瑞。',76,'宋词/ci.song.1000.json','["地锺灵，天应瑞。", "簇簇香苞、团作真珠蕊。", "玉宇瑶台分十二。", "要伴姮娥，月里双双睡。", "月如花，花似月。", "花月生香，添此真奇异。", "不许扬州夸间气。", "昨夜春风，唤醒琼琼醉。"]'),
('song-ci-65','失调名','郑獬','宋','宋词','song-ci','失调名','[]','玉环妾意无渝。',16,'宋词/ci.song.1000.json','["玉环妾意无渝。", "问君心、朝槿何如。"]'),
('song-ci-66','好事近','郑獬','宋','宋词','song-ci','好事近','[]','江上探春回，正值早梅时节。',53,'宋词/ci.song.1000.json','["江上探春回，正值早梅时节。", "两行小槽双凤，按凉州初彻。", "谢娘扶下绣鞍来，红靴踏残雪。", "归去不须银烛，有山头明月。"]'),
('song-ci-67','好事近','郑獬','宋','宋词','song-ci','好事近','[]','把酒对江梅，花小未禁风力。',53,'宋词/ci.song.1000.json','["把酒对江梅，花小未禁风力。", "何计不教零落，为青春留得。", "故人莫问在天涯，尊前苦相忆。", "好把素香收取，寄江南消息。"]'),
('song-ci-68','渔家傲','强至','宋','宋词','song-ci','渔家傲','[]','雪月照梅溪畔路。',72,'宋词/ci.song.1000.json','["雪月照梅溪畔路。", "幽姿背立无言语。", "冷浸瘦枝清浅处。", "香暗度。", "妆成处士横斜句。", "浑似玉人常淡伫。", "菱花相对盈清楚。", "谁解小图先画取。", "天欲曙。", "恐随月色云间去。"]'),
('song-ci-69','踏莎行','沈注','宋','宋词','song-ci','踏莎行','[]','竹阁云深，巢虚人阒。',34,'宋词/ci.song.1000.json','["竹阁云深，巢虚人阒。", "几年湖上音尘寂。", "风流今有使君家，月明夜夜闻双笛。"]'),
('song-ci-70','望梅花','蒲宗孟','宋','宋词','song-ci','望梅花','[]','一阳初起。',84,'宋词/ci.song.1000.json','["一阳初起。", "暖力未胜寒气。", "堪赏素华长独秀，不并开红抽紫。", "青帝只应怜洁白，不使雷同众卉。", "淡然难比。", "粉蝶岂知芳蕊。", "半夜卷帘如乍失，只在银蟾影里。", "残雪枝头君认取，自有清香旖旎。"]'),
('song-ci-71','减字木兰花','陈汝羲','宋','宋词','song-ci','减字木兰花','[]','纤纤素手。',52,'宋词/ci.song.1000.json','["纤纤素手。", "盘里醉花新点就。", "对叶双心。", "别有东风意思深。", "琼沾粉缀。", "消得玉堂留客醉。", "试嗅清芳。", "别有红罗巧袖香。"]'),
('song-ci-72','行香子','汪辅之','宋','宋词','song-ci','行香子','[]','晚绿寒红。',84,'宋词/ci.song.1000.json','["晚绿寒红。", "芳意匆匆。", "惜年华、今与谁同。", "碧云零落，数字宾鸿。", "看渚莲凋，宫扇旧，怨秋风。", "流波坠叶，佳期何在，想天教、离恨无穷。", "试将前事，闲倚梧桐。", "有销魂处，明月夜，锦屏空。"]'),
('song-ci-73','鹧鸪天','范纯仁','宋','宋词','song-ci','鹧鸪天','[]','腊后春前暖律催。',64,'宋词/ci.song.1000.json','["腊后春前暖律催。", "日和风软欲开梅。", "公方结客寻佳景，我亦忘形趁酒杯。", "添歌管，续尊罍。", "更阑烛短未能回。", "清欢莫待相期约，乘兴来时便可来。"]'),
('song-ci-74','雨中花・夜行船','张才翁','宋','宋词','song-ci','雨中花・夜行船','[]','万缕青青，初眠官柳，向人犹未成阴。',118,'宋词/ci.song.1000.json','["万缕青青，初眠官柳，向人犹未成阴。", "据雕鞍马上，拥鼻微吟。", "远宦情怀谁问，空嗟壮志销沈。", "正好花时节，山城留滞、忍负归心。", "别离万里，飘蓬无定，谁念会合难凭。", "相聚里，休辞金盏，酒浅还深。", "欲把春愁抖擞，春愁转更难禁。", "乱山高处，凭阑垂袖，聊寄登临。"]'),
('song-ci-75','渔家傲','寿涯禅师','宋','宋词','song-ci','渔家傲','[]','深愿弘慈无缝罅。',72,'宋词/ci.song.1000.json','["深愿弘慈无缝罅。", "乘时走入众生界。", "窈窕丰姿都没赛。", "提鱼卖。", "堪笑马郎来纳败。", "清冷露湿金襽坏。", "茜裙不把珠缨盖。", "特地掀来呈捏怪。", "牵人爱。", "还尽许多菩萨债。"]'),
('song-ci-76','水龙吟','章','宋','宋词','song-ci','水龙吟','[]','燕忙莺懒花残，正堤上、柳花飘坠。',126,'宋词/ci.song.1000.json','["燕忙莺懒花残，正堤上、柳花飘坠。", "轻飞点画青林，谁道全无才思。", "闲趁游丝，静临深院，日长门闭。", "傍珠帘散漫，垂垂欲下，依前被，风扶起。", "兰帐玉人睡觉，怪春衣、雪粘琼缀。", "绣床旋满，香球无数，才圆却碎。", "时见蜂儿，仰粘轻粉，鱼吹池水。", "望章台路杳，金鞍游荡，有盈盈泪。"]'),
('song-ci-77','声声令・胜胜令','章','宋','宋词','song-ci','声声令・胜胜令','[]','帘移碎影，香褪衣襟。',83,'宋词/ci.song.1000.json','["帘移碎影，香褪衣襟。", "旧家庭院嫩苔侵。", "东风过尽，暮云锁，绿窗深。", "怕对人、闲枕剩衾。", "楼底轻阴。", "春信断，怯登临。", "断肠魂梦两沈沈。", "花飞水远，便从今。", "莫追寻。", "又怎禁、蓦地上心。"]'),
('song-ci-78','渔父乐・渔歌子','徐积','宋','宋词','song-ci','渔父乐・渔歌子','[]','水曲山隈四五家。',32,'宋词/ci.song.1000.json','["水曲山隈四五家。", "夕阳烟火隔芦花。", "渔唱歇，醉眠斜。", "纶竿蓑笠是生涯。"]'),
('song-ci-79','渔父乐・渔歌子','徐积','宋','宋词','song-ci','渔父乐・渔歌子','[]','见说红尘罩九衢。',32,'宋词/ci.song.1000.json','["见说红尘罩九衢。", "贪名逐利各区区。", "论得失，问荣枯。", "争似侬家占五湖。"]'),
('song-ci-80','渔父乐・渔歌子','徐积','宋','宋词','song-ci','渔父乐・渔歌子','[]','讨得渔竿买得船。',32,'宋词/ci.song.1000.json','["讨得渔竿买得船。", "归休何必待高年。", "深浪里，乱云边。", "只有逍遥是水仙。"]'),
('song-ci-81','渔父乐・渔歌子','徐积','宋','宋词','song-ci','渔父乐・渔歌子','[]','饱则高歌醉即眠。',32,'宋词/ci.song.1000.json','["饱则高歌醉即眠。", "只知头白不知年。", "江绕屋，水随船。", "买得风光不著钱。"]'),
('song-ci-82','渔父乐・渔歌子','徐积','宋','宋词','song-ci','渔父乐・渔歌子','[]','管得江湖占得山。',32,'宋词/ci.song.1000.json','["管得江湖占得山。", "白云同散学云闲。", "清旦出，夕阳还。", "不知身在画屏间。"]'),
('song-ci-83','渔父乐・渔歌子','徐积','宋','宋词','song-ci','渔父乐・渔歌子','[]','一酌村醪一曲歌。',32,'宋词/ci.song.1000.json','["一酌村醪一曲歌。", "回看尘世足风波。", "忧患大，是非多。", "纵得荣华有几何。"]'),
('song-ci-84','开元乐・三台','沈括','宋','宋词','song-ci','开元乐・三台','[]','鹳鹊楼头日暖，蓬莱殿里花香。',28,'宋词/ci.song.1000.json','["鹳鹊楼头日暖，蓬莱殿里花香。", "草绿烟迷步辇，天高日近龙床。"]'),
('song-ci-85','开元乐・三台','沈括','宋','宋词','song-ci','开元乐・三台','[]','楼上正临宫外，人间不见仙家。',28,'宋词/ci.song.1000.json','["楼上正临宫外，人间不见仙家。", "寒食轻烟薄雾，满城明月梨花。"]'),
('song-ci-86','开元乐・三台','沈括','宋','宋词','song-ci','开元乐・三台','[]','按舞骊山影里，回銮渭水光中。',28,'宋词/ci.song.1000.json','["按舞骊山影里，回銮渭水光中。", "玉笛一天明月，翠华满陌东风。"]'),
('song-ci-87','开元乐・三台','沈括','宋','宋词','song-ci','开元乐・三台','[]','殿后春旗簇仗，楼前御队穿花。',28,'宋词/ci.song.1000.json','["殿后春旗簇仗，楼前御队穿花。", "一片红云闹处，外人遥认官家。"]'),
('song-ci-88','失调名','范宽之','宋','宋词','song-ci','失调名','[]','谢娘栀子，贾妃萸佩。',10,'宋词/ci.song.1000.json','["谢娘栀子，贾妃萸佩。"]'),
('song-ci-89','黄鹤引','方资','宋','宋词','song-ci','黄鹤引','[]','生逢垂拱。',101,'宋词/ci.song.1000.json','["生逢垂拱。", "不识干戈免田陇。", "士林书圃终年，庸非天宠。", "才初闒茸。", "老去支离何用。", "浩然归弄。", "似黄鹤、秋风相送。", "尘事塞翁心，浮世庄生梦。", "漾舟遥指烟波，群山森动。", "神闲意耸。", "回首利鞿名鞚。", "此情谁共。", "问几斛、淋浪春瓮。"]'),
('song-ci-90','点绛唇','王安国','宋','宋词','song-ci','点绛唇','[]','秋气微凉，梦回明月穿帘幕。',50,'宋词/ci.song.1000.json','["秋气微凉，梦回明月穿帘幕。", "井梧萧索。", "正绕南枝鹊。", "宝瑟尘生，金雁空零落。", "情无托。", "鬓云慵掠。", "不似君恩薄。"]'),
('song-ci-91','清平乐','王安国','宋','宋词','song-ci','清平乐','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','留春不住。',54,'宋词/ci.song.1000.json','["留春不住。", "费尽莺儿语。", "满地残红宫锦污。", "昨夜南园风雨。", "小怜初上琵琶。", "晓来思绕天涯。", "不肯画堂朱户，春风自在梨花。"]'),
('song-ci-92','减字木兰花','王安国','宋','宋词','song-ci','减字木兰花','[]','画桥流水。',52,'宋词/ci.song.1000.json','["画桥流水。", "雨湿落红飞不起。", "月破黄昏。", "帘里馀香马上闻。", "徘徊不语。", "今夜梦魂何处去。", "不似垂杨。", "犹解飞花入洞房。"]'),
('song-ci-93','菩萨蛮','孙洙','宋','宋词','song-ci','菩萨蛮','[]','楼头上有三冬鼓。',52,'宋词/ci.song.1000.json','["楼头上有三冬鼓。", "何须抵死催人去。", "上马苦匆匆。", "琵琶曲未终。", "回头肠断处。", "却更廉纤雨。", "漫道玉为堂。", "玉堂今夜长。"]'),
('song-ci-94','河满子','孙洙','宋','宋词','song-ci','河满子','[]','怅望浮生急景，凄凉宝瑟馀音。',86,'宋词/ci.song.1000.json','["怅望浮生急景，凄凉宝瑟馀音。", "楚客多情偏怨别，碧山远水登临。", "目送连天衰草，夜阑几处疏砧。", "黄叶无风自落，秋云不雨长阴。", "天若有情天亦老，摇摇幽恨难禁。", "惆怅旧欢如梦，觉来无处追寻。"]'),
('song-ci-95','失调名','李清臣','宋','宋词','song-ci','失调名','[]','杨花落。',50,'宋词/ci.song.1000.json','["杨花落。", "燕子穿朱阁。", "苦恨春醪如水薄。", "闲愁无处著。", "去年今日王陵舍，鼓角秋风。", "千岁辽东。", "回首人间万事空。"]'),
('song-ci-96','减字木兰花','韦骧','宋','宋词','song-ci','减字木兰花','[]','人生可意。',52,'宋词/ci.song.1000.json','["人生可意。", "祗说功名贪富贵。", "遇景开怀。", "且尽生前有限杯。", "韶华几许。", "鹈鴂声残无觅处。", "莫自因循。", "一片花飞减却春。"]'),
('song-ci-97','减字木兰花','韦骧','宋','宋词','song-ci','减字木兰花','[]','金貂贳酒。',52,'宋词/ci.song.1000.json','["金貂贳酒。", "乐事可为须趁手。", "且醉青春。", "白发何曾饶贵人。", "凤笙鼍鼓。", "况是桃花落红雨。", "莫诉觥筹。", "炊熟黄粱一梦休。"]'),
('song-ci-98','减字木兰花','韦骧','宋','宋词','song-ci','减字木兰花','[]','鸾坡凤沼。',52,'宋词/ci.song.1000.json','["鸾坡凤沼。", "轩冕傥来何足道。", "存养天真。", "安用浮名绊此身。", "劳生逸老。", "摆脱纷华须是早。", "解绶眠云。", "林下何曾见一人。"]'),
('song-ci-99','减字木兰花','韦骧','宋','宋词','song-ci','减字木兰花','[]','危楼引望。',52,'宋词/ci.song.1000.json','["危楼引望。", "天气犹寒花未放。", "远思悠悠。", "芳草何年恨即休。", "仙踪何处。", "此去蓬山多少路。", "春霭腾腾。", "更在瑶台十二层。"]'),
('song-ci-100','减字木兰花','韦骧','宋','宋词','song-ci','减字木兰花','[]','帝城春媚。',52,'宋词/ci.song.1000.json','["帝城春媚。", "绿柳参天花照地。", "共乐升平。", "处处楼台歌板声。", "香轮玉镫。", "驰骤芳郊争选胜。", "妙舞轻讴。", "扰乱春风卒未休。"]'),
('song-ci-101','菩萨蛮','韦骧','宋','宋词','song-ci','菩萨蛮','[]','琼杯且尽清歌送。',52,'宋词/ci.song.1000.json','["琼杯且尽清歌送。", "人生离合真如梦。", "瞬息又春归。", "回头光景非。", "香喷金兽暖。", "欢意愁更短。", "白发不须量。", "从教千丈长。"]'),
('song-ci-102','鹊桥仙','韦骧','宋','宋词','song-ci','鹊桥仙','[]','岁华将暮，寒林萧索，极目冻云垂地。',68,'宋词/ci.song.1000.json','["岁华将暮，寒林萧索，极目冻云垂地。", "官梅忽见一枝芳，便顿觉、新春情味。", "小筵开处，歌喉清婉，舞态蹁跹争媚。", "沈腰潘鬓两休论，共举白、何须惜醉。"]'),
('song-ci-103','减字木兰花','韦骧','宋','宋词','song-ci','减字木兰花','[]','雕阑香砌。',52,'宋词/ci.song.1000.json','["雕阑香砌。", "红紫妖韶何足计。", "争似幽芳。", "几朵先春蘸碧塘。", "玉盘金盏。", "谁谓花神情有限。", "绰约仙姿。", "仿佛江皋解佩时。"]'),
('song-ci-104','洛阳春・一落萦','韦骧','宋','宋词','song-ci','洛阳春・一落萦','[]','冷艳幽香奇绝。',56,'宋词/ci.song.1000.json','["冷艳幽香奇绝。", "粉金裁雪。", "无端又欲恨春风，恨不解、千千结。", "曲槛小池清切。", "倚烟笼月。", "佳人纤手傍柔条，似不忍、轻攀折。"]'),
('song-ci-105','醉蓬莱','韦骧','宋','宋词','song-ci','醉蓬莱','[]','漏新春消耗，柳眼微青，素梅犹小。',120,'宋词/ci.song.1000.json','["漏新春消耗，柳眼微青，素梅犹小。", "帘幕轻寒，引炉烟袅袅。", "凤管雍容，雁筝清切，对绮筵呈妙。", "此际欢虞，门庭自有，辉光荣耀。", "庆事难逢，世间须信，八十遐龄，古来稀少。", "况偶佳辰，是桑弧曾表。", "满奉金觥，暂停牙板，听雅歌精祷。", "惟愿增高，龟年鹤算，鸿恩紫诏。"]'),
('song-ci-106','沁园春','韦骧','宋','宋词','song-ci','沁园春','[]','林叶阴浓，海云峰耸，夏景渐分。',141,'宋词/ci.song.1000.json','["林叶阴浓，海云峰耸，夏景渐分。", "称画堂开宴，雍雍笑语，高年耆德，初弄君恩。", "汉相家声，一经传训，赏典今朝归庆门。", "清和昼，见香飘百和，乐按长春。", "休论。", "万事纷纭。", "算寿考、乡闾能几人。", "况凤书才降，龟龄正永，莫辞金盏，一醉醺醺。", "萱草忘忧，榴花含笑，庭院风光如再新。", "成欢颂，愿齐坚桧柏，频奉丝纶。"]'),
('song-ci-107','渔家傲','圆禅师','宋','宋词','song-ci','渔家傲','[]','本是潇湘一钓客。',72,'宋词/ci.song.1000.json','["本是潇湘一钓客。", "自东自西自南北。", "只把孤舟为屋宅。", "无宽窄。", "幕天席地人难测。", "顷闻四海停戈革。", "金门懒去投书册。", "时向滩头歌月白。", "真高格。", "浮名浮利谁拘得。"]'),
('song-ci-108','满庭芳','则禅师','宋','宋词','song-ci','满庭芳','[]','咄这牛儿，身强力健，几人能解牵骑。',118,'宋词/ci.song.1000.json','["咄这牛儿，身强力健，几人能解牵骑。", "为贪原上，嫩草绿离离。", "只管寻芳逐翠，奔驰后、不顾倾危。", "争知道，山遥水远，回首到家迟。", "牧童，今有智，长绳牢把，短杖高提。", "入泥入水，终是不生疲。", "直待心调步稳，青松下、孤笛横吹。", "当归去，人牛不见，正是月明时。"]'),
('song-ci-109','八声甘州','陈偕','宋','宋词','song-ci','八声甘州','[]','芰荷风、涤面恰麦秋，应倒著春衣。',119,'宋词/ci.song.1000.json','["芰荷风、涤面恰麦秋，应倒著春衣。", "渡晓溪云湿，日流尘脚，露滉蛛丝。", "调翼受风雏燕，弱不解争泥。", "衬琅玕锦院，竹外蔷薇。", "立久阑干凭暖，看行鱼吹沫，波晕平池。", "藓痕斑础石，渐雨熟梅时。", "傍短篱、成团粉蝶，掠野花、相逐□高低。", "忘言处，徽弦乍拂，流水先知。"]'),
('song-ci-110','满庭芳','陈偕','宋','宋词','song-ci','满庭芳','[]','岚影浮春，云容阁雨，澄泓碧展玻璃。',117,'宋词/ci.song.1000.json','["岚影浮春，云容阁雨，澄泓碧展玻璃。", "高低楼观，窗户舞涟漪。", "别有轻盈水面，清讴起、舟叶如飞。", "沙堤上，垂鞭信马，柳重绿交枝。", "渐残红倒影，金波潋滟，弦管催归。", "看飘香陈粉，满路扶携。", "不尽湖边风月，孤山下、猿鸟须知。", "东风里、年年此水，贮尽是和非。"]'),
('song-ci-111','满庭芳','陈偕','宋','宋词','song-ci','满庭芳','[]','榆荚抛钱，桃英胎子，杨花已送春归。',118,'宋词/ci.song.1000.json','["榆荚抛钱，桃英胎子，杨花已送春归。", "未成萍叶，水面绿纹肥。", "沙暖溪禽行哺，忘机处、雏母相随。", "重帘静，铜壶昼歇，声度竹间棋。", "人生如意少，乐随春减，恨为情离。", "怕牵愁勾怨，渐近金徽。", "浮世更相代谢，江头明月，渡口斜晖。", "关情处，摩挲钓石，莫遣上苔衣。"]'),
('song-ci-112','临江仙','晏几道','宋','宋词','song-ci','临江仙','[]','斗草阶前初见，穿针楼上曾逢。',68,'宋词/ci.song.1000.json','["斗草阶前初见，穿针楼上曾逢。", "罗裙香露玉钗风。", "靓妆眉沁绿，羞脸粉生红。", "流水便随春远，行云终与谁同。", "酒醒长恨锦屏空。", "相寻梦里路，飞雨落花中。"]'),
('song-ci-113','临江仙','晏几道','宋','宋词','song-ci','临江仙','[]','身外闲愁空满，眼中欢事常稀。',68,'宋词/ci.song.1000.json','["身外闲愁空满，眼中欢事常稀。", "明年应赋送君诗。", "细从今夜数，相会几多时。", "浅酒欲邀谁劝，深情惟有君知。", "东溪春近好同归。", "柳垂江上影，梅谢雪中枝。"]'),
('song-ci-114','临江仙','晏几道','宋','宋词','song-ci','临江仙','[]','淡水三年欢意，危弦几夜离情。',68,'宋词/ci.song.1000.json','["淡水三年欢意，危弦几夜离情。", "晓霜红叶舞归程。", "客情今古道，秋梦短长亭。", "渌酒尊前清泪，阳关叠里离声。", "少陵诗思旧才名。", "云鸿相约处，烟雾九重城。"]'),
('song-ci-115','临江仙','晏几道','宋','宋词','song-ci','临江仙','[]','浅浅馀寒春半，雪消蕙草初长。',68,'宋词/ci.song.1000.json','["浅浅馀寒春半，雪消蕙草初长。", "烟迷柳岸旧池塘。", "风吹梅蕊闹，雨细杏花香。", "月堕枝头欢意，从前虚梦高唐，觉来何处放思量。", "如今不是梦，真个到伊行。"]'),
('song-ci-116','临江仙','晏几道','宋','宋词','song-ci','临江仙','[]','长爱碧阑干影，芙蓉秋水开时。',68,'宋词/ci.song.1000.json','["长爱碧阑干影，芙蓉秋水开时。", "脸红凝露学娇啼。", "霞觞熏冷艳，云髻袅纤枝。", "烟雨依前时候，霜丛如旧芳菲。", "与谁同醉采香归。", "去年花下客，今似蝶分飞。"]'),
('song-ci-117','临江仙','晏几道','宋','宋词','song-ci','临江仙','[]','旖旎仙花解语，轻盈春柳能眠。',68,'宋词/ci.song.1000.json','["旖旎仙花解语，轻盈春柳能眠。", "玉楼深处绮窗前。", "梦回芳草夜，歌罢落梅天。", "沈水浓熏绣被，流霞浅酌金船。", "绿娇红小正堪怜。", "莫如云易散，须似月频圆。"]'),
('song-ci-118','临江仙','晏几道','宋','宋词','song-ci','临江仙','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','梦后楼台高锁，酒醒帘幕低垂。',68,'宋词/ci.song.1000.json','["梦后楼台高锁，酒醒帘幕低垂。", "去年春恨却来时。", "落花人独立，微雨燕双飞。", "记得小苹初见，两重心字罗衣。", "琵琶弦上说相思。", "当时明月在，曾照彩云归。"]'),
('song-ci-119','临江仙','晏几道','宋','宋词','song-ci','临江仙','[]','东野亡来无丽句，于君去后少交亲。',72,'宋词/ci.song.1000.json','["东野亡来无丽句，于君去后少交亲。", "追思往事好沾巾。", "白头王建在，犹见咏诗人。", "学道深山空自老，留名千载不干身。", "酒筵歌席莫辞频。", "争如南陌上，占取一年春。"]'),
('song-ci-120','蝶恋花','晏几道','宋','宋词','song-ci','蝶恋花','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','卷絮风头寒欲尽。',70,'宋词/ci.song.1000.json','["卷絮风头寒欲尽。", "坠粉飘红，日日香成阵。", "新酒又添残酒困。", "今春不减前春恨。", "蝶去莺飞无处问。", "隔水高楼，望断双鱼信。", "恼乱层波横一寸。", "斜阳只与黄昏近。"]'),
('song-ci-121','蝶恋花','晏几道','宋','宋词','song-ci','蝶恋花','[]','初拈霜纨生怅望。',70,'宋词/ci.song.1000.json','["初拈霜纨生怅望。", "隔叶莺声，似学秦娥唱。", "午睡醒来慵一饷。", "双纹翠簟铺寒浪。", "雨罢苹风吹碧涨。", "脉脉荷花，泪脸红相向。", "斜贴绿云新月上。", "弯环正是愁眉样。"]'),
('song-ci-122','蝶恋花','晏几道','宋','宋词','song-ci','蝶恋花','[]','庭院碧苔红叶遍。',70,'宋词/ci.song.1000.json','["庭院碧苔红叶遍。", "金菊开时，已近重阳宴。", "日日露荷凋绿扇。", "粉塘烟水澄如练。", "试倚凉风醒酒面。", "雁字来时，恰向层楼见。", "几点护霜云影转。", "谁家芦管吹秋怨。"]'),
('song-ci-123','蝶恋花','晏几道','宋','宋词','song-ci','蝶恋花','[]','喜鹊桥成催凤驾。',70,'宋词/ci.song.1000.json','["喜鹊桥成催凤驾。", "天为欢迟，乞与初凉夜。", "乞巧双蛾加意画。", "玉钩斜傍西南挂。", "分钿擘钗凉叶下。", "香袖凭肩，谁记当时话。", "路隔银河犹可借。", "世间离恨何年罢。"]'),
('song-ci-124','蝶恋花','晏几道','宋','宋词','song-ci','蝶恋花','[]','碧草池塘春又晚。',70,'宋词/ci.song.1000.json','["碧草池塘春又晚。", "小叶风娇，尚学娥妆浅。", "双燕来时还念远。", "珠帘绣户杨花满。", "绿柱频移弦易断。", "细看秦筝，正似人情短。", "一曲啼乌心绪乱。", "红颜暗与流年换。"]'),
('song-ci-125','蝶恋花','晏几道','宋','宋词','song-ci','蝶恋花','[]','碾玉钗头双凤小。',70,'宋词/ci.song.1000.json','["碾玉钗头双凤小。", "倒晕工夫，画得宫眉巧。", "嫩曲罗裙胜碧草。", "鸳鸯绣字春衫好。", "三月露桃芳意早。", "细看花枝，人面争多少。", "水调声长歌未了。", "掌中杯尽东池晓。"]'),
('song-ci-126','蝶恋花','晏几道','宋','宋词','song-ci','蝶恋花','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','醉别西楼醒不记。',70,'宋词/ci.song.1000.json','["醉别西楼醒不记。", "春梦秋云，聚散真容易。", "斜月半窗还少睡。", "画屏闲展吴山翠。", "衣上酒痕诗里字。", "点点行行，总是凄凉意。", "红烛自怜无好计。", "夜寒空替人垂泪。"]'),
('song-ci-127','蝶恋花','晏几道','宋','宋词','song-ci','蝶恋花','[]','欲减罗衣寒未去。',70,'宋词/ci.song.1000.json','["欲减罗衣寒未去。", "不卷珠帘，人在深深处。", "残杏枝头花几许。", "啼红正恨清明雨。", "尽日沈香烟一缕。", "宿酒醒迟，恼破春情绪。", "远信还因归燕误。", "小屏风上西江路。"]'),
('song-ci-128','蝶恋花','晏几道','宋','宋词','song-ci','蝶恋花','[]','千叶早梅夸百媚。',70,'宋词/ci.song.1000.json','["千叶早梅夸百媚。", "笑面凌寒，内样妆先试。", "月脸冰肌香细腻。", "风流新称东君意。", "一捻年光春有味。", "江北江南，更有谁相比。", "横玉声中吹满地。", "好枝长恨无人寄。"]'),
('song-ci-129','蝶恋花','晏几道','宋','宋词','song-ci','蝶恋花','[]','金翦刀头芳意动。',70,'宋词/ci.song.1000.json','["金翦刀头芳意动。", "彩蕊开时，不怕朝寒重。", "晴雪半消花䰒䰄。", "晓妆呵尽香酥冻。", "十二楼中双翠凤。", "缥缈歌声，记得江南弄。", "醉舞春风谁可共。", "秦云已有鸳屏梦。"]'),
('song-ci-130','蝶恋花','晏几道','宋','宋词','song-ci','蝶恋花','[]','笑艳秋莲生绿浦。',70,'宋词/ci.song.1000.json','["笑艳秋莲生绿浦。", "红脸青腰，旧识凌波女。", "照影弄妆娇欲语。", "西风岂是繁华主。", "可恨良辰天不与。", "才过斜阳，又是黄昏雨。", "朝落暮开空自许。", "竟无人解知心苦。"]'),
('song-ci-131','蝶恋花','晏几道','宋','宋词','song-ci','蝶恋花','[]','碧落秋风吹玉树。',70,'宋词/ci.song.1000.json','["碧落秋风吹玉树。", "翠节红旌，晚过银河路。", "休笑星机停弄杼。", "凤帏已在云深处。", "楼上金针穿绣缕。", "谁管天边，隔岁分飞苦。", "试等夜阑寻别绪。", "泪痕千点罗衣露。"]'),
('song-ci-132','蝶恋花','晏几道','宋','宋词','song-ci','蝶恋花','[]','碧玉高楼临水住。',70,'宋词/ci.song.1000.json','["碧玉高楼临水住。", "红杏开时，花底曾相遇。", "一曲阳春春已暮。", "晓莺声断朝云去。", "远水来从楼下路。", "过尽流波，未得鱼中素。", "月细风尖垂柳渡。", "梦魂长在分襟处。"]'),
('song-ci-133','蝶恋花','晏几道','宋','宋词','song-ci','蝶恋花','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','梦入江南烟水路。',70,'宋词/ci.song.1000.json','["梦入江南烟水路。", "行尽江南，不与离人遇。", "睡里消魂无说处。", "觉来惆怅消魂误。", "欲尽此情书尺素。", "浮雁沈鱼，终了无凭据。", "却倚缓弦歌别绪。", "断肠移破秦筝柱。"]'),
('song-ci-134','蝶恋花','晏几道','宋','宋词','song-ci','蝶恋花','[]','黄菊开时伤聚散。',70,'宋词/ci.song.1000.json','["黄菊开时伤聚散。", "曾记花前，共说深深愿。", "重见金英人未见。", "相思一夜天涯远。", "罗带同心闲结遍。", "带易成双，人恨成双晚。", "欲写彩笺书别怨。", "泪痕早已先书满。"]'),
('song-ci-135','鹧鸪天','晏几道','宋','宋词','song-ci','鹧鸪天','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','彩袖殷勤捧玉锺。',64,'宋词/ci.song.1000.json','["彩袖殷勤捧玉锺。", "当年拼却醉颜红。", "舞低杨柳楼心月，歌尽桃花扇影风。", "从别后，忆相逢。", "几回魂梦与君同。", "今宵剩把银釭照，犹恐相逢是梦中。"]'),
('song-ci-136','鹧鸪天','晏几道','宋','宋词','song-ci','鹧鸪天','[]','一醉醒来春又残。',64,'宋词/ci.song.1000.json','["一醉醒来春又残。", "野棠梨雨泪阑干。", "玉笙声里鸾空怨。", "罗幕香中燕未还。", "终易散，且长闲。", "莫教离恨损朱颜。", "谁堪共展鸳鸯锦，同过西楼此夜寒。"]'),
('song-ci-137','鹧鸪天','晏几道','宋','宋词','song-ci','鹧鸪天','[]','梅蕊新妆桂叶眉。',64,'宋词/ci.song.1000.json','["梅蕊新妆桂叶眉。", "小莲风韵出瑶池。", "云随绿水歌声转，雪绕红绡舞袖垂。", "伤别易，恨欢迟。", "惜无红锦为裁诗。", "行人莫便消魂去，汉渚星桥尚有期。"]'),
('song-ci-138','鹧鸪天','晏几道','宋','宋词','song-ci','鹧鸪天','[]','守得莲开结伴游。',64,'宋词/ci.song.1000.json','["守得莲开结伴游。", "约开萍叶上兰舟。", "来时浦口云随棹，采罢江边月满楼。", "花不语，水空流。", "年年拼得为花愁。", "明朝万一西风动，争向朱颜不耐秋。"]'),
('song-ci-139','鹧鸪天','晏几道','宋','宋词','song-ci','鹧鸪天','[]','斗鸭池南夜不归。',64,'宋词/ci.song.1000.json','["斗鸭池南夜不归。", "酒阑纨扇有新诗。", "云随碧玉歌声转，雪绕红琼舞袖回。", "今感旧，欲沾衣。", "可怜人似水东西。", "回头满眼凄凉事，秋月春风岂得知。"]'),
('song-ci-140','鹧鸪天','晏几道','宋','宋词','song-ci','鹧鸪天','[]','当日佳期鹊误传。',64,'宋词/ci.song.1000.json','["当日佳期鹊误传。", "至今犹作断肠仙。", "桥成汉渚星波外，人在鸾歌凤舞前。", "欢尽夜，别经年。", "别多欢少奈何天。", "情知此会无长计。", "咫尺凉蟾亦未圆。"]'),
('song-ci-141','鹧鸪天','晏几道','宋','宋词','song-ci','鹧鸪天','[]','题破香笺小砑红。',64,'宋词/ci.song.1000.json','["题破香笺小砑红。", "诗篇多寄旧相逢。", "西楼酒面垂垂雪，南苑春衫细细风。", "花不尽，柳无穷。", "别来欢事少人同。", "凭谁问取归云信，今在巫山第几峰。"]'),
('song-ci-142','鹧鸪天','晏几道','宋','宋词','song-ci','鹧鸪天','[]','清颍尊前酒满衣。',64,'宋词/ci.song.1000.json','["清颍尊前酒满衣。", "十年风月旧相知。", "凭谁细话当时事，肠断山长水远诗。", "金凤阙，玉龙墀。", "看君来换锦袍时。", "姮娥已有殷勤约，留著蟾宫第一枝。"]'),
('song-ci-143','鹧鸪天','晏几道','宋','宋词','song-ci','鹧鸪天','[]','醉拍春衫惜旧香。',64,'宋词/ci.song.1000.json','["醉拍春衫惜旧香。", "天将离恨恼疏狂。", "年年陌上生秋草，日日楼中到夕阳。", "云渺渺，水茫茫。", "征人归路许多长。", "相思本是无凭语，莫向花笺费泪行。"]'),
('song-ci-144','鹧鸪天','晏几道','宋','宋词','song-ci','鹧鸪天','[]','小令尊前见玉箫。',64,'宋词/ci.song.1000.json','["小令尊前见玉箫。", "银灯一曲太妖娆。", "歌中醉倒谁能恨，唱罢归来酒未消。", "春悄悄，夜迢迢。", "碧云天共楚宫遥。", "梦魂惯得无拘检，又踏杨花过谢桥。"]'),
('song-ci-145','鹧鸪天','晏几道','宋','宋词','song-ci','鹧鸪天','[]','楚女腰肢越女腮。',64,'宋词/ci.song.1000.json','["楚女腰肢越女腮。", "粉圆双蕊髻中开。", "朱弦曲怨愁春尽，渌酒杯寒记夜来。", "新掷果，旧分钗。", "冶游音信隔章台。", "花间锦字空频寄，月底金鞍竟未回。"]'),
('song-ci-146','鹧鸪天','晏几道','宋','宋词','song-ci','鹧鸪天','[]','十里楼台倚翠微。',64,'宋词/ci.song.1000.json','["十里楼台倚翠微。", "百花深处杜娟啼。", "殷勤自与行人语，不似流莺取次飞。", "惊梦觉，弄晴时。", "声声只道不如归。", "天涯岂是无归意，争奈归期未可期。"]'),
('song-ci-147','鹧鸪天','晏几道','宋','宋词','song-ci','鹧鸪天','[]','陌上濛濛残絮飞。',64,'宋词/ci.song.1000.json','["陌上濛濛残絮飞。", "杜娟花里杜娟啼。", "年年底事不归去，怨月愁烟长为谁。", "梅雨细，晓风微。", "倚楼人听欲沾衣。", "故园三度群花谢，曼倩天涯犹未归。"]'),
('song-ci-148','鹧鸪天','晏几道','宋','宋词','song-ci','鹧鸪天','[]','晓日迎长岁岁同。',64,'宋词/ci.song.1000.json','["晓日迎长岁岁同。", "太平箫鼓间歌钟。", "云高未有前村雪，梅小初开昨夜风。", "罗幕翠，锦筵红。", "钗头罗胜写宜冬。", "从今屈指春期近，莫使金尊对月空。"]'),
('song-ci-149','鹧鸪天','晏几道','宋','宋词','song-ci','鹧鸪天','[]','小玉楼中月上时。',64,'宋词/ci.song.1000.json','["小玉楼中月上时。", "夜来惟许月华知。", "重帘有意藏私语，双烛无端恼暗期。", "伤别易，恨欢迟。", "归来何处验相思。", "沈郎春雪愁消臂，谢女香膏懒画眉。"]'),
('song-ci-150','鹧鸪天','晏几道','宋','宋词','song-ci','鹧鸪天','[]','手拈香笺忆小莲。',64,'宋词/ci.song.1000.json','["手拈香笺忆小莲。", "欲将遗恨倩谁传。", "归来独卧逍遥夜，梦里相逢酩酊天。", "花易落，月难圆。", "只应花月似欢缘。", "秦筝算有心情在，试写离声入旧弦。"]'),
('song-ci-151','鹧鸪天','晏几道','宋','宋词','song-ci','鹧鸪天','[]','九日悲秋不到心。',64,'宋词/ci.song.1000.json','["九日悲秋不到心。", "凤城歌管有新音。", "风凋碧柳愁眉淡，露染黄花笑靥深。", "初见雁，已闻砧。", "绮罗丛里胜登临。", "须教月户纤纤玉，细捧霞觞滟滟金。"]'),
('song-ci-152','鹧鸪天','晏几道','宋','宋词','song-ci','鹧鸪天','[]','碧藕花开水殿凉。',64,'宋词/ci.song.1000.json','["碧藕花开水殿凉。", "万年枝外转红阳。", "升平歌管随天仗，祥瑞封章满御床。", "金掌露，玉炉香。", "岁华方共圣恩长。", "皇州又奏圜扉静，十样宫眉捧寿觞。"]'),
('song-ci-153','鹧鸪天','晏几道','宋','宋词','song-ci','鹧鸪天','[]','绿橘梢头几点春。',64,'宋词/ci.song.1000.json','["绿橘梢头几点春。", "似留香蕊送行人。", "明朝紫凤朝天路，十二重城五碧云。", "歌渐咽，酒初醺。", "尽将红泪湿湘裙。", "赣江西畔从今日，明月清风忆使君。"]'),
('song-ci-154','生查子','晏几道','宋','宋词','song-ci','生查子','[]','金鞭美少年，去跃青骢马。',48,'宋词/ci.song.1000.json','["金鞭美少年，去跃青骢马。", "牵系玉楼人，绣被春寒夜。", "消息未归来，寒食梨花谢。", "无处说相思，背面秋千下。"]'),
('song-ci-155','生查子','晏几道','宋','宋词','song-ci','生查子','[]','轻匀两脸花，淡扫双眉柳。',48,'宋词/ci.song.1000.json','["轻匀两脸花，淡扫双眉柳。", "会写锦笺时，学弄朱弦后。", "今春玉钏宽，昨夜罗裙皱。", "无计奈情何，且醉金杯酒。"]'),
('song-ci-156','生查子','晏几道','宋','宋词','song-ci','生查子','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','关山魂梦长，鱼雁音尘少。',48,'宋词/ci.song.1000.json','["关山魂梦长，鱼雁音尘少。", "两鬓可怜青，只为相思老。", "归梦碧纱窗，说与人人道。", "真个别离难，不似相逢好。"]'),
('song-ci-157','生查子','晏几道','宋','宋词','song-ci','生查子','[]','坠雨已辞云，流水难归浦。',48,'宋词/ci.song.1000.json','["坠雨已辞云，流水难归浦。", "遗恨几时休，心抵秋莲苦。", "忍泪不能歌，试托哀弦语。", "弦语愿相逢，知有相逢否。"]'),
('song-ci-158','生查子','晏几道','宋','宋词','song-ci','生查子','[]','一分残酒霞，两点愁蛾晕。',48,'宋词/ci.song.1000.json','["一分残酒霞，两点愁蛾晕。", "罗幕夜犹寒，玉枕春先困。", "心情翦彩慵，时节烧灯近。", "见少别离多，还有人堪恨。"]'),
('song-ci-159','生查子','晏几道','宋','宋词','song-ci','生查子','[]','轻轻制舞衣，小小裁歌扇。',48,'宋词/ci.song.1000.json','["轻轻制舞衣，小小裁歌扇。", "三月柳浓时，又向津亭见。", "垂泪送行人，湿破红妆面。", "玉指袖中弹，一曲清商怨。"]'),
('song-ci-160','生查子','晏几道','宋','宋词','song-ci','生查子','[]','红尘陌上游，碧柳堤边住。',48,'宋词/ci.song.1000.json','["红尘陌上游，碧柳堤边住。", "才趁彩云来，又逐飞花去。", "深深美酒家，曲曲幽香路。", "风月有情时，总是相思处。"]'),
('song-ci-161','生查子','晏几道','宋','宋词','song-ci','生查子','[]','长恨涉江遥，移近溪头住。',48,'宋词/ci.song.1000.json','["长恨涉江遥，移近溪头住。", "闲荡木兰舟，误入双鸳浦。", "无端轻薄云，暗作廉纤雨。", "翠袖不胜寒，欲向荷花语。"]'),
('song-ci-162','生查子','晏几道','宋','宋词','song-ci','生查子','[]','远山眉黛长，细柳腰肢袅。',48,'宋词/ci.song.1000.json','["远山眉黛长，细柳腰肢袅。", "妆罢立春风，一笑千金少。", "归去凤城时，说与青楼道。", "遍看颍川花，不似师师好。"]'),
('song-ci-163','生查子','晏几道','宋','宋词','song-ci','生查子','[]','落梅庭榭香，芳草池塘绿。',48,'宋词/ci.song.1000.json','["落梅庭榭香，芳草池塘绿。", "春恨最关情，日过阑干曲。", "几时花里闲，看得花枝足。", "醉后莫思家，借取师师宿。"]'),
('song-ci-164','生查子','晏几道','宋','宋词','song-ci','生查子','[]','狂花顷刻香，晚蝶缠绵意。',48,'宋词/ci.song.1000.json','["狂花顷刻香，晚蝶缠绵意。", "天与短因缘，聚散常容易。", "传唱入离声，恼乱双蛾翠。", "游子不堪闻，正是衷肠事。"]'),
('song-ci-165','生查子','晏几道','宋','宋词','song-ci','生查子','[]','官身几日闲，世事何时足。',48,'宋词/ci.song.1000.json','["官身几日闲，世事何时足。", "君貌不长红，我鬓无重绿。", "榴花满盏香，金缕多情曲。", "且尽眼中欢，莫叹时光促。"]'),
('song-ci-166','生查子','晏几道','宋','宋词','song-ci','生查子','[]','春从何处归，试向溪边问。',48,'宋词/ci.song.1000.json','["春从何处归，试向溪边问。", "岸柳弄娇黄，陇麦回青润。", "多情美少年，屈指芳菲近。", "谁寄岭头梅，来报江南信。"]'),
('song-ci-167','南乡子','晏几道','宋','宋词','song-ci','南乡子','[]','渌水带青潮。',66,'宋词/ci.song.1000.json','["渌水带青潮。", "水上朱阑小渡桥。", "桥上女儿双笑靥，妖娆。", "倚著阑干弄柳条。", "月夜落花朝。", "减字偷声按玉箫。", "柳外行人回首处，迢迢。", "若比银河路更遥。"]'),
('song-ci-168','南乡子','晏几道','宋','宋词','song-ci','南乡子','[]','小蕊受春风。',66,'宋词/ci.song.1000.json','["小蕊受春风。", "日日宫花花树中。", "恰向柳绵撩乱处，相逢。", "笑靥旁边心字浓。", "归路草茸茸。", "家在秦楼更近东。", "醒去醉来无限事，谁同。", "说著西池满面红。"]'),
('song-ci-169','南乡子','晏几道','宋','宋词','song-ci','南乡子','[]','花落未须悲。',66,'宋词/ci.song.1000.json','["花落未须悲。", "红蕊明年又满枝。", "惟有花间人别后，无期。", "水阔山长雁字迟。", "今日最相思。", "记得攀条话别离。", "共说春来春去事，多时。", "一点愁心入翠眉。"]'),
('song-ci-170','南乡子','晏几道','宋','宋词','song-ci','南乡子','[]','何处别时难。',66,'宋词/ci.song.1000.json','["何处别时难。", "玉指偷将粉泪弹。", "记得来时楼上烛，初残。", "待得清霜满画阑。", "不惯独眠寒。", "自解罗衣衬枕檀。", "百媚也应愁不睡，更阑。", "恼乱心情半被闲。"]'),
('song-ci-171','南乡子','晏几道','宋','宋词','song-ci','南乡子','[]','画鸭懒熏香。',66,'宋词/ci.song.1000.json','["画鸭懒熏香。", "绣茵犹展旧鸳鸯。", "不似同衾愁易晓，空床。", "细剔银灯怨漏长。", "几夜月波凉。", "梦魂随月到兰房。", "残睡觉来人又远，难忘。", "便是无情也断肠。"]'),
('song-ci-172','南乡子','晏几道','宋','宋词','song-ci','南乡子','[]','眼约也应虚。',66,'宋词/ci.song.1000.json','["眼约也应虚。", "昨夜归来凤枕孤。", "且据如今情分里，相於。", "只恐多时不似初。", "深意托双鱼。", "小翦蛮笺细字书。", "更把此情重问得，何如。", "共结因缘久远无。"]'),
('song-ci-173','南乡子','晏几道','宋','宋词','song-ci','南乡子','[]','新月又如眉。',66,'宋词/ci.song.1000.json','["新月又如眉。", "长笛谁教月下吹。", "楼倚暮云初见雁，南飞。", "漫道行人雁后归。", "意欲梦佳期。", "梦里关山路不知。", "却待短书来破恨，应迟。", "还是凉生玉枕时。"]'),
('song-ci-174','清平乐','晏几道','宋','宋词','song-ci','清平乐','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','留人不住。',54,'宋词/ci.song.1000.json','["留人不住。", "醉解兰舟去。", "一棹碧涛春水路。", "过尽晓莺啼处。", "渡头杨柳青青。", "枝枝叶叶离情。", "此后锦书休寄，画楼云雨无凭。"]'),
('song-ci-175','清平乐','晏几道','宋','宋词','song-ci','清平乐','[]','千花百草。',54,'宋词/ci.song.1000.json','["千花百草。", "送得春归了。", "拾蕊人稀红渐少。", "叶底杏青梅小。", "小琼闲抱琵琶。", "雪香微透轻纱。", "正好一枝娇艳，当筵独占韶华。"]'),
('song-ci-176','清平乐','晏几道','宋','宋词','song-ci','清平乐','[]','烟轻雨小。',54,'宋词/ci.song.1000.json','["烟轻雨小。", "紫陌香尘少。", "谢客池塘生绿草。", "一夜红梅先老。", "旋题罗带新诗。", "重寻杨柳佳期。", "强半春寒去后，几番花信来时。"]'),
('song-ci-177','清平乐','晏几道','宋','宋词','song-ci','清平乐','[]','可怜娇小。',54,'宋词/ci.song.1000.json','["可怜娇小。", "掌上承恩早。", "把镜不知人易老。", "欲占朱颜长好。", "画堂秋月佳期。", "藏钩赌酒归迟。", "红烛泪前低语，绿笺花里新词。"]'),
('song-ci-178','清平乐','晏几道','宋','宋词','song-ci','清平乐','[]','红英落尽。',54,'宋词/ci.song.1000.json','["红英落尽。", "未有相逢信。", "可恨流年凋绿鬓。", "睡得春酲欲醒。", "钿筝曾醉西楼。", "朱弦玉指梁州。", "曲罢翠帘高卷，几回新月如钩。"]'),
('song-ci-179','清平乐','晏几道','宋','宋词','song-ci','清平乐','[]','春云绿处。',54,'宋词/ci.song.1000.json','["春云绿处。", "又见归鸿去。", "侧帽风前花满路。", "冶叶倡条情绪。", "红楼桂酒新开。", "曾携翠袖同来。", "醉弄影娥池水，短箫吹落残梅。"]'),
('song-ci-180','清平乐','晏几道','宋','宋词','song-ci','清平乐','[]','波纹碧皱。',54,'宋词/ci.song.1000.json','["波纹碧皱。", "曲水清明后。", "折得疏梅香满袖。", "暗喜春红依旧。", "归来紫陌东头。", "金钗换酒消愁。", "柳影深深细路，花梢小小层楼。"]'),
('song-ci-181','清平乐','晏几道','宋','宋词','song-ci','清平乐','[]','西池烟草。',54,'宋词/ci.song.1000.json','["西池烟草。", "恨不寻芳早。", "满路落花红不扫。", "春色渐随人老。", "远山眉黛娇长。", "清歌细逐霞觞。", "正在十洲残梦，水心宫殿斜阳。"]'),
('song-ci-182','清平乐','晏几道','宋','宋词','song-ci','清平乐','[]','蕙心堪怨。',54,'宋词/ci.song.1000.json','["蕙心堪怨。", "也逐春风转。", "丹杏墙东当日见。", "幽会绿窗题遍。", "眼中前事分明。", "可怜如梦难凭。", "都把旧时薄幸，只消今日无情。"]'),
('song-ci-183','清平乐','晏几道','宋','宋词','song-ci','清平乐','[]','幺弦写意。',54,'宋词/ci.song.1000.json','["幺弦写意。", "意密弦声碎。", "书得凤笺无限事。", "犹恨春心难寄。", "卧听疏雨梧桐。", "雨馀淡月朦胧。", "一夜梦魂何处，那回杨叶楼中。"]'),
('song-ci-184','清平乐','晏几道','宋','宋词','song-ci','清平乐','[]','笙歌宛转。',54,'宋词/ci.song.1000.json','["笙歌宛转。", "台上吴王宴。", "宫女如花倚春殿。", "舞绽缕金衣线。", "酒阑画烛低迷。", "彩鸳惊起双栖。", "月底三千绣户，云间十二琼梯。"]'),
('song-ci-185','清平乐','晏几道','宋','宋词','song-ci','清平乐','[]','暂来还去。',54,'宋词/ci.song.1000.json','["暂来还去。", "轻似风头絮。", "纵得相逢留不住。", "何况相逢无处。", "去时约略黄昏。", "月华却到朱门。", "别后几番明月，素娥应是消魂。"]'),
('song-ci-186','清平乐','晏几道','宋','宋词','song-ci','清平乐','[]','双纹彩袖。',54,'宋词/ci.song.1000.json','["双纹彩袖。", "笑捧金船酒。", "娇妙如花轻似柳。", "劝客千春长寿。", "艳歌更倚疏弦。", "有情须醉尊前。", "恰是可怜时候，玉娇今夜初圆。"]'),
('song-ci-187','清平乐','晏几道','宋','宋词','song-ci','清平乐','[]','寒催酒醒。',54,'宋词/ci.song.1000.json','["寒催酒醒。", "晓陌飞霜定。", "背照画帘残烛影。", "斜月光中人静。", "锦衣才子西征。", "万重云水初程。", "翠黛倚门相送，鸾肠断处离声。"]'),
('song-ci-188','清平乐','晏几道','宋','宋词','song-ci','清平乐','[]','莲开欲遍。',54,'宋词/ci.song.1000.json','["莲开欲遍。", "一夜秋声转。", "残绿断红香片片。", "长是西风堪怨。", "莫愁家住溪边。", "采莲心事年年。", "谁管水流花谢，月明昨夜兰船。"]'),
('song-ci-189','清平乐','晏几道','宋','宋词','song-ci','清平乐','[]','沈思暗记。',54,'宋词/ci.song.1000.json','["沈思暗记。", "几许无凭事。", "菊靥开残秋少味。", "闲却画阑风意。", "梦云归处难寻。", "微凉暗入香襟。", "犹恨那回庭院，依前月浅灯深。"]'),
('song-ci-190','清平乐','晏几道','宋','宋词','song-ci','清平乐','[]','莺来燕去。',54,'宋词/ci.song.1000.json','["莺来燕去。", "宋玉墙东路。", "草草幽欢能几度。", "便有系人心处。", "碧天秋月无端。", "别来长照关山。", "一点恹恹谁会，依前凭暖阑干。"]'),
('song-ci-191','清平乐','晏几道','宋','宋词','song-ci','清平乐','[]','心期休问。',54,'宋词/ci.song.1000.json','["心期休问。", "只有尊前分。", "勾引行人添别恨。", "因是语低香近。", "劝人满酌金锺。", "清歌唱彻还重。", "莫道后期无定，梦魂犹有相逢。"]'),
('song-ci-192','木兰花・玉楼春','晏几道','宋','宋词','song-ci','木兰花・玉楼春','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','秋千院落重帘暮。',64,'宋词/ci.song.1000.json','["秋千院落重帘暮。", "彩笔闲来题绣户。", "墙头丹杏雨馀花，门外绿杨风后絮。", "朝云信断知何处。", "应作襄王春梦去。", "紫骝认得旧游踪，嘶过画桥东畔路。"]'),
('song-ci-193','木兰花・玉楼春','晏几道','宋','宋词','song-ci','木兰花・玉楼春','[]','小颦若解愁春暮。',64,'宋词/ci.song.1000.json','["小颦若解愁春暮。", "一笑留春春也住。", "晚红初减谢池花，新翠已遮琼苑路。", "湔裙曲水曾相遇。", "挽断罗巾容易去。", "啼珠弹尽又成行，毕竟心情无会处。"]'),
('song-ci-194','木兰花・玉楼春','晏几道','宋','宋词','song-ci','木兰花・玉楼春','[]','小莲未解论心素。',64,'宋词/ci.song.1000.json','["小莲未解论心素。", "狂似钿筝弦底柱。", "脸边霞散酒初醒，眉上月残人欲去。", "旧时家近章台住。", "尽日东风吹柳絮。", "生憎繁杏绿阴时，正碍粉墙偷眼觑。"]'),
('song-ci-195','木兰花・玉楼春','晏几道','宋','宋词','song-ci','木兰花・玉楼春','[]','风帘向晓寒成阵。',64,'宋词/ci.song.1000.json','["风帘向晓寒成阵。", "来报东风消息近。", "试从梅蒂紫边寻，更绕柳枝柔处问。", "来迟不是春无信。", "开晚却疑花有恨。", "又应添得几分愁，二十五弦弹未尽。"]'),
('song-ci-196','木兰花・玉楼春','晏几道','宋','宋词','song-ci','木兰花・玉楼春','[]','念奴初唱离亭宴。',64,'宋词/ci.song.1000.json','["念奴初唱离亭宴。", "会作离声勾别怨。", "当时垂泪忆西楼，湿尽罗衣歌未遍。", "难逢最是身强健。", "无定莫如人聚散。", "已拼归袖醉相扶，更恼香檀珍重劝。"]'),
('song-ci-197','木兰花・玉楼春','晏几道','宋','宋词','song-ci','木兰花・玉楼春','[]','玉真能唱朱帘静。',64,'宋词/ci.song.1000.json','["玉真能唱朱帘静。", "忆在双莲池上听。", "百分蕉叶醉如泥，却向断肠声里醒。", "夜凉水月铺明镜。", "更看娇花闲弄影。", "曲终人意似流波，休问心期何处定。"]'),
('song-ci-198','木兰花・玉楼春','晏几道','宋','宋词','song-ci','木兰花・玉楼春','[]','阿茸十五腰肢好。',64,'宋词/ci.song.1000.json','["阿茸十五腰肢好。", "天与怀春风味早。", "画眉匀脸不知愁，殢酒熏香偏称小。", "东城杨柳西城草。", "月会花期如意少。", "思量心事薄轻云，绿镜台前还自笑。"]'),
('song-ci-199','木兰花・玉楼春','晏几道','宋','宋词','song-ci','木兰花・玉楼春','[]','初心已恨花期晚。',64,'宋词/ci.song.1000.json','["初心已恨花期晚。", "别后相思长在眼。", "兰衾犹有旧时香，每到梦回珠泪满。", "多应不信人肠断。", "几夜夜寒谁共暖。", "欲将恩爱结来生，只恐来生缘又短。"]'),
('song-ci-200','减字木兰花','晏几道','宋','宋词','song-ci','减字木兰花','[]','长亭晚送。',52,'宋词/ci.song.1000.json','["长亭晚送。", "都似绿窗前日梦。", "小字还家。", "恰应红灯昨夜花。", "良时易过。", "半镜流年春欲破。", "往事难忘。", "一枕高楼到夕阳。"]'),
('song-ci-201','减字木兰花','晏几道','宋','宋词','song-ci','减字木兰花','[]','留春不住。',52,'宋词/ci.song.1000.json','["留春不住。", "恰似年光无味处。", "满眼飞英。", "弹指东风太浅情。", "筝弦未稳。", "学得新声难破恨。", "转枕花前。", "且占香红一夜眠。"]'),
('song-ci-202','减字木兰花','晏几道','宋','宋词','song-ci','减字木兰花','[]','长杨辇路。',52,'宋词/ci.song.1000.json','["长杨辇路。", "绿满当年携手处。", "试逐春风。", "重到宫花花树中。", "芳菲绕遍。", "今日不如前日健。", "酒罢凄凉。", "新恨犹添旧恨长。"]'),
('song-ci-203','泛清波摘遍','晏几道','宋','宋词','song-ci','泛清波摘遍','[]','催花雨小，著柳风柔，都似去年时候好。',126,'宋词/ci.song.1000.json','["催花雨小，著柳风柔，都似去年时候好。", "露红烟绿，尽有狂情斗春早。", "长安道。", "秋千影里，丝管声中，谁放艳阳轻过了。", "倦客登临，暗惜光阴恨多少。", "楚天渺。", "归思正如乱云，短梦未成芳草。", "空把吴霜鬓华，自悲清晓。", "帝城杳。", "双凤旧约渐虚，孤鸿后期难到。", "且趁朝花夜月，翠尊频倒。"]'),
('song-ci-204','洞仙歌','晏几道','宋','宋词','song-ci','洞仙歌','[]','春残雨过，绿暗东池道。',103,'宋词/ci.song.1000.json','["春残雨过，绿暗东池道。", "玉艳藏羞媚赪笑。", "记当时、已恨飞镜欢疏，那至此，仍苦题花信少。", "连环情未己，物是人非，月下疏梅似伊好。", "澹秀色，黯寒香，粲若春容，何心顾、闲花凡草。", "但莫使、情随岁华迁，便杳隔秦源，也须能到。"]'),
('song-ci-205','菩萨蛮','晏几道','宋','宋词','song-ci','菩萨蛮','[]','来时杨柳东桥路。',52,'宋词/ci.song.1000.json','["来时杨柳东桥路。", "曲中暗有相期处。", "明月好因缘。", "欲圆还未圆。", "欲寻芳草去。", "画扇遮微雨。", "飞絮莫无情。", "闲花应笑人。"]'),
('song-ci-206','菩萨蛮','晏几道','宋','宋词','song-ci','菩萨蛮','[]','个人轻似低飞燕。',52,'宋词/ci.song.1000.json','["个人轻似低飞燕。", "春来绮陌时相见。", "堪恨两横波。", "恼人情绪多。", "长留青鬓住。", "莫放红颜去。", "占取艳阳天。", "且教伊少年。"]'),
('song-ci-207','菩萨蛮','晏几道','宋','宋词','song-ci','菩萨蛮','[]','鸾啼似作留春语。',52,'宋词/ci.song.1000.json','["鸾啼似作留春语。", "花飞斗学回风舞。", "红日又平西。", "画帘遮燕泥。", "烟光还自老。", "绿镜人空好。", "香在去年衣。", "鱼笺音信稀。"]'),
('song-ci-208','菩萨蛮','晏几道','宋','宋词','song-ci','菩萨蛮','[]','春风未放花心吐。',52,'宋词/ci.song.1000.json','["春风未放花心吐。", "尊前不拟分明语。", "酒色上来迟。", "绿须红杏枝。", "今朝眉黛浅。", "暗恨归时远。", "前夜月当楼。", "相逢南陌头。"]'),
('song-ci-209','菩萨蛮','晏几道','宋','宋词','song-ci','菩萨蛮','[]','娇香淡染胭脂雪。',52,'宋词/ci.song.1000.json','["娇香淡染胭脂雪。", "愁春细画弯弯月。", "花月镜边情。", "浅妆匀未成。", "佳期应有在。", "试倚秋千待。", "满地落英红。", "万条杨柳风。"]'),
('song-ci-210','菩萨蛮','晏几道','宋','宋词','song-ci','菩萨蛮','[]','香莲烛下匀丹雪。',52,'宋词/ci.song.1000.json','["香莲烛下匀丹雪。", "妆成笑弄金阶月。", "娇面胜芙蓉。", "脸边天与红。", "玳筵双揭鼓。", "唤上华茵舞。", "春浅未禁寒。", "暗嫌罗袖宽。"]'),
('song-ci-211','菩萨蛮','晏几道','宋','宋词','song-ci','菩萨蛮','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','哀筝一弄湘江曲。',52,'宋词/ci.song.1000.json','["哀筝一弄湘江曲。", "声声写尽湘波绿。", "纤指十三弦。", "细将幽恨传。", "当筵秋水慢。", "玉柱斜飞雁。", "弹到断肠时。", "春山眉黛低。"]'),
('song-ci-212','菩萨蛮','晏几道','宋','宋词','song-ci','菩萨蛮','[]','江南未雪梅花白。',52,'宋词/ci.song.1000.json','["江南未雪梅花白。", "忆梅人是江南客。", "犹记旧相逢。", "淡烟微月中。", "玉容长有信。", "一笑归来近。", "怀远上楼时。", "晚云和雁低。"]'),
('song-ci-213','菩萨蛮','晏几道','宋','宋词','song-ci','菩萨蛮','[]','相逢欲话相思苦。',52,'宋词/ci.song.1000.json','["相逢欲话相思苦。", "浅情肯信相思否。", "还恐漫相思。", "浅情人不知。", "忆曾携手处。", "月满窗前路。", "长到月来时。", "不眠犹待伊。"]'),
('song-ci-214','玉楼春','晏几道','宋','宋词','song-ci','玉楼春','[]','雕鞍好为莺花住。',64,'宋词/ci.song.1000.json','["雕鞍好为莺花住。", "占取东城南陌路。", "尽教春思乱如云，莫管世情轻似絮。", "古来多被虚名误。", "宁负虚名身莫负。", "劝君频入醉乡来，此是无愁无恨处。"]'),
('song-ci-215','玉楼春','晏几道','宋','宋词','song-ci','玉楼春','[]','一尊相遇春风里。',64,'宋词/ci.song.1000.json','["一尊相遇春风里。", "诗好似君人有几。", "吴姬十五语如弦，能唱当时楼下水。", "良辰易去如弹指。", "金盏十分须尽意。", "明朝三丈日高时，共拼醉头扶不起。"]'),
('song-ci-216','玉楼春','晏几道','宋','宋词','song-ci','玉楼春','[]','琼酥酒面风吹醒。',64,'宋词/ci.song.1000.json','["琼酥酒面风吹醒。", "一缕斜红临晚镜。", "小颦微笑尽妖娆，浅注轻匀长淡净。", "手挪梅蕊寻香径。", "正是佳期期未定。", "春来还为个般愁，瘦损宫腰罗带剩。"]'),
('song-ci-217','玉楼春','晏几道','宋','宋词','song-ci','玉楼春','[]','清歌学得秦娥似。',64,'宋词/ci.song.1000.json','["清歌学得秦娥似。", "金屋瑶台知姓字。", "可怜春恨一生心，长带粉痕双袖泪。", "从来懒话低眉事。", "今日新声谁会意。", "坐中应有赏音人，试问回肠曾断未。"]'),
('song-ci-218','玉楼春','晏几道','宋','宋词','song-ci','玉楼春','[]','旗亭西畔朝云住。',64,'宋词/ci.song.1000.json','["旗亭西畔朝云住。", "沈水香烟长满路。", "柳阴分到画眉边，花片飞来垂手处。", "妆成尽任秋娘妒。", "袅袅盈盈当绣户。", "临风一曲醉朦腾，陌上行人凝恨去。"]'),
('song-ci-219','玉楼春','晏几道','宋','宋词','song-ci','玉楼春','[]','离鸾照罢尘生镜。',64,'宋词/ci.song.1000.json','["离鸾照罢尘生镜。", "几点吴霜侵绿鬓。", "琵琶弦上语无凭，豆蔻梢头春有信。", "相思拼损朱颜尽。", "天若多情终欲问。", "雪窗休记夜来寒，桂酒已消人去恨。"]'),
('song-ci-220','玉楼春','晏几道','宋','宋词','song-ci','玉楼春','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','东风又作无情计。',64,'宋词/ci.song.1000.json','["东风又作无情计。", "艳粉娇红吹满地。", "碧楼帘影不遮愁，还似去年今日意。", "谁知错管春残事。", "到处登临曾费泪。", "此时金盏直须深，看尽落花能几醉。"]'),
('song-ci-221','玉楼春','晏几道','宋','宋词','song-ci','玉楼春','[]','斑骓路与阳台近。',64,'宋词/ci.song.1000.json','["斑骓路与阳台近。", "前度无题初借问。", "暖风鞭袖尽闲垂，微月帘栊曾暗认。", "梅花未足凭芳信。", "弦语岂堪传素恨。", "翠眉饶似远山长，寄与此愁颦不尽。"]'),
('song-ci-222','玉楼春','晏几道','宋','宋词','song-ci','玉楼春','[]','红绡学舞腰肢软。',64,'宋词/ci.song.1000.json','["红绡学舞腰肢软。", "旋织舞衣宫样染。", "织成云外雁行斜，染作江南春水浅。", "露桃宫里随歌管。", "一曲霓裳红日晚。", "归来双袖酒成痕，小字香笺无意展。"]'),
('song-ci-223','玉楼春','晏几道','宋','宋词','song-ci','玉楼春','[]','当年信道情无价。',64,'宋词/ci.song.1000.json','["当年信道情无价。", "桃叶尊前论别夜。", "脸红心绪学梅妆，眉翠工夫如月画。", "来时醉倒旗亭下。", "知是阿谁扶上马。", "忆曾挑尽五更灯，不记临分多少话。"]'),
('song-ci-224','玉楼春','晏几道','宋','宋词','song-ci','玉楼春','[]','采莲时候慵歌舞。',64,'宋词/ci.song.1000.json','["采莲时候慵歌舞。", "永日闲从花里度。", "暗随苹末晓风来，直待柳梢斜月去。", "停桡共说江头路。", "临水楼台苏小住。", "细思巫峡梦回时，不减秦源肠断处。"]'),
('song-ci-225','玉楼春','晏几道','宋','宋词','song-ci','玉楼春','[]','芳年正是香英嫩。',64,'宋词/ci.song.1000.json','["芳年正是香英嫩。", "天与娇波长入鬓。", "蕊珠宫里旧承恩，夜拂银屏朝把镜。", "云情去住终难信。", "花意有无休更问。", "醉中同尽一杯欢，归后各成孤枕恨。"]'),
('song-ci-226','玉楼春','晏几道','宋','宋词','song-ci','玉楼春','[]','轻风拂柳冰初绽。',64,'宋词/ci.song.1000.json','["轻风拂柳冰初绽。", "细雨消尘云未散。", "红窗青镜待妆梅，绿陌高楼催送雁。", "华罗歌扇金蕉盏。", "记得寻芳心绪惯。", "凤城寒尽又飞花，岁岁春光常有限。"]'),
('song-ci-227','阮郎归','晏几道','宋','宋词','song-ci','阮郎归','[]','粉痕闲印玉尖纤。',56,'宋词/ci.song.1000.json','["粉痕闲印玉尖纤。", "啼红傍晚奁。", "旧寒新暖尚相兼。", "梅疏待雪添。", "春冉冉，恨恹恹。", "章台对卷帘。", "个人鞭影弄凉蟾。", "楼前侧帽檐。"]'),
('song-ci-228','阮郎归','晏几道','宋','宋词','song-ci','阮郎归','[]','来时红日弄窗纱。',56,'宋词/ci.song.1000.json','["来时红日弄窗纱。", "春红入睡霞。", "去时庭树欲栖鸦。", "香屏掩月斜。", "收翠羽，整妆华。", "青骊信又差。", "玉笙犹恋碧桃花。", "今宵未忆家。"]'),
('song-ci-229','阮郎归','晏几道','宋','宋词','song-ci','阮郎归','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','旧香残粉似当初。',56,'宋词/ci.song.1000.json','["旧香残粉似当初。", "人情恨不如。", "一春犹有数行书。", "秋来书更疏。", "衾凤冷，枕鸳孤。", "愁肠待酒舒。", "梦魂纵有也成虚。", "那堪和梦无。"]'),
('song-ci-230','阮郎归','晏几道','宋','宋词','song-ci','阮郎归','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','天边金掌露成霜。',56,'宋词/ci.song.1000.json','["天边金掌露成霜。", "云随雁字长。", "绿杯红袖称重阳。", "人情似故乡。", "兰佩紫，菊簪黄。", "殷勤理旧狂。", "欲将沈醉换悲凉。", "清歌莫断肠。"]'),
('song-ci-231','阮郎归','晏几道','宋','宋词','song-ci','阮郎归','[]','晚妆长趁景阳钟。',56,'宋词/ci.song.1000.json','["晚妆长趁景阳钟。", "双蛾著意浓。", "舞腰浮动绿云浓。", "樱桃半点红。", "怜美景，惜芳容。", "沈思暗记中。", "春寒帘幕几重重。", "杨花尽日风。"]'),
('song-ci-232','归田乐','晏几道','宋','宋词','song-ci','归田乐','[]','试把花期数。',87,'宋词/ci.song.1000.json','["试把花期数。", "便早有、感春情绪。", "看即梅花吐。", "愿花更不谢，春且长住。", "只恐花飞又春去。", "花开还不语。", "问此意、年年春还会否。", "绛唇青鬓，渐少花前语。", "对花又记得、旧曾游处。", "门外垂杨未飘絮。"]'),
('song-ci-233','浣溪沙','晏几道','宋','宋词','song-ci','浣溪沙','[]','二月春花厌落梅。',48,'宋词/ci.song.1000.json','["二月春花厌落梅。", "仙源归路碧桃催。", "渭城丝雨劝离杯。", "欢意似云真薄幸，客鞭摇柳正多才。", "凤楼人待锦书来。"]'),
('song-ci-234','浣溪沙','晏几道','宋','宋词','song-ci','浣溪沙','[]','卧鸭池头小苑开。',48,'宋词/ci.song.1000.json','["卧鸭池头小苑开。", "暄风吹尽北枝梅。", "柳长莎软路萦回。", "静避绿阴莺有意，漫随游骑絮多才。", "去年今日忆同来。"]'),
('song-ci-235','浣溪沙','晏几道','宋','宋词','song-ci','浣溪沙','[]','二月和风到碧城。',48,'宋词/ci.song.1000.json','["二月和风到碧城。", "万条千缕绿相迎。", "舞烟眠雨过清明。", "妆镜巧眉偷叶样，歌楼妍曲借枝名。", "晚秋霜霰莫无情。"]'),
('song-ci-236','浣溪沙','晏几道','宋','宋词','song-ci','浣溪沙','[]','白纻春衫杨柳鞭。',48,'宋词/ci.song.1000.json','["白纻春衫杨柳鞭。", "碧蹄骄马杏花鞯。", "落英飞絮冶游天。", "南陌暖风吹舞榭，东城凉月照歌筵。", "赏心多是酒中仙。"]'),
('song-ci-237','浣溪沙','晏几道','宋','宋词','song-ci','浣溪沙','[]','床上银屏几点山。',48,'宋词/ci.song.1000.json','["床上银屏几点山。", "鸭炉香过琐窗寒。", "小云双枕恨春闲。", "惜别漫成良夜醉，解愁时有翠笺还。", "那回分袂月初残。"]'),
('song-ci-238','浣溪沙','晏几道','宋','宋词','song-ci','浣溪沙','[]','绿柳藏乌静掩关。',48,'宋词/ci.song.1000.json','["绿柳藏乌静掩关。", "鸭炉香细琐窗闲。", "那回分袂月初残。", "惜别漫成良夜醉，解愁时有翠笺还。", "欲寻双叶寄情难。"]'),
('song-ci-239','浣溪沙','晏几道','宋','宋词','song-ci','浣溪沙','[]','家近旗亭酒易酤。',48,'宋词/ci.song.1000.json','["家近旗亭酒易酤。", "花时长得醉工夫。", "伴人歌笑懒妆梳。", "户外绿杨春系马，床前红烛夜呼卢。", "相逢还解有情无。"]'),
('song-ci-240','浣溪沙','晏几道','宋','宋词','song-ci','浣溪沙','[]','日日双眉斗画长。',48,'宋词/ci.song.1000.json','["日日双眉斗画长。", "行云飞絮共轻狂。", "不将心嫁冶游郎。", "溅酒滴残歌扇字，弄花熏得舞衣香。", "一春弹泪说凄凉。"]'),
('song-ci-241','浣溪沙','晏几道','宋','宋词','song-ci','浣溪沙','[]','飞鹊台前晕翠蛾。',48,'宋词/ci.song.1000.json','["飞鹊台前晕翠蛾。", "千金新换绛仙螺。", "最难加意为颦多。", "几处睡痕留醉袖，一春愁思近横波。", "远山低尽不成歌。"]'),
('song-ci-242','浣溪沙','晏几道','宋','宋词','song-ci','浣溪沙','[]','午醉西桥夕未醒。',48,'宋词/ci.song.1000.json','["午醉西桥夕未醒。", "雨花凄断不堪听。", "归时应减鬓边青。", "衣化客尘今古道，柳含春意短长亭。", "凤楼争见路旁情。"]'),
('song-ci-243','浣溪沙','晏几道','宋','宋词','song-ci','浣溪沙','[]','一样宫妆簇彩舟。',48,'宋词/ci.song.1000.json','["一样宫妆簇彩舟。", "碧罗团扇自障羞。", "水仙人在镜中游。", "腰自细来多态度，脸因红处转风流。", "年年相遇绿江头。"]'),
('song-ci-244','浣溪沙','晏几道','宋','宋词','song-ci','浣溪沙','[]','已拆秋千不奈闲。',48,'宋词/ci.song.1000.json','["已拆秋千不奈闲。", "却随胡蝶到花间。", "旋寻双叶插云鬟。", "几摺湘裙烟缕细，一钩罗袜素蟾弯。", "绿窗红豆忆前欢。"]'),
('song-ci-245','浣溪沙','晏几道','宋','宋词','song-ci','浣溪沙','[]','闲弄筝弦懒系裙。',48,'宋词/ci.song.1000.json','["闲弄筝弦懒系裙。", "铅华消尽见天真。", "眼波低处事还新。", "怅恨不逢如意酒，寻思难值有情人。", "可怜虚度琐窗春。"]'),
('song-ci-246','浣溪沙','晏几道','宋','宋词','song-ci','浣溪沙','[]','团扇初随碧簟收。',48,'宋词/ci.song.1000.json','["团扇初随碧簟收。", "画檐归燕尚迟留。", "靥朱眉翠喜清秋。", "风意未应迷狭路，灯痕犹自记高楼。", "露花烟叶与人愁。"]'),
('song-ci-247','浣溪沙','晏几道','宋','宋词','song-ci','浣溪沙','[]','翠阁朱阑倚处危。',48,'宋词/ci.song.1000.json','["翠阁朱阑倚处危。", "夜凉闲捻彩箫吹。", "曲中双凤已分飞。", "绿酒细倾消别恨，红笺小写问归期。", "月华风意似当时。"]'),
('song-ci-248','浣溪沙','晏几道','宋','宋词','song-ci','浣溪沙','[]','唱得红梅字字香。',48,'宋词/ci.song.1000.json','["唱得红梅字字香。", "柳枝桃叶尽深藏。", "遏云声里送雕觞。", "才听便拼衣袖湿，欲歌先倚黛眉长。", "曲终敲损燕钗梁。"]'),
('song-ci-249','浣溪沙','晏几道','宋','宋词','song-ci','浣溪沙','[]','小杏春声学浪仙。',48,'宋词/ci.song.1000.json','["小杏春声学浪仙。", "疏梅清唱替哀弦。", "似花如雪绕琼筵。", "腮粉月痕妆罢后，脸红莲艳酒醒前。", "今年水调得人怜。"]'),
('song-ci-250','浣溪沙','晏几道','宋','宋词','song-ci','浣溪沙','[]','铜虎分符领外台。',48,'宋词/ci.song.1000.json','["铜虎分符领外台。", "五云深处彩旌来。", "春随红旆过长淮。", "千里裤襦添旧暖，万家桃李间新栽。", "使星回首是三台。"]'),
('song-ci-251','浣溪沙','晏几道','宋','宋词','song-ci','浣溪沙','[]','浦口莲香夜不收。',48,'宋词/ci.song.1000.json','["浦口莲香夜不收。", "水边风里欲生秋。", "棹歌声细不惊鸥。", "凉月送归思往事，落英飘去起新愁。", "可堪题叶寄东楼。"]'),
('song-ci-252','浣溪沙','晏几道','宋','宋词','song-ci','浣溪沙','[]','莫问逢春能几回。',48,'宋词/ci.song.1000.json','["莫问逢春能几回。", "能歌能笑是多才。", "露花犹有好枝开。", "绿鬓旧人皆老大，红梁新燕又归来。", "尽须珍重掌中杯。"]'),
('song-ci-253','浣溪沙','晏几道','宋','宋词','song-ci','浣溪沙','[]','楼上灯深欲闭门。',48,'宋词/ci.song.1000.json','["楼上灯深欲闭门。", "梦云归去不留痕。", "几年芳草忆王孙。", "向日阑干依旧绿，试将前事倚黄昏。", "记曾来处易消魂。"]'),
('song-ci-254','六么令','晏几道','宋','宋词','song-ci','六么令','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','绿阴春尽，飞絮绕香阁。',112,'宋词/ci.song.1000.json','["绿阴春尽，飞絮绕香阁。", "晚来翠眉宫样，巧把远山学。", "一寸狂心未说，已向横波觉。", "画帘遮币。", "新翻曲妙，暗许闲人带偷掏。", "前度书多隐语，意浅愁难答。", "昨夜诗有回纹，韵险还慵押。", "都待笙歌散了，记取留时霎。", "不消红蜡。", "闲云归后，月在庭花旧阑角。"]'),
('song-ci-255','六么令','晏几道','宋','宋词','song-ci','六么令','[]','雪残风信，悠扬春消息。',112,'宋词/ci.song.1000.json','["雪残风信，悠扬春消息。", "天涯倚楼新恨，杨柳几丝碧。", "还是南云雁少，锦字无端的。", "宝钗瑶席。", "彩弦声里，拼作尊前未归客。", "遥想疏梅此际，月底香英白。", "别后谁绕前溪，手拣繁枝摘。", "莫道伤高恨远，付与临风笛。", "尽堪愁寂。", "花时往事，更有多情个人忆。"]'),
('song-ci-256','六么令','晏几道','宋','宋词','song-ci','六么令','[]','日高春睡，唤起懒装束。',112,'宋词/ci.song.1000.json','["日高春睡，唤起懒装束。", "年年落花时候，惯得娇眠足。", "学唱宫梅便好，更暖银笙逐。", "黛蛾低绿。", "堪教人恨，却似江南旧时曲。", "常记东楼夜雪，翠幕遮红烛。", "还是芳酒杯中，一醉光阴促。", "曾笑阳台梦短，无计怜香玉。", "此欢难续。", "乞求歌罢，借取归云画堂宿。"]'),
('song-ci-257','更漏子','晏几道','宋','宋词','song-ci','更漏子','[]','槛花稀，池草遍。',58,'宋词/ci.song.1000.json','["槛花稀，池草遍。", "冷落吹笙庭院。", "人去日，燕西飞。", "燕归人未归。", "数书期，寻梦意。", "弹指一年春事。", "新怅望，旧悲凉。", "不堪红日长。"]'),
('song-ci-258','更漏子','晏几道','宋','宋词','song-ci','更漏子','[]','柳间眠，花里醉。',58,'宋词/ci.song.1000.json','["柳间眠，花里醉。", "不惜绣裙铺地。", "钗燕重，鬓蝉轻。", "一双梅子青。", "粉笺书，罗袖泪。", "还有可怜新意。", "遮闷绿，掩羞红。", "晚来团扇风。"]'),
('song-ci-259','更漏子','晏几道','宋','宋词','song-ci','更漏子','[]','柳丝长，桃叶小。',58,'宋词/ci.song.1000.json','["柳丝长，桃叶小。", "深院断无人到。", "红日淡，绿烟晴。", "流莺三两声。", "雪香浓，檀晕少。", "枕上卧枝花好。", "春思重，晓妆迟。", "寻思残梦时。"]'),
('song-ci-260','更漏子','晏几道','宋','宋词','song-ci','更漏子','[]','露华高，风信远。',58,'宋词/ci.song.1000.json','["露华高，风信远。", "宿醉画帘低卷。", "梳洗倦，冶游慵。", "绿窗春睡浓。", "彩条轻，金缕重。", "昨日小桥相送。", "芳草恨，落花愁。", "去年同倚楼。"]'),
('song-ci-261','更漏子','晏几道','宋','宋词','song-ci','更漏子','[]','出墙花，当路柳。',58,'宋词/ci.song.1000.json','["出墙花，当路柳。", "借问芳心谁有。", "红解笑，绿能颦。", "千般恼乱春。", "北来人，南去客。", "朝暮等闲攀折。", "怜晚秀，惜残阳。", "情知枉断肠。"]'),
('song-ci-262','更漏子','晏几道','宋','宋词','song-ci','更漏子','[]','欲论心，先掩泪。',58,'宋词/ci.song.1000.json','["欲论心，先掩泪。", "零落去年风味。", "闲卧处，不言时。", "愁多只自知。", "到情深，俱是怨。", "惟有梦中相见。", "犹似旧，奈人禁。", "偎人说寸心。"]'),
('song-ci-263','河满子','晏几道','宋','宋词','song-ci','河满子','[]','对镜偷匀玉箸，背人学写银钩。',86,'宋词/ci.song.1000.json','["对镜偷匀玉箸，背人学写银钩。", "系谁红豆罗带角，心情正著春游。", "那日杨花陌上，多时杏子墙头。", "眼底关山无奈，梦中云雨空休。", "问看几许怜才意，两蛾藏尽离愁。", "难拼此回肠断，终须锁定红楼。"]'),
('song-ci-264','河满子','晏几道','宋','宋词','song-ci','河满子','[]','绿绮琴中心事，齐纨扇上时光。',86,'宋词/ci.song.1000.json','["绿绮琴中心事，齐纨扇上时光。", "五陵年少浑薄幸，轻如曲水飘香。", "夜夜魂消梦峡，年年泪尽啼湘。", "归雁行边远字，惊鸾舞处离肠。", "蕙楼多少铅华在，从来错倚红妆。", "可羡邻姬十五，金钗早嫁王昌。"]'),
('song-ci-265','于飞乐','晏几道','宋','宋词','song-ci','于飞乐','[]','晓日当帘，睡痕犹占香腮。',90,'宋词/ci.song.1000.json','["晓日当帘，睡痕犹占香腮。", "轻盈笑倚鸾台。", "晕残红，匀宿翠，满镜花开。", "娇蝉鬓畔，插一枝、淡蕊疏梅。", "每到春深，多愁饶恨，妆成懒下香阶。", "意中人，从别后，萦系情怀。", "良辰好景，相思字、唤不归来。"]'),
('song-ci-266','愁倚阑令・春光好','晏几道','宋','宋词','song-ci','愁倚阑令・春光好','[]','凭江阁，看烟鸿。',52,'宋词/ci.song.1000.json','["凭江阁，看烟鸿。", "恨春浓。", "还有当年闻笛泪，洒东风。", "时候草绿花红。", "斜阳外、远水溶溶。", "浑似阿莲双枕畔，画屏中。"]'),
('song-ci-267','愁倚阑令・春光好','晏几道','宋','宋词','song-ci','愁倚阑令・春光好','[]','花阴月，柳梢莺。',52,'宋词/ci.song.1000.json','["花阴月，柳梢莺。", "近清明。", "长恨去年今夜雨，洒离亭。", "枕上怀远诗成。", "红笺纸、小砑吴绫。", "寄与征人教念远，莫无情。"]'),
('song-ci-268','愁倚阑令・春光好','晏几道','宋','宋词','song-ci','愁倚阑令・春光好','[]','春罗薄，酒醒寒。',52,'宋词/ci.song.1000.json','["春罗薄，酒醒寒。", "梦初残。", "敧枕片时云雨事，已关山。", "楼上斜日阑干。", "楼前路、曾试雕鞍。", "拼却一襟怀远泪，倚阑看。"]'),
('song-ci-269','御街行','晏几道','宋','宋词','song-ci','御街行','[]','年光正似花梢露。',90,'宋词/ci.song.1000.json','["年光正似花梢露。", "弹指春还暮。", "翠眉仙子望归来，倚遍玉城珠树。", "岂知别后，好风良月，往事无寻处。", "狂情错向红尘住。", "忘了瑶台路。", "碧桃花蕊已应开，欲伴彩云飞去。", "回思十载，朱颜青鬓，枉被浮名误。"]'),
('song-ci-270','御街行','晏几道','宋','宋词','song-ci','御街行','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','街南绿树春饶絮。',90,'宋词/ci.song.1000.json','["街南绿树春饶絮。", "雪满游春路。", "树头花艳杂娇云，树底人家朱户。", "北楼闲上，疏帘高卷，直见街南树。", "阑干倚尽犹慵去。", "几度黄昏雨。", "晚春盘马踏青苔，曾傍绿阴深驻。", "落花犹在，香屏空掩，人面知何处。"]'),
('song-ci-271','浪淘沙','晏几道','宋','宋词','song-ci','浪淘沙','[]','高阁对横塘。',64,'宋词/ci.song.1000.json','["高阁对横塘。", "新燕年光。", "柳花残梦隔潇湘。", "绿浦归帆看不见，还是斜阳。", "一笑解愁肠。", "人会娥妆。", "藕丝衫袖郁金香。", "曳雪牵云留客醉，且伴春狂。"]'),
('song-ci-272','浪淘沙','晏几道','宋','宋词','song-ci','浪淘沙','[]','小绿间长红。',64,'宋词/ci.song.1000.json','["小绿间长红。", "露蕊烟丛。", "花开花落昔年同。", "惟恨花前携手处，往事成空。", "山远水重重。", "一笑难逢。", "已拼长在别离中。", "霜鬓知他从此去，几度春风。"]'),
('song-ci-273','浪淘沙','晏几道','宋','宋词','song-ci','浪淘沙','[]','丽曲醉思仙。',64,'宋词/ci.song.1000.json','["丽曲醉思仙。", "十二哀弦。", "秾蛾叠柳脸红莲。", "多少雨条烟叶恨，红泪离筵。", "行子惜流年。", "鹈鴂枝边。", "吴堤春水舣兰船。", "南去北来今渐老，难负尊前。"]'),
('song-ci-274','浪淘沙','晏几道','宋','宋词','song-ci','浪淘沙','[]','翠幕绮筵张。',64,'宋词/ci.song.1000.json','["翠幕绮筵张。", "淑景难忘。", "阳关声巧绕雕梁。", "美酒十分谁与共，玉指持觞。", "晓枕梦高唐。", "略话衷肠。", "小山池院竹风凉。", "明夜月圆帘四卷，今夜思量。"]'),
('song-ci-275','丑奴儿・采桑子','晏几道','宋','宋词','song-ci','丑奴儿・采桑子','[]','昭华凤管知名久。',52,'宋词/ci.song.1000.json','["昭华凤管知名久。", "长闭帘栊。", "日日春慵。", "闲倚庭花晕脸红。", "应说金谷无人后，此会相逢。", "三弄临风。", "送得当筵玉盏空。"]'),
('song-ci-276','丑奴儿・采桑子','晏几道','宋','宋词','song-ci','丑奴儿・采桑子','[]','日高庭院杨花转，闲淡春风。',52,'宋词/ci.song.1000.json','["日高庭院杨花转，闲淡春风。", "莺语惺忪。", "似笑金屏昨夜空。", "娇慵未洗匀妆手，闲印斜红。", "新恨重重。", "都与年时旧意同。"]'),
('song-ci-277','诉衷情','晏几道','宋','宋词','song-ci','诉衷情','[]','种花人自蕊宫来。',54,'宋词/ci.song.1000.json','["种花人自蕊宫来。", "牵衣问小梅。", "今年芳意何似，应向旧枝开。", "凭寄语，谢瑶台。", "客无才。", "粉香传信，玉盏开筵，莫待春回。"]'),
('song-ci-278','诉衷情','晏几道','宋','宋词','song-ci','诉衷情','[]','净揩妆脸浅匀眉。',54,'宋词/ci.song.1000.json','["净揩妆脸浅匀眉。", "衫子素梅儿。", "苦无心绪梳洗，闲淡也相宜。", "云态度，柳腰肢。", "入相思。", "夜来月底，今日尊前，未当佳期。"]'),
('song-ci-279','诉衷情','晏几道','宋','宋词','song-ci','诉衷情','[]','渚莲霜晓坠残红。',54,'宋词/ci.song.1000.json','["渚莲霜晓坠残红。", "依约旧秋同。", "玉人团扇恩浅，一意恨西风。", "云去住，月朦胧。", "夜寒浓。", "此时还是，泪墨书成，未有归鸿。"]'),
('song-ci-280','诉衷情','晏几道','宋','宋词','song-ci','诉衷情','[]','凭觞静忆去年秋，桐落故溪头。',54,'宋词/ci.song.1000.json','["凭觞静忆去年秋，桐落故溪头。", "诗成自写红叶，和恨寄东流。", "人脉脉，水悠悠。", "几多愁。", "雁书不到，蝶梦无凭，漫倚高楼。"]'),
('song-ci-281','诉衷情','晏几道','宋','宋词','song-ci','诉衷情','[]','小梅风韵最妖娆。',54,'宋词/ci.song.1000.json','["小梅风韵最妖娆。", "开处雪初消。", "南枝欲附春信，长恨陇人遥。", "闲记忆，旧江皋。", "路迢迢。", "暗香浮动，疏影横斜，几处溪桥。"]'),
('song-ci-282','诉衷情','晏几道','宋','宋词','song-ci','诉衷情','[]','长因蕙草记罗裙。',54,'宋词/ci.song.1000.json','["长因蕙草记罗裙。", "绿腰沈水熏。", "阑干曲处人静，曾共倚黄昏。", "风有韵，月无痕。", "暗消魂。", "拟将幽恨，试写残花，寄与朝云。"]'),
('song-ci-283','诉衷情','晏几道','宋','宋词','song-ci','诉衷情','[]','御纱新制石榴裙。',54,'宋词/ci.song.1000.json','["御纱新制石榴裙。", "沈香慢火熏。", "越罗双带宫样，飞鹭碧波纹。", "随锦字，叠香痕。", "寄文君。", "系来花下，解向尊前，谁伴朝云。"]'),
('song-ci-284','诉衷情','晏几道','宋','宋词','song-ci','诉衷情','[]','都人离恨满歌筵。',54,'宋词/ci.song.1000.json','["都人离恨满歌筵。", "清唱倚危弦。", "星屏别后千里，更见是何年。", "骢骑稳，绣衣鲜。", "欲朝天。", "北人欢笑，南国悲凉，迎送金鞭。"]'),
('song-ci-285','破阵子','晏几道','宋','宋词','song-ci','破阵子','[]','柳下笙歌庭院，花间姊妹秋千。',72,'宋词/ci.song.1000.json','["柳下笙歌庭院，花间姊妹秋千。", "记得春楼当日事，写向红窗夜月前。", "凭谁寄小莲。", "绛蜡等闲陪泪，吴蚕到了缠绵。", "绿鬓能供多少恨，未肯无情比断弦。", "今年老去年。"]'),
('song-ci-286','好女儿','晏几道','宋','宋词','song-ci','好女儿','[]','绿遍西池。',77,'宋词/ci.song.1000.json','["绿遍西池。", "梅子青时。", "尽无端、尽日东风恶，更霏微细雨，恼人离恨，满路春泥。", "应是行云归路，有闲泪、洒相思。", "想旗亭、望断黄昏月，又依前误了，红笺香信，翠袖欢期。"]'),
('song-ci-287','好女儿','晏几道','宋','宋词','song-ci','好女儿','[]','酌酒殷勤。',77,'宋词/ci.song.1000.json','["酌酒殷勤。", "尽更留春。", "忍无情、便赋馀花落，待花前细把、一春心事，问个人人。", "莫似花开还谢，愿芳意、且长新。", "倚娇红、待得欢期定，向水沈烟底，金莲影下，睡过佳辰。"]'),
('song-ci-288','点绛唇','晏几道','宋','宋词','song-ci','点绛唇','[]','花信来时，恨无人似花依旧。',50,'宋词/ci.song.1000.json','["花信来时，恨无人似花依旧。", "又成春瘦。", "折断门前柳。", "天与多情，不与长相守。", "分飞后。", "泪痕和酒。", "占了双罗袖。"]'),
('song-ci-289','点绛唇','晏几道','宋','宋词','song-ci','点绛唇','[]','明日征鞭，又将南陌垂杨折。',50,'宋词/ci.song.1000.json','["明日征鞭，又将南陌垂杨折。", "自怜轻别。", "拼得音尘绝。", "杏子枝边，倚处阑干月。", "依前缺。", "去年时节。", "旧事无人说。"]'),
('song-ci-290','点绛唇','晏几道','宋','宋词','song-ci','点绛唇','[]','碧水东流，漫题凉叶津头寄。',50,'宋词/ci.song.1000.json','["碧水东流，漫题凉叶津头寄。", "谢娘春意。", "临水颦双翠。", "日日骊歌，空费行人泪。", "成何计。", "未如浓醉。", "闲掩红楼睡。"]'),
('song-ci-291','点绛唇','晏几道','宋','宋词','song-ci','点绛唇','[]','妆席相逢，旋匀红泪歌金缕。',50,'宋词/ci.song.1000.json','["妆席相逢，旋匀红泪歌金缕。", "意中曾许。", "欲共吹花去。", "长爱荷香，柳色殷桥路。", "留人住。", "淡烟微雨。", "好个双栖处。"]'),
('song-ci-292','点绛唇','晏几道','宋','宋词','song-ci','点绛唇','[]','湖上西风，露花啼处秋香老。',50,'宋词/ci.song.1000.json','["湖上西风，露花啼处秋香老。", "谢家春草。", "唱得清商好。", "笑倚兰舟，转尽新声了。", "烟波渺。", "暮云稀少。", "一点凉蟾小。"]'),
('song-ci-293','两同心','晏几道','宋','宋词','song-ci','两同心','[]','楚乡春晚，似入仙源。',86,'宋词/ci.song.1000.json','["楚乡春晚，似入仙源。", "拾翠处、闲随流水，踏青路、暗惹香尘。", "心心在，柳外青帘，花下朱门。", "对景且醉芳尊。", "莫话消魂。", "好意思、曾同明月，恶滋味、最是黄昏。", "相思处，一纸红笺，无限啼痕。"]'),
('song-ci-294','少年游','晏几道','宋','宋词','song-ci','少年游','[]','绿勾阑畔，黄昏淡月，携手对残红。',64,'宋词/ci.song.1000.json','["绿勾阑畔，黄昏淡月，携手对残红。", "纱窗影里，朦腾春睡，繁杏小屏风。", "须愁别后，天高海阔，何处更相逢。", "幸有花前，一杯芳酒，欢计莫匆匆。"]'),
('song-ci-295','少年游','晏几道','宋','宋词','song-ci','少年游','[]','西溪丹杏，波前媚脸，珠露与深匀。',64,'宋词/ci.song.1000.json','["西溪丹杏，波前媚脸，珠露与深匀。", "南楼翠柳，烟中愁黛，丝雨恼娇颦。", "当年此处，闻歌殢酒，曾对可怜人。", "今夜相思，水长山远，闲卧送残春。"]'),
('song-ci-296','少年游','晏几道','宋','宋词','song-ci','少年游','[]','离多最是，东西流水，终解两相逢。',64,'宋词/ci.song.1000.json','["离多最是，东西流水，终解两相逢。", "浅情终似，行云无定，犹到梦魂中。", "可怜人意，薄於云水，佳会更难重。", "细想从来，断肠多处，不与者番同。"]'),
('song-ci-297','少年游','晏几道','宋','宋词','song-ci','少年游','[]','西楼别后，风高露冷，无奈月分明。',62,'宋词/ci.song.1000.json','["西楼别后，风高露冷，无奈月分明。", "飞鸿影里，捣衣砧外，总是玉关情。", "王孙此际，山重水远，何处赋西征。", "金闺魂梦枉丁宁。", "寻尽短长亭。"]'),
('song-ci-298','少年游','晏几道','宋','宋词','song-ci','少年游','[]','雕梁燕去，裁诗寄远，庭院旧风流。',62,'宋词/ci.song.1000.json','["雕梁燕去，裁诗寄远，庭院旧风流。", "黄花醉了，碧梧题罢，闲卧对高秋。", "繁云破后，分明素月，凉影挂金钩。", "有人凝澹倚西楼。", "新样两眉愁。"]'),
('song-ci-299','虞美人','晏几道','宋','宋词','song-ci','虞美人','[]','闲敲玉镫隋堤路。',66,'宋词/ci.song.1000.json','["闲敲玉镫隋堤路。", "一笑开朱户。", "素云凝澹月婵娟。", "门外鸭头春水、木兰船。", "吹花拾蕊嬉游惯。", "天与相逢晚。", "一声长笛倚楼时。", "应恨不题红叶、寄相思。"]'),
('song-ci-300','虞美人','晏几道','宋','宋词','song-ci','虞美人','[]','飞花自有牵情处。',66,'宋词/ci.song.1000.json','["飞花自有牵情处。", "不向枝边坠。", "随风飘荡已堪愁。", "更伴东流流水、过秦楼。", "楼中翠黛含春怨。", "闲倚阑干见。", "远弹双泪惜香红。", "暗恨玉颜光景、与花同。"]'),
('song-ci-301','虞美人','晏几道','宋','宋词','song-ci','虞美人','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','曲阑干外天如水。',66,'宋词/ci.song.1000.json','["曲阑干外天如水。", "昨夜还曾倚。", "初将明月比佳期。", "长向月圆时候、望人归。", "罗衣著破前香在。", "旧意谁教改。", "一春离恨懒调弦。", "犹有两行闲泪、宝筝前。"]'),
('song-ci-302','虞美人','晏几道','宋','宋词','song-ci','虞美人','[]','疏梅月下歌金缕。',66,'宋词/ci.song.1000.json','["疏梅月下歌金缕。", "忆共文君语。", "更谁情浅似春风。", "一夜满枝新绿、替残红。", "苹香已有莲开信。", "两桨佳期近。", "采莲时节定来无。", "醉后满身花影、倩人扶。"]'),
('song-ci-303','虞美人','晏几道','宋','宋词','song-ci','虞美人','[]','玉箫吹遍烟花路。',66,'宋词/ci.song.1000.json','["玉箫吹遍烟花路。", "小谢经年去。", "更教谁画远山眉。", "又是陌头风细、恼人时。", "时光不解年年好。", "叶上秋声早。", "可怜蝴蝶易分飞。", "只有杏梁双燕、每来归。"]'),
('song-ci-304','虞美人','晏几道','宋','宋词','song-ci','虞美人','[]','秋风不似春风好。',66,'宋词/ci.song.1000.json','["秋风不似春风好。", "一夜金英老。", "更谁来凭曲阑干。", "惟有雁边斜月、照关山。", "双星旧约年年在。", "笑尽人情改。", "有期无定是无期。", "说与小云新恨、也低眉。"]'),
('song-ci-305','虞美人','晏几道','宋','宋词','song-ci','虞美人','[]','小梅枝上东君信。',66,'宋词/ci.song.1000.json','["小梅枝上东君信。", "雪后花期近。", "南枝开尽北枝开。", "长被陇头游子、寄春来。", "年年衣袖年年泪。", "总为今朝意。", "问谁同是忆花人。", "赚得小鸿眉黛、也低颦。"]'),
('song-ci-306','虞美人','晏几道','宋','宋词','song-ci','虞美人','[]','湿红笺纸回纹字。',66,'宋词/ci.song.1000.json','["湿红笺纸回纹字。", "多少柔肠事。", "去年双燕欲归时。", "还是碧云千里、锦书迟。", "南楼风月长依旧。", "别恨无端有。", "倩谁横笛倚危阑。", "今夜落梅声里、怨关山。"]'),
('song-ci-307','虞美人','晏几道','宋','宋词','song-ci','虞美人','[]','一弦弹尽仙韶乐。',66,'宋词/ci.song.1000.json','["一弦弹尽仙韶乐。", "曾破千金学。", "玉楼银烛夜深深。", "愁见曲中双泪、落香襟。", "从来不奈离声怨。", "几度朱弦断。", "未知谁解赏新音。", "长是好风明月、暗知心。"]'),
('song-ci-308','采桑子','晏几道','宋','宋词','song-ci','采桑子','[]','秋千散后朦胧月，满院人闲。',52,'宋词/ci.song.1000.json','["秋千散后朦胧月，满院人闲。", "几处雕阑。", "一夜风吹杏粉残。", "昭阳殿里春衣就，金缕初乾。", "莫信朝寒。", "明日花前试舞看。"]'),
('song-ci-309','采桑子','晏几道','宋','宋词','song-ci','采桑子','[]','花前独占春风早，长爱江梅。',52,'宋词/ci.song.1000.json','["花前独占春风早，长爱江梅。", "秀艳清杯。", "芳意先愁凤管催。", "寻香已落闲人后，此恨难裁。", "更晚须来。", "却恐初开胜未开。"]'),
('song-ci-310','采桑子','晏几道','宋','宋词','song-ci','采桑子','[]','芦鞭坠遍杨花陌，晚见珍珍。',52,'宋词/ci.song.1000.json','["芦鞭坠遍杨花陌，晚见珍珍。", "疑是朝云。", "来作高唐梦里人。", "应怜醉落楼中帽，长带歌尘。", "试拂香茵。", "留解金鞍睡过春。"]'),
('song-ci-311','采桑子','晏几道','宋','宋词','song-ci','采桑子','[]','日高庭院杨花转，闲淡春风。',52,'宋词/ci.song.1000.json','["日高庭院杨花转，闲淡春风。", "昨夜匆匆。", "颦入遥山翠黛中。", "金盆水冷菱花净，满面残红。", "欲洗犹慵。", "弦上啼乌此夜同。"]'),
('song-ci-312','采桑子','晏几道','宋','宋词','song-ci','采桑子','[]','征人去日殷勤嘱，莫负心期。',52,'宋词/ci.song.1000.json','["征人去日殷勤嘱，莫负心期。", "寒雁来时。", "第一传书慰别离。", "轻春织就机中素，泪墨题诗。", "欲寄相思。", "日日高楼看雁飞。"]'),
('song-ci-313','采桑子','晏几道','宋','宋词','song-ci','采桑子','[]','花时恼得琼枝瘦，半被残香。',52,'宋词/ci.song.1000.json','["花时恼得琼枝瘦，半被残香。", "睡损梅妆。", "红泪今春第一行。", "风流笑伴相逢处，白马游缰。", "共折垂杨。", "手拈芳条说夜长。"]'),
('song-ci-314','采桑子','晏几道','宋','宋词','song-ci','采桑子','[]','春风不负年年信，长趁花期。',52,'宋词/ci.song.1000.json','["春风不负年年信，长趁花期。", "小锦堂西。", "红杏初开第一枝。", "碧箫度曲留人醉，昨夜归迟。", "短恨凭谁。", "莺语殷勤月落时。"]'),
('song-ci-315','采桑子','晏几道','宋','宋词','song-ci','采桑子','[]','秋来更觉消魂苦，小字还稀。',52,'宋词/ci.song.1000.json','["秋来更觉消魂苦，小字还稀。", "坐想行思。", "怎得相看似旧时。", "南楼把手凭肩处，风月应知。", "别后除非。", "梦里时时得见伊。"]'),
('song-ci-316','采桑子','晏几道','宋','宋词','song-ci','采桑子','[]','谁将一点凄凉意，送入低眉。',52,'宋词/ci.song.1000.json','["谁将一点凄凉意，送入低眉。", "画箔闲垂。", "多是今宵得睡迟。", "夜痕记尽窗间月，曾误心期。", "准拟相思。", "还是窗间记月时。"]'),
('song-ci-317','采桑子','晏几道','宋','宋词','song-ci','采桑子','[]','宜春苑外楼堪倚，雪意方浓。',52,'宋词/ci.song.1000.json','["宜春苑外楼堪倚，雪意方浓。", "雁影冥濛。", "正共银屏小景同。", "可无人解相思处，昨夜东风。", "梅蕊应红。", "知在谁家锦字中。"]'),
('song-ci-318','采桑子','晏几道','宋','宋词','song-ci','采桑子','[]','白莲池上当时月，今夜重圆。',52,'宋词/ci.song.1000.json','["白莲池上当时月，今夜重圆。", "曲水兰船。", "忆伴飞琼看月眠。", "黄花绿酒分携后，泪湿吟笺。", "旧事年年。", "时节南湖又采莲。"]'),
('song-ci-319','采桑子','晏几道','宋','宋词','song-ci','采桑子','[]','高吟烂醉淮西月，诗酒相留。',52,'宋词/ci.song.1000.json','["高吟烂醉淮西月，诗酒相留。", "明日归舟。", "碧藕花中醉过秋。", "文姬赠别双团扇，自写银钩。", "散尽离愁。", "携得清风出画楼。"]'),
('song-ci-320','采桑子','晏几道','宋','宋词','song-ci','采桑子','[]','前欢几处笙歌地，长负登临。',52,'宋词/ci.song.1000.json','["前欢几处笙歌地，长负登临。", "月幌风襟。", "犹忆西楼著意深。", "莺花见尽当时事，应笑如今。", "一寸愁心。", "日日寒蝉夜夜砧。"]'),
('song-ci-321','采桑子','晏几道','宋','宋词','song-ci','采桑子','[]','无端恼破桃源梦，明日青楼。',52,'宋词/ci.song.1000.json','["无端恼破桃源梦，明日青楼。", "玉腻花柔。", "不学行云易去留。", "应嫌衫袖前香冷，重傍金虬。", "歌扇风流。", "遮尽归时翠黛愁。"]'),
('song-ci-322','采桑子','晏几道','宋','宋词','song-ci','采桑子','[]','年年此夕东城见，欢意匆匆。',52,'宋词/ci.song.1000.json','["年年此夕东城见，欢意匆匆。", "明日还重。", "却在楼台缥缈中。", "垂螺拂黛清歌女，曾唱相逢。", "秋月春风。", "醉枕香衾一岁同。"]'),
('song-ci-323','采桑子','晏几道','宋','宋词','song-ci','采桑子','[]','双螺未学同心绾，已占歌名。',52,'宋词/ci.song.1000.json','["双螺未学同心绾，已占歌名。", "月白风清。", "长倚昭华笛里声。", "知音敲尽朱颜改，寂寞时情。", "一曲离亭。", "惜与青楼忍泪听。"]'),
('song-ci-324','采桑子','晏几道','宋','宋词','song-ci','采桑子','[]','西楼月下当时见，泪粉偷匀。',52,'宋词/ci.song.1000.json','["西楼月下当时见，泪粉偷匀。", "歌罢还颦。", "恨隔炉烟看未真。", "别来楼外垂杨缕，几换青春。", "倦客红尘。", "长记楼中粉泪人。"]'),
('song-ci-325','采桑子','晏几道','宋','宋词','song-ci','采桑子','[]','非花非雾前时见，满眼娇春。',52,'宋词/ci.song.1000.json','["非花非雾前时见，满眼娇春。", "浅笑微颦。", "恨隔垂帘看未真。", "殷勤借问家何处，不在红尘。", "若是朝云。", "宜作今宵梦里人。"]'),
('song-ci-326','采桑子','晏几道','宋','宋词','song-ci','采桑子','[]','当时月下分飞处，依旧凄凉。',52,'宋词/ci.song.1000.json','["当时月下分飞处，依旧凄凉。", "也会思量。", "不道孤眠夜更长。", "泪痕搵遍鸳鸯枕，重绕回廊。", "月上东窗。", "长到如今欲断肠。"]'),
('song-ci-327','采桑子','晏几道','宋','宋词','song-ci','采桑子','[]','湘妃浦口莲开尽，昨夜红稀。',52,'宋词/ci.song.1000.json','["湘妃浦口莲开尽，昨夜红稀。", "懒过前溪。", "闲舣扁舟看雁飞。", "去年谢女池边醉，晚雨霏微。", "记得归时。", "旋折新荷盖舞衣。"]'),
('song-ci-328','采桑子','晏几道','宋','宋词','song-ci','采桑子','[]','别来长记西楼事，结遍兰襟。',52,'宋词/ci.song.1000.json','["别来长记西楼事，结遍兰襟。", "遗恨重寻。", "弦断相如绿绮琴。", "何时一枕逍遥夜，细话初心。", "若问如今。", "也似当时著意深。"]'),
('song-ci-329','采桑子','晏几道','宋','宋词','song-ci','采桑子','[]','红窗碧玉新名旧，犹绾双螺。',52,'宋词/ci.song.1000.json','["红窗碧玉新名旧，犹绾双螺。", "一寸秋波。", "千斛明珠觉未多。", "小来竹马同游客，惯听清歌。", "今日蹉跎。", "恼乱工夫晕翠蛾。"]'),
('song-ci-330','采桑子','晏几道','宋','宋词','song-ci','采桑子','[]','昭华凤管知名久，长闭帘栊。',52,'宋词/ci.song.1000.json','["昭华凤管知名久，长闭帘栊。", "闻道春慵。", "方倚庭花晕脸红。", "可怜金谷无人后，此会相逢。", "三弄临风。", "送得当筵玉盏空。"]'),
('song-ci-331','采桑子','晏几道','宋','宋词','song-ci','采桑子','[]','金风玉露初凉夜，秋草窗前。',52,'宋词/ci.song.1000.json','["金风玉露初凉夜，秋草窗前。", "浅醉闲眠。", "一枕江风梦不圆。", "长情短恨难凭寄，枉费红笺。", "试拂么弦。", "却恐琴心可暗传。"]'),
('song-ci-332','采桑子','晏几道','宋','宋词','song-ci','采桑子','[]','心期昨夜寻思遍，犹负殷勤。',52,'宋词/ci.song.1000.json','["心期昨夜寻思遍，犹负殷勤。", "齐斗堆金。", "难买丹诚一寸真。", "须知枕上尊前意，占得长春。", "寄语东邻。", "似此相看有几人。"]'),
('song-ci-333','踏莎行','晏几道','宋','宋词','song-ci','踏莎行','[]','柳上烟归，池南雪尽。',68,'宋词/ci.song.1000.json','["柳上烟归，池南雪尽。", "东风渐有繁华信。", "花开花谢蝶应知，春来春去莺能问。", "梦意犹疑，心期欲近。", "云笺字字萦方寸。", "宿妆曾比杏腮红，忆人细把香英认。"]'),
('song-ci-334','踏莎行','晏几道','宋','宋词','song-ci','踏莎行','[]','宿雨收尘，朝霞破暝。',68,'宋词/ci.song.1000.json','["宿雨收尘，朝霞破暝。", "风光暗许花期定。", "玉人呵手试妆时，粉香帘幕阴阴静。", "斜雁朱弦，孤鸾绿镜。", "伤春误了寻芳兴。", "去年今日杏墙西，啼莺唤得闲愁醒。"]'),
('song-ci-335','踏莎行','晏几道','宋','宋词','song-ci','踏莎行','[]','绿径穿花，红楼压水。',68,'宋词/ci.song.1000.json','["绿径穿花，红楼压水。", "寻芳误到蓬莱地。", "玉颜人是蕊珠仙，相逢展尽双蛾翠。", "梦草闲眠，流觞浅醉。", "一春总见瀛洲事。", "别来双燕又西飞，无端不寄相思字。"]'),
('song-ci-336','踏莎行','晏几道','宋','宋词','song-ci','踏莎行','[]','雪尽寒轻，月斜烟重。',68,'宋词/ci.song.1000.json','["雪尽寒轻，月斜烟重。", "清欢犹记前时共。", "迎风朱户背灯开，拂檐花影侵帘动。", "绣枕双鸳，香苞翠凤。", "从来往事都如梦。", "伤心最是醉归时，眼前少个人人送。"]'),
('song-ci-337','满庭芳','晏几道','宋','宋词','song-ci','满庭芳','[]','南苑吹花，西楼题叶，故园欢事重重。',117,'宋词/ci.song.1000.json','["南苑吹花，西楼题叶，故园欢事重重。", "凭阑秋思，闲记旧相逢。", "几处歌云梦雨，可怜便、流水西东。", "别来久，浅情未有，锦字系征鸿。", "年光还少味，开残槛菊，落尽溪桐。", "漫留得，尊前淡月西风。", "此恨谁堪共说，清愁付、绿酒杯中。", "佳期在，归时待把，香袖看啼红。"]'),
('song-ci-338','留春令','晏几道','宋','宋词','song-ci','留春令','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','画屏天畔，梦回依约，十洲云水。',61,'宋词/ci.song.1000.json','["画屏天畔，梦回依约，十洲云水。", "手拈红笺寄人书，写无限、伤春事。", "别浦高楼曾漫倚。", "对江南千里。", "楼下分流水声中，有当日、凭高泪。"]'),
('song-ci-339','留春令','晏几道','宋','宋词','song-ci','留春令','[]','采莲舟上，夜来陡觉，十分秋意。',61,'宋词/ci.song.1000.json','["采莲舟上，夜来陡觉，十分秋意。", "懊恼寒花暂时香，与情浅、人相似。", "玉蕊歌清招晚醉。", "恋小桥风细。", "水湿红裙酒初消，又记得、南溪事。"]'),
('song-ci-340','留春令','晏几道','宋','宋词','song-ci','留春令','[]','海棠风横，醉中吹落，香红强半。',61,'宋词/ci.song.1000.json','["海棠风横，醉中吹落，香红强半。", "小粉多情怨花飞，仔细把、残香看。", "一抹浓檀秋水畔。", "缕金衣新换。", "鹦鹉杯深艳歌迟，更莫放、人肠断。"]'),
('song-ci-341','风入松','晏几道','宋','宋词','song-ci','风入松','[]','柳阴庭院杏梢墙。',88,'宋词/ci.song.1000.json','["柳阴庭院杏梢墙。", "依旧巫阳。", "凤箫已远青楼在，水沈谁、复暖前香。", "临镜舞鸾离照，倚筝飞雁辞行。", "坠鞭人意自凄凉。", "泪眼回肠。", "断云残雨当年事，到如今、几处难忘。", "两袖晓风花陌，一帘夜月兰堂。"]'),
('song-ci-342','风入松','晏几道','宋','宋词','song-ci','风入松','[]','心心念念忆相逢。',88,'宋词/ci.song.1000.json','["心心念念忆相逢。", "别恨谁浓。", "就中懊恼难拼处，是擘钗、分钿匆匆。", "却似桃源路失，落花空记前踪。", "彩笺书尽浣溪红。", "深意难通。", "强欢殢酒图消遣，到醒来、愁闷还重。", "若是初心未改，多应此意须同。"]'),
('song-ci-343','清商怨','晏几道','宋','宋词','song-ci','清商怨','[]','庭花香信尚浅。',51,'宋词/ci.song.1000.json','["庭花香信尚浅。", "最玉楼先暖。", "梦觉春衾，江南依旧远。", "回纹锦字暗翦。", "漫寄与、也应归晚。", "要问相思，天涯犹自短。"]'),
('song-ci-344','秋蕊香','晏几道','宋','宋词','song-ci','秋蕊香','[]','池苑清阴欲就。',56,'宋词/ci.song.1000.json','["池苑清阴欲就。", "还傍送春时候。", "眼中人去难欢偶。", "谁共一杯芳酒。", "朱阑碧砌皆如旧。", "记携手。", "有情不管别离久。", "情在相逢终有。"]'),
('song-ci-345','秋蕊香','晏几道','宋','宋词','song-ci','秋蕊香','[]','歌彻郎君秋草。',56,'宋词/ci.song.1000.json','["歌彻郎君秋草。", "别恨远山眉小。", "无情莫把多情恼。", "第一归来须早。", "红尘自古长安道。", "故人少。", "相思不比相逢好。", "此别朱颜应老。"]'),
('song-ci-346','思远人','晏几道','宋','宋词','song-ci','思远人','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','红叶黄花秋意晚，千里念行客。',61,'宋词/ci.song.1000.json','["红叶黄花秋意晚，千里念行客。", "飞云过尽，归鸿无信，何处寄书得。", "泪弹不尽临窗滴。", "就砚旋研墨。", "渐写到别来，此情深处，红笺为无色。"]'),
('song-ci-347','碧牡丹','晏几道','宋','宋词','song-ci','碧牡丹','[]','翠袖疏纨扇。',89,'宋词/ci.song.1000.json','["翠袖疏纨扇。", "凉叶催归燕。", "一夜西风，几处伤高怀远。", "细菊枝头，开嫩香还遍。", "月痕依旧庭院。", "事何限。", "怅望秋意晚。", "离人鬓华将换。", "静忆天涯，路比此情犹短。", "试约鸾笺，传素期良愿。", "南云应有新雁。"]'),
('song-ci-348','长相思','晏几道','宋','宋词','song-ci','长相思','[]','长相思。',44,'宋词/ci.song.1000.json','["长相思。", "长相思。", "若问相思甚了期。", "除非相见时。", "长相思。", "长相思。", "欲把相思说似谁。", "浅情人不知。"]'),
('song-ci-349','醉落魄・一斛珠','晏几道','宋','宋词','song-ci','醉落魄・一斛珠','[]','满街斜月。',67,'宋词/ci.song.1000.json','["满街斜月。", "垂鞭自唱阳关彻。", "断尽柔肠思归切。", "都为人人，不许多时别。", "南桥昨夜风吹雪。", "短长亭下征尘歇。", "归时定有梅堪折。", "欲把离愁，细拈花枝说。"]'),
('song-ci-350','醉落魄・一斛珠','晏几道','宋','宋词','song-ci','醉落魄・一斛珠','[]','鸾孤月缺。',67,'宋词/ci.song.1000.json','["鸾孤月缺。", "两春惆怅音尘绝。", "如今若负当时节。", "信道欢缘，狂向衣襟结。", "若问相思何处歇。", "相逢便是相思彻。", "尽饶别后留心别。", "也待相逢，细把相思说。"]'),
('song-ci-351','醉落魄・一斛珠','晏几道','宋','宋词','song-ci','醉落魄・一斛珠','[]','天教命薄。',67,'宋词/ci.song.1000.json','["天教命薄。", "青楼占得声名恶。", "对酒当歌寻思著。", "月户星窗，多少旧期约。", "相逢细语初心错。", "两行红泪尊前落。", "霞觞且共深深酌。", "恼乱春宵，翠被都闲却。"]'),
('song-ci-352','醉落魄・一斛珠','晏几道','宋','宋词','song-ci','醉落魄・一斛珠','[]','休休莫莫。',67,'宋词/ci.song.1000.json','["休休莫莫。", "离多还是因缘恶。", "有情无奈思量著。", "月夜佳期，近写青笺约。", "心心口口长恨昨。", "分飞容易当时错。", "后期休似前欢薄。", "买断青楼，莫放春闲却。"]'),
('song-ci-353','望仙楼・胡捣练','晏几道','宋','宋词','song-ci','望仙楼・胡捣练','[]','小春花信日边来，未上江楼先坼。',55,'宋词/ci.song.1000.json','["小春花信日边来，未上江楼先坼。", "今岁东君消息。", "还自南枝得。", "素衣染尽天香，玉酒添成国色。", "一自故溪疏隔。", "肠断长相忆。"]'),
('song-ci-354','凤孤飞','晏几道','宋','宋词','song-ci','凤孤飞','[]','一曲画楼钟动，宛转歌声缓。',58,'宋词/ci.song.1000.json','["一曲画楼钟动，宛转歌声缓。", "绮席飞尘满。", "更少待、金蕉暖。", "细雨轻寒今夜短。", "依前是、粉墙别馆。", "端的欢期应未晚。", "奈归云难管。"]'),
('song-ci-355','西江月','晏几道','宋','宋词','song-ci','西江月','[]','愁黛颦成月浅，啼妆印得花残。',58,'宋词/ci.song.1000.json','["愁黛颦成月浅，啼妆印得花残。", "只消鸳枕夜来闲。", "晓镜心情便懒。", "醉帽檐头风细，征衫袖口香寒。", "绿江春水寄书难。", "携手佳期又晚。"]'),
('song-ci-356','西江月','晏几道','宋','宋词','song-ci','西江月','[]','南苑垂鞭路冷，西楼把袂人稀。',58,'宋词/ci.song.1000.json','["南苑垂鞭路冷，西楼把袂人稀。", "庭花犹有鬓边枝。", "且插残红自醉。", "画幕凉催燕去，香屏晓放云归。", "依前青枕梦回时。", "试问闲愁有几。"]'),
('song-ci-357','武陵春','晏几道','宋','宋词','song-ci','武陵春','[]','绿蕙红兰芳信歇，金蕊正风流。',56,'宋词/ci.song.1000.json','["绿蕙红兰芳信歇，金蕊正风流。", "应为诗人多怨秋。", "花意与消愁。", "梁王苑路香英密，长记旧嬉游。", "曾看飞琼戴满头。", "浮动舞梁州。"]'),
('song-ci-358','武陵春','晏几道','宋','宋词','song-ci','武陵春','[]','九日黄花如有意，依旧满珍丛。',56,'宋词/ci.song.1000.json','["九日黄花如有意，依旧满珍丛。", "谁似龙山秋兴浓。", "吹帽落西风。", "年年岁岁登高节，欢事旋成空。", "几处佳人此会同。", "今在泪痕中。"]'),
('song-ci-359','武陵春','晏几道','宋','宋词','song-ci','武陵春','[]','烟柳长堤知几曲，一曲一魂消。',56,'宋词/ci.song.1000.json','["烟柳长堤知几曲，一曲一魂消。", "秋水无情天共遥。", "愁送木兰桡。", "熏香绣被心情懒，期信转迢迢。", "记得来时倚画桥。", "红泪满鲛绡。"]'),
('song-ci-360','解佩令','晏几道','宋','宋词','song-ci','解佩令','[]','玉阶秋感，年华暗去。',84,'宋词/ci.song.1000.json','["玉阶秋感，年华暗去。", "掩深宫、团扇无绪。", "记得当时，自翦下、机中轻素。", "点丹青、画成秦女。", "凉襟犹在，朱弦未改，忍霜纨、飘零何处。", "自古悲凉，是情事、轻如云雨。", "倚么弦、恨长难诉。"]'),
('song-ci-361','行香子','晏几道','宋','宋词','song-ci','行香子','[]','晚绿寒红。',84,'宋词/ci.song.1000.json','["晚绿寒红。", "芳意匆匆。", "惜年华、今与谁同。", "碧云零落，数字征鸿。", "看渚莲凋，宫扇旧，怨秋风。", "流波坠叶，佳期何在，想天教、离恨无穷。", "试将前事，闲倚梧桐。", "有消魂处，明月夜，粉屏空。"]'),
('song-ci-362','庆春时','晏几道','宋','宋词','song-ci','庆春时','[]','倚天楼殿，升平风月，彩仗春移。',59,'宋词/ci.song.1000.json','["倚天楼殿，升平风月，彩仗春移。", "鸾丝凤竹，长生调里，迎得翠舆归。", "雕鞍游罢，何处还有心期。", "浓熏翠被，深停画烛，人约月西时。"]'),
('song-ci-363','庆春时','晏几道','宋','宋词','song-ci','庆春时','[]','梅梢已有，春来音信，风意犹寒。',59,'宋词/ci.song.1000.json','["梅梢已有，春来音信，风意犹寒。", "南楼暮雪，无人共赏，闲却玉阑干。", "殷勤今夜，凉月还似眉弯。", "尊前为把，桃根丽曲，重倚四弦看。"]'),
('song-ci-364','喜团圆','晏几道','宋','宋词','song-ci','喜团圆','[]','危楼静锁，窗中远岫，门外垂杨。',59,'宋词/ci.song.1000.json','["危楼静锁，窗中远岫，门外垂杨。", "珠帘不禁春风度，解偷送馀香。", "眠思梦想，不如双燕，得到兰房。", "别来只是，凭高泪眼，感旧离肠。"]'),
('song-ci-365','忆闷令','晏几道','宋','宋词','song-ci','忆闷令','[]','取次临鸾匀画浅。',56,'宋词/ci.song.1000.json','["取次临鸾匀画浅。", "酒醒迟来晚。", "多情爱惹闲愁，长黛眉低敛。", "月底相逢花下见。", "有深深良愿。", "愿期信、似月如花，须更教长远。"]'),
('song-ci-366','梁州令','晏几道','宋','宋词','song-ci','梁州令','[]','莫唱阳关曲。',58,'宋词/ci.song.1000.json','["莫唱阳关曲。", "泪湿当年金缕。", "离歌自古最消魂，闻歌更在魂消处。", "南楼杨柳多情绪。", "不系行人住。", "人情却似飞絮。", "悠扬便逐春风去。"]'),
('song-ci-367','燕归梁','晏几道','宋','宋词','song-ci','燕归梁','[]','莲叶雨，蓼花风。',57,'宋词/ci.song.1000.json','["莲叶雨，蓼花风。", "秋恨几枝红。", "远烟收尽水溶溶。", "飞雁碧云中。", "衷肠事。", "鱼笺字。", "情绪年年相似。", "凭高双袖晚寒浓。", "人在月桥东。"]'),
('song-ci-368','胡捣练','晏几道','宋','宋词','song-ci','胡捣练','[]','小亭初报一枝梅，惹起江南归兴。',56,'宋词/ci.song.1000.json','["小亭初报一枝梅，惹起江南归兴。", "遥想玉溪风景，水漾横斜影。", "异香直到醉乡中，醉后还因香醒。", "好是玉容相并。", "人与花争莹。"]'),
('song-ci-369','扑蝴蝶','晏几道','宋','宋词','song-ci','扑蝴蝶','[]','风梢雨叶，绿遍江南岸。',92,'宋词/ci.song.1000.json','["风梢雨叶，绿遍江南岸。", "思归倦客，寻芳来最晚。", "酒边红日初长，陌上飞花正满。", "凄凉数声弦管。", "怨春短。", "玉人应在，明月楼中画眉懒。", "鱼笺锦字，多时音信断。", "恨如去水空长，事与行云渐远。", "罗衾旧香馀暖。"]'),
('song-ci-370','丑奴儿・采桑子','晏几道','宋','宋词','song-ci','丑奴儿・采桑子','[]','夜来酒醒清无梦，愁倚阑干。',52,'宋词/ci.song.1000.json','["夜来酒醒清无梦，愁倚阑干。", "露滴轻寒。", "雨打芙蓉泪不乾。", "佳人别后音尘悄，瘦尽难拼。", "明月无端。", "已过红楼十二间。"]'),
('song-ci-371','谒金门','晏几道','宋','宋词','song-ci','谒金门','[]','溪声急。',53,'宋词/ci.song.1000.json','["溪声急。", "无数落花漂出。", "燕子分泥蜂酿蜜。", "迟迟艳风日。", "须信芳菲随失。", "况复佳期难必。", "拟把此情书万一。", "愁多翻阁笔。"]'),
('song-ci-372','忆黄梅','王观','宋','宋词','song-ci','忆黄梅','[]','枝上叶儿未展。',97,'宋词/ci.song.1000.json','["枝上叶儿未展。", "已有坠红千片。", "春意怎生防，怎不怨。", "被我安排，矮牙床斗帐，和娇艳。", "移在花丛里面。", "请君看。", "惹清香，偎媚暖。", "爱香爱暖金杯满。", "问春怎管。", "大家拼、便做东风，总吹交零乱。", "犹肯自、输我鸳鸯一半。"]'),
('song-ci-373','浪淘沙','王观','宋','宋词','song-ci','浪淘沙','[]','素手水晶盘。',64,'宋词/ci.song.1000.json','["素手水晶盘。", "垒起仙丸。", "红绡剪碎却成团。", "逗得安排金粟遍，何似鸡冠。", "味胜玉浆寒。", "只被宜酸。", "莫将荔子一般看。", "色淡香消僝僽损，才到长安。"]'),
('song-ci-374','天香','王观','宋','宋词','song-ci','天香','[]','霜瓦鸳鸯，风帘翡翠，今年早是寒少。',116,'宋词/ci.song.1000.json','["霜瓦鸳鸯，风帘翡翠，今年早是寒少。", "矮钉明窗，侧开朱户，断莫乱教人到。", "重阴未解，云共雪、商量不了。", "青帐垂毡要密，红炉收围宜小。", "呵梅弄妆试巧。", "绣罗衣、瑞云芝草。", "伴我语时同语，笑时同笑。", "已被金尊劝倒。", "又唱个新词故相恼。", "尽道穷冬，元来恁好。"]'),
('song-ci-375','卜算子','王观','宋','宋词','song-ci','卜算子','[]','水是眼波横，山是眉峰聚。',52,'宋词/ci.song.1000.json','["水是眼波横，山是眉峰聚。", "欲问行人去那边，眉眼盈盈处。", "才始送春归，又送君归去。", "若到江东赶上春，千万和春住。"]'),
('song-ci-376','清平乐','王观','宋','宋词','song-ci','清平乐','[]','黄金殿里。',54,'宋词/ci.song.1000.json','["黄金殿里。", "烛影双龙戏。", "劝得官家真个醉。", "进酒犹呼万岁。", "折旋舞彻伊州。", "君恩与整搔头。", "一夜御前宣住，六宫多少人愁。"]'),
('song-ci-377','雨中花令','王观','宋','宋词','song-ci','雨中花令','[]','百尺清泉声陆续。',68,'宋词/ci.song.1000.json','["百尺清泉声陆续。", "映潇洒、碧梧翠竹。", "面千步回廊，重重帘幕，小枕敧寒玉。", "试展鲛绡看画轴。", "见一片、潇湘凝绿。", "待玉漏穿花，银河垂地，月上栏干曲。"]'),
('song-ci-378','庆清朝慢・庆清朝','王观','宋','宋词','song-ci','庆清朝慢・庆清朝','[]','调雨为酥，催冰做水，东君分付春还。',118,'宋词/ci.song.1000.json','["调雨为酥，催冰做水，东君分付春还。", "何人便将轻暖，点破残寒。", "结伴踏青去好，平头鞋子小双鸾。", "烟郊外，望中秀色，如有无间。", "晴则个，阴则个，饾饤得天气，有许多般。", "须教镂花拨柳，争要先看。", "不道吴绫绣袜，香泥斜沁几行斑。", "东风巧，尽收翠绿，吹在眉山。"]'),
('song-ci-379','清平乐','王观','宋','宋词','song-ci','清平乐','[]','宜春小苑。',54,'宋词/ci.song.1000.json','["宜春小苑。", "处处花开满。", "学得红妆红要浅。", "催上金车要看。", "君王曲宴瑶池。", "小舟掠水如飞。", "夺得锦标归去，匆匆不惜罗衣。"]'),
('song-ci-380','木兰花令','王观','宋','宋词','song-ci','木兰花令','[]','铜驼陌上新正后。',64,'宋词/ci.song.1000.json','["铜驼陌上新正后。", "第一风流除是柳。", "勾牵春事不如梅，断送离人强似酒。", "东君有意偏撋就。", "惯得腰肢真个瘦。", "阿谁道你不思量，因甚眉头长恁皱。"]'),
('song-ci-381','生查子','王观','宋','宋词','song-ci','生查子','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','关山魂梦长，塞雁音书少。',48,'宋词/ci.song.1000.json','["关山魂梦长，塞雁音书少。", "两鬓可怜青，一夜相思老。", "归傍碧纱窗，说与人人道。", "真个别离难，不似相逢好。"]'),
('song-ci-382','菩萨蛮','王观','宋','宋词','song-ci','菩萨蛮','[]','单于吹落山头月。',52,'宋词/ci.song.1000.json','["单于吹落山头月。", "漫漫江上沙如雪。", "谁唱缕金衣。", "水寒船舫稀。", "芦花枫叶浦。", "忆抱琵琶语。", "身未发长沙。", "梦魂先到家。"]'),
('song-ci-383','江城梅花引','王观','宋','宋词','song-ci','江城梅花引','[]','年年江上见寒梅。',104,'宋词/ci.song.1000.json','["年年江上见寒梅。", "暗香来。", "为谁开。", "疑是月宫、仙子下瑶台。", "冷艳一枝春在手，故人远，相思寄与谁。", "怨极恨极嗅香蕊。", "念此情，家万里。", "暮霞散绮。", "楚天碧、片片轻飞。", "为我多情，特地点征衣。", "花易飘零人易老，正心碎，那堪塞管吹。"]'),
('song-ci-384','高阳台','王观','宋','宋词','song-ci','高阳台','[]','红入桃腮，青回柳眼，韶华已破三分。',122,'宋词/ci.song.1000.json','["红入桃腮，青回柳眼，韶华已破三分。", "人不归来，空教草怨王孙。", "平明几点催花雨，梦半阑、敧枕初闻。", "问东君，因甚将春，老了闲人。", "东郊十里香尘满，旋安排玉勒，整顿雕轮。", "趁取芳时，共寻岛上红云。", "朱衣引马黄金带，算到头、总是虚名。", "莫闲愁，一半悲秋，一半伤春。"]'),
('song-ci-385','减字木兰花','王观','宋','宋词','song-ci','减字木兰花','[]','瑞云仙雾。',52,'宋词/ci.song.1000.json','["瑞云仙雾。", "拂晓重重遮绣户。", "一炷清香。", "千尺流霞入寿觞。", "家门转好。", "从此应须长不老。", "来岁春风。", "看拜西枢小令公。"]'),
('song-ci-386','红芍药','王观','宋','宋词','song-ci','红芍药','[]','人生百岁，七十稀少。',108,'宋词/ci.song.1000.json','["人生百岁，七十稀少。", "更除十年孩童小。", "又十年昏老。", "都来五十载，一半被、睡魔分了。", "那二十五载之中，宁无些个烦恼。", "仔细思量，好追欢及早。", "遇酒追朋笑傲。", "任玉山摧倒。", "沈醉且沈醉，人生似、露垂芳草。", "幸新来、有酒如渑，结千秋歌笑。"]'),
('song-ci-387','失调名','王观','宋','宋词','song-ci','失调名','[]','十三妮子绿窗中。',8,'宋词/ci.song.1000.json','["十三妮子绿窗中。"]'),
('song-ci-388','临江仙','王观','宋','宋词','song-ci','临江仙','[]','别岸相逢何草草，扁舟两岸垂杨。',69,'宋词/ci.song.1000.json','["别岸相逢何草草，扁舟两岸垂杨。", "绣屏珠箔绮香囊。", "酒深歌拍缓，愁入翠眉长。", "燕子归来人去也，此时无奈昏黄。", "桃花应是我心肠。", "不禁微雨，流泪湿红妆。"]'),
('song-ci-389','万年欢','王安礼','宋','宋词','song-ci','万年欢','[]','雅出群芳。',119,'宋词/ci.song.1000.json','["雅出群芳。", "占春前信息，腊后风光。", "野岸邮亭，繁似万点轻霜。", "清浅溪流倒影，更黯淡、月色笼香。", "浑疑是、姑射冰姿，寿阳粉面初妆。", "多情对景易感，况淮天庾岭，迢递相望。", "愁听龙吟凄绝，画角悲凉。", "念昔因谁醉赏，向此际、空恼危肠。", "终须待结实，恁时佳味堪尝。"]'),
('song-ci-390','潇湘忆故人慢','王安礼','宋','宋词','song-ci','潇湘忆故人慢','["\u6d1e\u5ead\u6e56"]','薰风微动，方樱桃弄色，萱草成窠。',129,'宋词/ci.song.1000.json','["薰风微动，方樱桃弄色，萱草成窠。", "翠帏敞轻罗。", "试冰簟初展，几尺湘波。", "疏帘广厦，寄潇洒、一枕南柯。", "引多少、梦中归绪，洞庭雨棹烟蓑。", "惊回处，闲昼永，但时时，燕雏莺友相过。", "正绿影婆娑。", "况庭有幽花，池有新荷。", "青梅煮酒，幸随分、赢得高歌。", "功名事、到头终在，岁华忍负清和。"]'),
('song-ci-391','点绛唇','王安礼','宋','宋词','song-ci','点绛唇','[]','春睡腾腾，觉来鸳被堆香暖。',50,'宋词/ci.song.1000.json','["春睡腾腾，觉来鸳被堆香暖。", "起来慵懒。", "触目情何限。", "深院日斜，人静花阴转。", "柔肠断。", "凭高不见。", "芳草连天远。"]'),
('song-ci-392','江神子・江城子','张舜民','宋','宋词','song-ci','江神子・江城子','[]','七朝文物旧江山。',86,'宋词/ci.song.1000.json','["七朝文物旧江山。", "水如天。", "莫凭栏。", "千古斜阳，无处问长安。", "更隔秦淮闻旧曲，秋已半，夜将阑。", "争教潘鬓不生斑。", "敛芳颜。", "抹么弦。", "须记琵琶，子细说因缘。", "待得鸾胶肠已断，重别日，是何年。"]'),
('song-ci-393','朝中措','张舜民','宋','宋词','song-ci','朝中措','[]','三湘迁客思悠哉。',57,'宋词/ci.song.1000.json','["三湘迁客思悠哉。", "尊俎定常开。", "云雨未消歌伴，山川忍对离杯。", "他年来此，贤侯未去，忍话先回。", "好在江南山色，恁时重上高台。"]'),
('song-ci-394','卖花声','张舜民','宋','宋词','song-ci','卖花声','[]','木叶下君山。',64,'宋词/ci.song.1000.json','["木叶下君山。", "空水漫漫。", "十分斟酒敛芳颜。", "不是渭城西去客，休唱阳关。", "醉袖抚危栏。", "天淡云闲。", "何人此路得生还。", "回首夕阳红尽处，应是长安。"]'),
('song-ci-395','卖花声','张舜民','宋','宋词','song-ci','卖花声','[]','楼上久踟躇。',64,'宋词/ci.song.1000.json','["楼上久踟躇。", "地远身孤。", "拟将憔悴吊三闾。", "自是长安日下影，流落江湖。", "烂醉且消除。", "不醉何如。", "又看暝色满平芜。", "试问寒沙新到雁，应有来书。"]'),
('song-ci-396','江南好・忆江南','曾布','宋','宋词','song-ci','江南好・忆江南','[]','江南客，家有宁馨儿。',64,'宋词/ci.song.1000.json','["江南客，家有宁馨儿。", "三世文章称大手，一门兄弟独良眉。", "藉甚众多推。", "千里足，来自渥洼池。", "莫倚善题鹦鹉赋，青山须待健时归。", "不似傲当时。"]'),
('song-ci-397','水调歌头','曾布','宋','宋词','song-ci','水调歌头','[]','魏豪有冯燕，年少客幽并。',120,'宋词/ci.song.1000.json','["魏豪有冯燕，年少客幽并。", "击球斗鸡为戏，游侠久知名。", "因避仇、来东郡。", "元戎留属中军。", "直气凌貔虎，须臾叱咤风云。", "凛凛坐中生。", "偶乘佳兴。", "轻裘锦带，东风跃马，往来寻访幽胜。", "游冶出东城。", "堤上莺花撩乱，香车宝马纵横。", "草软平沙稳。", "高楼两岸春风，语笑隔帘声。"]'),
('song-ci-398','水调歌头','曾布','宋','宋词','song-ci','水调歌头','[]','袖笼鞭敲镫。',118,'宋词/ci.song.1000.json','["袖笼鞭敲镫。", "无语独闲行。", "绿杨下、人初静。", "烟澹夕阳明。", "窈窕佳人，独立瑶阶，掷果潘郎，瞥见红颜横波盻，不胜娇软倚银屏。", "曳红裳，频推朱户，半开还掩，似欲倚、咿哑声里，细说深情。", "因遣林间青鸟，为言彼此心期，的的深相许，窃香解佩，绸缪相顾不胜情。"]'),
('song-ci-399','水调歌头','曾布','宋','宋词','song-ci','水调歌头','[]','说良人滑将张婴。',111,'宋词/ci.song.1000.json','["说良人滑将张婴。", "从来嗜酒，还家镇长酩酊狂酲。", "屋上鸣鸠空斗，梁间客燕相惊。", "谁与花为主，兰房从此，朝云夕雨两牵萦。", "似游丝飘荡，随风无定。", "奈何岁华荏苒，欢计苦难凭。", "唯见新恩缱绻，连枝并翼，香闺日日为郎，谁知松萝托蔓，一比一毫轻。"]'),
('song-ci-400','水调歌头','曾布','宋','宋词','song-ci','水调歌头','[]','一夕还家醉，开户起相迎。',98,'宋词/ci.song.1000.json','["一夕还家醉，开户起相迎。", "为郎引裾相庇，低首略潜形。", "情深无隐。", "欲郎乘间起佳兵。", "授青萍。", "茫然抚叹，不忍欺心。", "尔能负心於彼，於我必无情。", "熟视花钿不足，刚肠终不能平。", "假手迎天意，一挥霜刃。", "窗间粉颈断瑶琼。"]'),
('song-ci-401','水调歌头','曾布','宋','宋词','song-ci','水调歌头','[]','凤凰钗、宝玉凋零。',114,'宋词/ci.song.1000.json','["凤凰钗、宝玉凋零。", "惨然怅，娇魂怨，饮泣吞声。", "还被凌波呼唤，相将金谷同游，想见逢迎处，揶揄羞面，妆脸泪盈盈。", "醉眠人、醒来晨起，血凝螓首，但惊喧，白邻里、骇我卒难明。", "思败幽囚推究，覆盆无计哀鸣。", "丹笔终诬服，圜门驱拥，衔冤垂首欲临刑。"]'),
('song-ci-402','水调歌头','曾布','宋','宋词','song-ci','水调歌头','[]','向红尘里，有喧呼攘臂，转声辟众，莫遣人冤滥、杀张室，忍偷生。',104,'宋词/ci.song.1000.json','["向红尘里，有喧呼攘臂，转声辟众，莫遣人冤滥、杀张室，忍偷生。", "僚吏惊呼呵叱，狂辞不变如初，投身属吏，慷慨吐丹诚。", "仿佛缧绁，自疑梦中，闻者皆惊叹，为不平。", "割爱无心，泣对虞姬，手戮倾城宠，翻然起死，不教仇怨负冤声。"]'),
('song-ci-403','水调歌头','曾布','宋','宋词','song-ci','水调歌头','[]','义城元靖贤相国，喜慕英雄士，赐金缯。',95,'宋词/ci.song.1000.json','["义城元靖贤相国，喜慕英雄士，赐金缯。", "闻斯事，频叹赏，封章归印。", "请赎冯燕罪，日边紫泥封诏，阖境赦深刑。", "万古三河风义在，青简上、众知名。", "河东注，任流水滔滔，水涸名难泯。", "至今乐府歌咏。", "流入管弦声。"]'),
('song-ci-404','临江仙','魏夫人','宋','宋词','song-ci','临江仙','[]','庭院深深深几许，云窗雾阁春迟。',70,'宋词/ci.song.1000.json','["庭院深深深几许，云窗雾阁春迟。", "为谁憔悴损芳姿。", "夜来清梦好，应是发南枝。", "玉瘦檀轻无限恨，南楼羌管休吹。", "浓香吹尽有谁知。", "暖风迟日也，别到杏花肥。"]'),
('song-ci-405','好事近','魏夫人','宋','宋词','song-ci','好事近','[]','雨后晓寒轻，花外早莺啼歇。',53,'宋词/ci.song.1000.json','["雨后晓寒轻，花外早莺啼歇。", "愁听隔溪残漏，正一声凄咽。", "不堪西望去程赊，离肠万回结。", "不似海棠阴下，按凉州时节。"]'),
('song-ci-406','阮郎归','魏夫人','宋','宋词','song-ci','阮郎归','[]','夕阳楼外落花飞。',56,'宋词/ci.song.1000.json','["夕阳楼外落花飞。", "晴空碧四垂。", "去帆回首已天涯。", "孤烟卷翠微。", "楼上客，鬓成丝。", "归来未有期。", "断魂不忍下危梯。", "桐阴月影移。"]'),
('song-ci-407','减字木兰花','魏夫人','宋','宋词','song-ci','减字木兰花','[]','西楼明月。',52,'宋词/ci.song.1000.json','["西楼明月。", "掩映梨花千树雪。", "楼上人归。", "愁听孤城一雁飞。", "玉人何处。", "又见江南春色暮。", "芳信难寻。", "去后桃花流水深。"]'),
('song-ci-408','减字木兰花','魏夫人','宋','宋词','song-ci','减字木兰花','[]','落花飞絮。',52,'宋词/ci.song.1000.json','["落花飞絮。", "杳杳天涯人甚处。", "欲寄相思。", "春尽衡阳雁渐稀。", "离肠泪眼。", "肠断泪痕流不断。", "明月西楼。", "一曲阑干一倍愁。"]'),
('song-ci-409','菩萨蛮','魏夫人','宋','宋词','song-ci','菩萨蛮','[]','溪山掩映斜阳里。',52,'宋词/ci.song.1000.json','["溪山掩映斜阳里。", "楼台影动鸳鸯起。", "隔岸两三家。", "出墙红杏花。", "绿杨堤下路。", "早晚溪边去。", "三见柳绵飞。", "离人犹未归。"]'),
('song-ci-410','菩萨蛮','魏夫人','宋','宋词','song-ci','菩萨蛮','[]','东风已绿瀛洲草。',52,'宋词/ci.song.1000.json','["东风已绿瀛洲草。", "画楼帘卷清霜晓。", "清绝比湖梅。", "花开未满枝。", "长天音信断。", "又见南归雁。", "何处是离愁。", "长安明月楼。"]'),
('song-ci-411','菩萨蛮','魏夫人','宋','宋词','song-ci','菩萨蛮','[]','红楼斜倚连溪曲。',52,'宋词/ci.song.1000.json','["红楼斜倚连溪曲。", "楼前溪水凝寒玉。", "荡漾木兰船。", "船中人少年。", "荷花娇欲语。", "笑入鸳鸯浦。", "波上暝烟低。", "菱歌月下归。"]'),
('song-ci-412','定风波','魏夫人','宋','宋词','song-ci','定风波','[]','不是无心惜落花。',73,'宋词/ci.song.1000.json','["不是无心惜落花。", "落花无意恋春华。", "昨日盈盈枝上笑。", "谁道。", "今朝吹去落谁家。", "把酒临风千种恨。", "难问。", "梦回云散见无涯。", "妙舞清歌谁是主。", "回顾。", "高城不见夕阳斜。"]'),
('song-ci-413','点绛唇','魏夫人','宋','宋词','song-ci','点绛唇','[]','波上清风，画船明月人归后，渐消残酒。',50,'宋词/ci.song.1000.json','["波上清风，画船明月人归后，渐消残酒。", "独自凭阑久。", "聚散匆匆，此恨年年有，重回首。", "淡烟疏柳。", "隐隐芜城漏。"]'),
('song-ci-414','武陵春','魏夫人','宋','宋词','song-ci','武陵春','[]','小院无人帘半卷，独自倚阑时。',56,'宋词/ci.song.1000.json','["小院无人帘半卷，独自倚阑时。", "宽尽春来金缕衣。", "憔悴有谁知。", "玉人近日书来少，应是怨来迟。", "梦里长安早晚归。", "和泪立斜晖。"]'),
('song-ci-415','江城子','魏夫人','宋','宋词','song-ci','江城子','[]','别郎容易见郎难。',86,'宋词/ci.song.1000.json','["别郎容易见郎难。", "几何般。", "懒临鸾。", "憔悴容仪，陡觉缕衣宽。", "门外红梅将谢也，谁信道、不曾看。", "晓妆楼上望长安。", "怯轻寒。", "莫凭阑。", "嫌怕东风，吹恨上眉端。", "为报归期须及早，休误妾、一春闲。"]'),
('song-ci-416','卷珠帘・蝶恋花','魏夫人','宋','宋词','song-ci','卷珠帘・蝶恋花','[]','记得来时春未暮。',70,'宋词/ci.song.1000.json','["记得来时春未暮。", "执手攀花，袖染花梢露。", "暗卜春心共花语。", "争寻双朵争先去。", "多情因甚相辜负。", "轻折轻离，欲向谁分诉。", "泪湿海棠花枝处。", "东君空把奴分付。"]'),
('song-ci-417','系裙腰','魏夫人','宋','宋词','song-ci','系裙腰','[]','灯花耿耿漏迟迟。',72,'宋词/ci.song.1000.json','["灯花耿耿漏迟迟。", "人别后、夜凉时。", "西风潇洒梦初回。", "谁念我，就单枕，皱双眉。", "锦屏绣幌与秋期。", "肠欲断、泪偷垂。", "月明还到小窗西。", "我恨你，我忆你，你争知。"]'),
('song-ci-418','清平乐','王仲甫','宋','宋词','song-ci','清平乐','[]','黄金殿里。',54,'宋词/ci.song.1000.json','["黄金殿里。", "烛影双龙戏。", "劝得官家真个醉，进酒犹呼万岁。", "锦裀舞彻凉州，君恩与整搔头。", "一夜御前宣唤，六宫多少人愁。"]'),
('song-ci-419','满朝欢','王仲甫','宋','宋词','song-ci','满朝欢','[]','忆得延州，旧曾相见，东城近东下住。',68,'宋词/ci.song.1000.json','["忆得延州，旧曾相见，东城近东下住。", "被若著意引归家，放十分、以上抬举。", "小样罗衫，淡红拂过，风流万般做处。", "怕伊蓦地忆人时，梦中来、不要迷路。"]'),
('song-ci-420','丑奴儿・采桑子','王仲甫','宋','宋词','song-ci','丑奴儿・采桑子','[]','牡丹不好长春好，有个因依。',52,'宋词/ci.song.1000.json','["牡丹不好长春好，有个因依。", "一两枝儿。", "但是风光总属伊。", "当初祗为嫦娥种，月正明时。", "教恁芳菲。", "伴著团圆十二回。"]'),
('song-ci-421','永遇乐','王仲甫','宋','宋词','song-ci','永遇乐','[]','风折新英，雨肥繁实，又还如豆。',128,'宋词/ci.song.1000.json','["风折新英，雨肥繁实，又还如豆。", "玉核初成，红腮尚浅，齿软酸透。", "粉墙低亚，佳人惊见，不管露沾襟袖。", "一枝钗子未插，应把手挪频嗅。", "相思病酒，只因思此，免使文君眉皱。", "入鼎调羹，攀林止渴，功业还依旧。", "看看飞燕，衔将春去，又将欲、黄昏时候。", "争如向、金盘满捧，共君王对酒。"]'),
('song-ci-422','浪淘沙','王仲甫','宋','宋词','song-ci','浪淘沙','[]','素手水晶盘。',64,'宋词/ci.song.1000.json','["素手水晶盘。", "垒起仙丸。", "红绡碾碎却成团。", "逗得安排金粟遍，何似鸡冠。", "味胜玉浆寒。", "只被宜酸。", "莫将荔子一般看。", "色淡香消僝僽损，才到长安。"]'),
('song-ci-423','醉落魄・一斛珠','王仲甫','宋','宋词','song-ci','醉落魄・一斛珠','[]','醉醒醒醉。',67,'宋词/ci.song.1000.json','["醉醒醒醉。", "凭君会取皆滋味。", "浓斟琥珀香浮蚁。", "一入愁肠，便有阳春意。", "须将席幕为天地。", "歌前起舞花前睡。", "从他兀兀陶陶里。", "犹胜醒醒，惹得闲憔悴。"]'),
('song-ci-424','蓦山溪','王仲甫','宋','宋词','song-ci','蓦山溪','[]','挂冠神武，来作烟花主。',102,'宋词/ci.song.1000.json','["挂冠神武，来作烟花主。", "千里好江山，都尽是、君恩赐与。", "风勾月引，催上泛宅时，酒倾玉，脍堆雪，总道神仙侣。", "蓑衣箬笠，更著些儿雨。", "横笛两三声，晚云中、惊鸥来去。", "欲烦妙手，写入散人图，蜗角名，蝇头利，著甚来由顾。"]'),
('song-ci-425','离亭燕・离亭宴','孙浩然','宋','宋词','song-ci','离亭燕・离亭宴','[]','一带江山如画。',84,'宋词/ci.song.1000.json','["一带江山如画。", "景物向秋潇洒。", "水浸碧天何处断，霁色冷光相射。", "橘树荻花洲，掩映竹篱茅舍。", "天际客帆高挂。", "烟外酒旗低亚。", "多少六朝兴废事，尽入渔樵闲话。", "怅望倚层楼，红日无言西下。"]'),
('song-ci-426','夜行船','孙浩然','宋','宋词','song-ci','夜行船','[]','何处采菱归暮。',67,'宋词/ci.song.1000.json','["何处采菱归暮。", "隔宵烟、菱歌轻举。", "白苹风起月华寒，影朦胧、半和梅雨。", "脉脉相逢心似许。", "扶兰棹、黯然凝伫。", "遥指前村，隐隐烟树，含情背人归去。"]'),
('song-ci-427','鹧鸪天','王诜','宋','宋词','song-ci','鹧鸪天','[]','才子阴风度远关。',64,'宋词/ci.song.1000.json','["才子阴风度远关。", "清愁曾向画图看。", "山衔斗柄三星没，雪共月明千里寒。", "新路陌，旧江干。", "崎岖谁叹客程难。", "临风更听昭华笛，簌簌梅花满地残。"]'),
('song-ci-428','花心动','王诜','宋','宋词','song-ci','花心动','[]','春欲来时，看雪里、新梅品流珍绝。',127,'宋词/ci.song.1000.json','["春欲来时，看雪里、新梅品流珍绝。", "气韵楚江，颜色中央，数朵巧熔香蜡。", "嫩苞珠泪圆金烛，娇腮润、蜂房微缺。", "画栏悄，佳人道妆，醉吟风月。", "淡白轻红谩说。", "算何事、东君用心偏别。", "赋与异姿，添与清香，堪向苦寒时节。", "但教开后金尊满，休惆怅、落时歌阙。", "断肠也，繁枝为谁赠折。"]'),
('song-ci-429','落梅花・落梅','王诜','宋','宋词','song-ci','落梅花・落梅','[]','寿阳妆晚，慵匀素脸，经宵醉痕堪惜。',131,'宋词/ci.song.1000.json','["寿阳妆晚，慵匀素脸，经宵醉痕堪惜。", "前村雪里，几枝初绽，□冰姿仙格。", "忍被东风，乱飘满地，残英堆积。", "可堪江上起离愁，凭谁说寄，肠断未归客。", "流恨声传羌笛。", "感行人、水亭山驿。", "越溪信阻，仙乡路杳，但风流尘迹。", "香艳浓时，东君吟赏，已成轻掷。", "愿身长健，且凭阑，明年还放春消息。"]'),
('song-ci-430','黄莺儿','王诜','宋','宋词','song-ci','黄莺儿','[]','多情春意忆时节。',116,'宋词/ci.song.1000.json','["多情春意忆时节。", "北圃人来，传道江梅，依稀芳姿，数枝新发。", "夸嫩脸著胭脂，腻滑凝香雪。", "问伊还记年时，正好相看，因甚轻别。", "情切。", "往事散浮云，旧恨成华发。", "算知空对，绮槛雕栏，孜孜望人攀折。", "愁未见苦思量，待见重端叠。", "愿与永仿高堂，云雨芳菲月。"]'),
('song-ci-431','踏青游','王诜','宋','宋词','song-ci','踏青游','[]','金勒狨鞍，西城嫩寒春晓。',104,'宋词/ci.song.1000.json','["金勒狨鞍，西城嫩寒春晓。", "路渐入、垂杨芳草。", "过平堤，穿绿迳，几声啼鸟。", "是处里，谁家杏花临水，依约靓妆窥照。", "极目高原，东风露桃烟岛。", "望十里、红围绿绕。", "更相将、乘酒兴，幽情多少。", "待向晚、从头记将归去，说与凤楼人道。"]'),
('song-ci-432','忆故人・烛影摇红','王诜','宋','宋词','song-ci','忆故人・烛影摇红','[]','烛影摇红向夜阑，乍酒醒、心情懒。',61,'宋词/ci.song.1000.json','["烛影摇红向夜阑，乍酒醒、心情懒。", "尊前谁为唱阳关，离恨天涯远。", "无奈云沈雨散。", "凭阑干、东风泪眼。", "海棠开后，燕子来时，黄昏庭院。"]'),
('song-ci-433','行香子','王诜','宋','宋词','song-ci','行香子','[]','金井先秋，梧叶飘黄。',83,'宋词/ci.song.1000.json','["金井先秋，梧叶飘黄。", "几回惊觉梦初长。", "雨微烟淡。", "疏雨池塘。", "渐蓼花明，菱花冷，藕花凉。", "幽人已惯，枕单衾冷，任商飙、催换年光。", "问谁相伴，终日清狂。", "有竹间风，尊中酒，水边床。"]'),
('song-ci-434','蝶恋花','王诜','宋','宋词','song-ci','蝶恋花','[]','钟送黄昏鸡报晓。',70,'宋词/ci.song.1000.json','["钟送黄昏鸡报晓。", "昏晓相催，世事何时了。", "万恨千愁人自老。", "春来依旧生芳草。", "忙处人多闲处少。", "闲处光阴，几个人知道。", "独上高楼云渺渺。", "天涯一点青山小。"]'),
('song-ci-435','玉楼春','王诜','宋','宋词','song-ci','玉楼春','[]','锦城春色花无数。',64,'宋词/ci.song.1000.json','["锦城春色花无数。", "排比笙歌留客住。", "轻寒轻暖夹衣天，乍雨乍晴寒食路。", "花虽不语莺能语。", "莫放韶光容易去。", "海棠开后月明前，纵有千金无买处。"]'),
('song-ci-436','花发沁园春','王诜','宋','宋词','song-ci','花发沁园春','[]','帝里春归，早先妆点，皇家池馆园林。',129,'宋词/ci.song.1000.json','["帝里春归，早先妆点，皇家池馆园林。", "雏莺未迁，燕子乍归，时节戏弄晴阴。", "琼楼珠阁，恰正在、柳曲花心。", "翠袖艳、衣凭阑干，惯闻弦管新音。", "此际相携宴赏，纵行乐随处，芳树遥岑。", "桃腮杏脸，嫩英万叶，千枝绿浅红深。", "轻风终日，泛暗香、长蛮衣襟。", "洞户醉，归访笙歌，晚来云海沈沈。"]'),
('song-ci-437','人月圆','王诜','宋','宋词','song-ci','人月圆','[]','小桃枝上春来早，初试薄罗衣。',59,'宋词/ci.song.1000.json','["小桃枝上春来早，初试薄罗衣。", "年年此夜，华灯盛照，人月圆时。", "禁街箫鼓，寒轻夜永，纤手同携。", "更阑人静。", "千门笑语，声在帘帏。"]'),
('song-ci-438','换遍歌头','王诜','宋','宋词','song-ci','换遍歌头','[]','雪霁轻尘敛，好风初报柳。',116,'宋词/ci.song.1000.json','["雪霁轻尘敛，好风初报柳。", "春寒浅、当三五。", "是处鳌山耸，金羁宝乘，游赏遍蓬壶。", "向黄昏时候。", "对双龙阙门前，皓月华灯射，变清昼。", "彩凤低衔天语。", "承宣诏传呼。", "飞上层霄，共陪霞觞频举。", "更渐阑，正回路。", "遥拥车佩珊珊，笼纱满香衢。", "指凤楼、相将醉归去。"]'),
('song-ci-439','失调名','王诜','宋','宋词','song-ci','失调名','[]','合彩丝、对缠玉腕。',9,'宋词/ci.song.1000.json','["合彩丝、对缠玉腕。"]'),
('song-ci-440','失调名','王诜','宋','宋词','song-ci','失调名','[]','偷闲结个艾虎儿，要插在、秋蝉鬓畔。',17,'宋词/ci.song.1000.json','["偷闲结个艾虎儿，要插在、秋蝉鬓畔。"]'),
('song-ci-441','失调名','王诜','宋','宋词','song-ci','失调名','[]','带了黄花，强饮茱萸酒。',11,'宋词/ci.song.1000.json','["带了黄花，强饮茱萸酒。"]'),
('song-ci-442','画堂春令・画堂春','王诜','宋','宋词','song-ci','画堂春令・画堂春','[]','画堂霜重晓寒消，南枝红雪妆成。',57,'宋词/ci.song.1000.json','["画堂霜重晓寒消，南枝红雪妆成。", "卷帘疑是弄妆人。", "粉面带春醒。", "最爱北江临岸，含娇浅淡精神。", "微风不动水纹平。", "倒影斗轻盈。"]'),
('song-ci-443','撼庭竹','王诜','宋','宋词','song-ci','撼庭竹','[]','绰略青梅弄春色。',84,'宋词/ci.song.1000.json','["绰略青梅弄春色。", "真艳态堪惜。", "经年费尽东君力。", "有情先到探春客。", "无语泣寒香，时暗度瑶席。", "月下风前空怅望，思携手同摘。", "画栏倚遍无消息。", "佳辰乐事再难得。", "还是夕阳天，空暮云凝碧。"]'),
('song-ci-444','蝶恋花','王诜','宋','宋词','song-ci','蝶恋花','[]','小雨初晴回晚照。',70,'宋词/ci.song.1000.json','["小雨初晴回晚照。", "金翠楼台，倒影芙蓉沼。", "杨柳垂垂风袅袅。", "嫩荷无数青钿小。", "似此园林无限好。", "流落归来，到了心情少。", "坐到黄昏人悄悄。", "更应添得朱颜老。"]'),
('song-ci-445','蓦山溪','陈济翁','宋','宋词','song-ci','蓦山溪','[]','去年今日，从驾游西苑。',102,'宋词/ci.song.1000.json','["去年今日，从驾游西苑。", "彩仗压金波，看水戏、鱼龙曼衍。", "宝津南殿，宴坐近天颜，金杯酒，君王劝。", "头上宫花颤。", "六军锦绣，万骑穿杨箭。", "日暮翠华归，拥钧天、笙歌一片。", "如今关外，千里未归人，前山雨，西楼晚。", "望断思君眼。"]'),
('song-ci-446','蓦山溪','陈济翁','宋','宋词','song-ci','蓦山溪','[]','薰风时候。',102,'宋词/ci.song.1000.json','["薰风时候。", "芍药披晴昼。", "天上玉阑干，展一枰、天家锦绣。", "汉宫唐殿。", "嫔御逞妖娆，飞燕女，太真妃，一样新妆就。", "黄金拈线，色与红芳斗。", "谁把绛绡衣，误将他、胭脂渍透。", "晚风生处，襟袖卷浓香，持玉斝，秉纱笼，倚醉听更漏。"]'),
('song-ci-447','踏青游','陈济翁','宋','宋词','song-ci','踏青游','[]','濯锦江头，羞杀艳桃秾李。',104,'宋词/ci.song.1000.json','["濯锦江头，羞杀艳桃秾李。", "纵赵昌、丹青难比。", "晕轻红，留浅素，千娇百媚。", "照绿水。", "恰如下临鸾镜，妃子弄妆犹醉。", "诗笔因循，不晓少陵深意。", "但满眼、伤春珠泪。", "燕来时，莺啼处，年年憔悴。", "便除是。", "秉烛凭阑吟赏，莫教夜深花睡。"]'),
('song-ci-448','水龙吟','苏轼','宋','宋词','song-ci','水龙吟','[]','古来云海茫茫，道山绛阙知何处。',126,'宋词/ci.song.1000.json','["古来云海茫茫，道山绛阙知何处。", "人间自有，赤城居士，龙蟠凤举。", "清净无为，坐忘遗照，八篇奇语。", "向玉霄东望，蓬莱暗霭，有云驾、骖风驭。", "行尽九州四海，笑纷纷、落花飞絮。", "临江一见，谪仙风采，无言心许。", "八表神游，浩然相对，酒酣箕踞。", "待垂天赋就，骑鲸路稳，约相将去。"]'),
('song-ci-449','水龙吟','苏轼','宋','宋词','song-ci','水龙吟','[]','楚山修竹如云，异材秀出千林表。',126,'宋词/ci.song.1000.json','["楚山修竹如云，异材秀出千林表。", "龙须半翦，凤膺微涨，玉肌匀绕。", "木落淮南，雨晴云梦，月明风袅。", "自中郎不见，桓伊去后，知孤负、秋多少。", "闻道岭南太守，后堂深、绿珠娇小。", "绮窗学弄，梁州初遍，霓裳未了。", "嚼徵含宫，泛商流羽，一声云杪。", "为使君洗尽，蛮风瘴雨，作霜天晓。"]'),
('song-ci-450','水龙吟','苏轼','宋','宋词','song-ci','水龙吟','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','似花还似非花，也无人惜从教坠。',126,'宋词/ci.song.1000.json','["似花还似非花，也无人惜从教坠。", "抛家傍路，思量却是，无情有思。", "萦损柔肠，困酣娇眼，欲开还闭。", "梦随风万里，寻郎去处，又还被、莺呼起。", "不恨此花飞尽，恨西园、落红难缀。", "晓来雨过，遗踪何在，一池萍碎。", "春色三分，二分尘土，一分流水。", "细看来，不是杨花点点，是离人泪。"]'),
('song-ci-451','水龙吟','苏轼','宋','宋词','song-ci','水龙吟','[]','小舟横截春江，卧看翠壁红楼起。',126,'宋词/ci.song.1000.json','["小舟横截春江，卧看翠壁红楼起。", "云间笑语，使君高会，佳人半醉。", "危柱哀弦，艳歌馀响，绕云萦水。", "念故人老大，风流未减，独回首、烟波里。", "推枕惘然不见，但空江、月明千里。", "五湖闻道，扁舟归去，仍携西子。", "云梦南州，武昌南岸，昔游应记。", "料多情梦里，端来见我，也参差是。"]'),
('song-ci-452','满庭芳','苏轼','宋','宋词','song-ci','满庭芳','[]','归去来兮，吾归何处，万里家在岷峨。',118,'宋词/ci.song.1000.json','["归去来兮，吾归何处，万里家在岷峨。", "百年强半，来日苦无多。", "坐见黄州再闰，儿童尽、楚语吴歌。", "山中友，鸡豚社酒，相劝老东坡。", "云何。", "当此去，人生底事，来往如梭。", "待闲看，秋风洛水清波。", "好在堂前细柳，应念我、莫翦柔柯。", "仍传语，江南父老，时与晒渔蓑。"]'),
('song-ci-453','满庭芳','苏轼','宋','宋词','song-ci','满庭芳','[]','香叆雕盘，寒生冰箸，画堂别是风光。',118,'宋词/ci.song.1000.json','["香叆雕盘，寒生冰箸，画堂别是风光。", "主人情重，开宴出红妆。", "腻玉圆搓素颈，藕丝嫩、新织仙裳。", "双歌罢，虚檐转月，馀韵尚悠扬。", "人间，何处有，司空见惯，应谓寻常。", "坐中有狂客，恼乱愁肠。", "报道金钗坠也，十指露、春笋纤长。", "亲曾见，全胜宋玉，想像赋高唐。"]'),
('song-ci-454','满庭芳','苏轼','宋','宋词','song-ci','满庭芳','[]','蜗角虚名，蝇头微利，算来著甚乾忙。',120,'宋词/ci.song.1000.json','["蜗角虚名，蝇头微利，算来著甚乾忙。", "事皆前定，谁弱又谁强。", "且趁闲身未老，尽放我、些子疏狂。", "百年里，浑教是醉，三万六千场。", "思量。", "能几许，忧愁风雨，一半相妨。", "又何须，抵死说短论长。", "幸对清风皓月，苔茵展、云幕高张。", "江南好，千锺美酒，一曲《满庭芳》。"]'),
('song-ci-455','满庭芳','苏轼','宋','宋词','song-ci','满庭芳','["\u957f\u6c5f"]','三十三年，今谁存者，算只君与长江。',118,'宋词/ci.song.1000.json','["三十三年，今谁存者，算只君与长江。", "凛然苍桧，霜干苦难双。", "闻道司州古县，云溪上、竹坞松窗。", "江南岸，不因送子，宁肯过吾邦。", "摐摐。", "疏雨过，风林舞破，烟盖云幢。", "愿持此邀君，一饮空缸。", "居士先生老矣，真梦里、相对残釭。", "歌舞断，行人未起，船鼓已逄逄。"]'),
('song-ci-456','满庭芳','苏轼','宋','宋词','song-ci','满庭芳','[]','三十三年，飘流江海，万里烟浪云帆。',118,'宋词/ci.song.1000.json','["三十三年，飘流江海，万里烟浪云帆。", "故人惊怪，憔悴老青衫。", "我自疏狂异趣，君何事、奔走尘凡。", "流年尽，穷途坐守，船尾冻相衔。", "巉巉。", "淮浦外，层楼翠壁，古寺空岩。", "步携手林间，笑挽ホホ。", "莫上孤峰尽处，萦望眼、云海相搀。", "家何在，因君问我，归梦绕松杉。"]'),
('song-ci-457','水调歌头','苏轼','宋','宋词','song-ci','水调歌头','[]','落日绣帘卷，亭下水连空。',114,'宋词/ci.song.1000.json','["落日绣帘卷，亭下水连空。", "知君为我，新作窗户湿青红。", "长记平山堂上，敧枕江南烟雨，渺渺没孤鸿。", "认得醉翁语，山色有无中。", "一千顷，都镜净，倒碧峰。", "忽然浪起，掀舞一叶白头翁。", "堪笑兰台公子，未解庄生天籁，刚道有雌雄。", "一点浩然气，千里快哉风。"]'),
('song-ci-458','水调歌头','苏轼','宋','宋词','song-ci','水调歌头','[]','安石在东海，从事鬓惊秋。',114,'宋词/ci.song.1000.json','["安石在东海，从事鬓惊秋。", "中年亲友难别，丝竹缓离愁。", "一旦功成名遂，准拟东还海道，扶病入西州。", "雅志困轩冕，遗恨寄沧洲。", "岁云暮，须早计，要褐裘。", "故乡归去千里，佳处辄迟留。", "我醉歌时君和，醉倒须君扶我，惟酒可忘忧。", "一任刘玄德，相对卧高楼。"]'),
('song-ci-459','水调歌头','苏轼','宋','宋词','song-ci','水调歌头','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','明月几时有，把酒问青天。',114,'宋词/ci.song.1000.json','["明月几时有，把酒问青天。", "不知天上宫阙，今夕是何年。", "我欲乘风归去，又恐琼楼玉宇，高处不胜寒。", "起舞弄清影，何似在人间。", "转朱阁，低绮户，照无眠。", "不应有恨，何事长向别时圆。", "人有悲欢离合，月有阴晴圆缺，此事古难全。", "但愿人长久，千里共婵娟。"]'),
('song-ci-460','水调歌头','苏轼','宋','宋词','song-ci','水调歌头','[]','昵昵儿女语，灯火夜微明。',114,'宋词/ci.song.1000.json','["昵昵儿女语，灯火夜微明。", "恩冤尔汝来去，弹指泪和声。", "忽变轩昂勇士，一鼓填然作气，千里不留行。", "回首暮云远，飞絮搅青冥。", "众禽里，真彩凤，独不鸣。", "跻攀寸步千险，一落百寻轻。", "烦子指间风雨，置我肠中冰炭，起坐不能平。", "推手从归去，无泪与君倾。"]'),
('song-ci-461','满江红','苏轼','宋','宋词','song-ci','满江红','[]','忧喜相寻，风雨过、一江春绿。',116,'宋词/ci.song.1000.json','["忧喜相寻，风雨过、一江春绿。", "巫峡梦、至今空有，乱山屏簇。", "何似伯鸾携德耀，箪瓢未足清欢足。", "渐粲然、光彩照阶庭，生兰玉。", "幽梦里，传心曲。", "肠断处，凭他续。", "文君婿知否，笑君卑辱。", "君不见周南歌汉广，天教夫子休乔木。", "便相将、左手抱琴书，云间宿。"]'),
('song-ci-462','满江红','苏轼','宋','宋词','song-ci','满江红','[]','江汉西来，高楼下、蒲萄深碧。',116,'宋词/ci.song.1000.json','["江汉西来，高楼下、蒲萄深碧。", "犹自带、岷峨云浪，锦江春色。", "君是南山遗爱守，我为剑外思归客。", "对此间、风物岂无情，殷勤说。", "江表传，君休读。", "狂处士，真堪惜。", "空洲对鹦鹉，苇花萧瑟。", "不独笑书生争底事，曹公黄祖俱飘忽。", "愿使君、还赋谪仙诗，追黄鹤。"]'),
('song-ci-463','满江红','苏轼','宋','宋词','song-ci','满江红','[]','东武南城，新堤固、涟漪初溢。',116,'宋词/ci.song.1000.json','["东武南城，新堤固、涟漪初溢。", "隐隐遍、长林高阜，卧红堆碧。", "枝上残花吹尽也，与君更向江头觅。", "问向前、犹有几多春，三之一。", "官里事，何时毕。", "风雨外，无多日。", "相将泛曲水，满城争出。", "君不见兰亭修禊事，当时坐上皆豪逸。", "到如今、修竹满山阴，空陈迹。"]'),
('song-ci-464','满江红','苏轼','宋','宋词','song-ci','满江红','["\u9ec4\u6cb3"]','清颖东流，愁目断、孤帆明灭。',115,'宋词/ci.song.1000.json','["清颖东流，愁目断、孤帆明灭。", "宦游处、青山白浪，万重千叠。", "孤负当年林下意，对床夜雨听萧瑟。", "恨此生、长向别离中，添华发。", "一尊酒，黄河侧。", "无限事，从头说。", "相看恍如昨，许多年月。", "衣上旧痕馀苦泪，眉间喜气添黄色。", "便与君、池上觅残春，花如雪。"]'),
('song-ci-465','满江红','苏轼','宋','宋词','song-ci','满江红','[]','天岂无情，天也解、多情留客。',115,'宋词/ci.song.1000.json','["天岂无情，天也解、多情留客。", "春向暖、朝来底事，尚飘轻雪。", "君过春来纡组绶，我应归去耽泉石。", "恐异时、杯酒忽相思，云山隔。", "浮世事，俱难必。", "人纵健，头应白。", "何辞更一醉，此欢难觅。", "欲向佳人诉离恨，泪珠先已凝双睫。", "但莫遣、新燕却来时，音书绝。"]'),
('song-ci-466','归朝欢','苏轼','宋','宋词','song-ci','归朝欢','["\u5e90\u5c71"]','我梦扁舟浮震泽。',122,'宋词/ci.song.1000.json','["我梦扁舟浮震泽。", "雪浪摇空千顷白。", "觉来满眼是庐山，倚天无数开青壁。", "此生长接淅。", "与君同是江南客。", "梦中游，觉来清赏，同作飞梭掷。", "明日西风还挂席。", "唱我新词泪沾臆。", "灵均去后楚山空，澧阳兰芷无颜色。", "君才如梦得。", "武陵更在西南极。", "竹枝词，莫摇新唱，谁谓古今隔。"]'),
('song-ci-467','念奴娇','苏轼','宋','宋词','song-ci','念奴娇','[]','大江东去，浪淘尽、千古风流人物。',120,'宋词/ci.song.1000.json','["大江东去，浪淘尽、千古风流人物。", "故垒西边人道是，三国周郎赤壁。", "乱石穿空，惊涛拍岸，卷起千堆雪。", "江山如画，一时多少豪杰。", "遥想公瑾当年，小乔初嫁了，雄姿英发。", "羽扇纶巾谈笑间，强虏灰飞烟灭。", "故国神游，多情应笑，我早生华发。", "人间如梦，一尊还酹江月。"]'),
('song-ci-468','雨中花・夜行船','苏轼','宋','宋词','song-ci','雨中花・夜行船','[]','今岁花时深院，尽日东风，荡扬茶烟。',120,'宋词/ci.song.1000.json','["今岁花时深院，尽日东风，荡扬茶烟。", "但有绿苔芳草，柳絮榆钱。", "闻道城西，长廊古寺，甲第名园。", "有国艳带酒，天香染袂，为我留连。", "清明过了，残红无处，对此泪洒尊前。", "秋向晚，一枝何事，向我依然。", "高会聊追短景，清商不暇馀妍。", "不如留取，十分春态，付与明年。"]'),
('song-ci-469','沁园春','苏轼','宋','宋词','song-ci','沁园春','[]','孤馆灯青，野店鸡号，旅枕梦残。',139,'宋词/ci.song.1000.json','["孤馆灯青，野店鸡号，旅枕梦残。", "渐月华收练，晨霜耿耿，云山摛锦，朝露清清。", "世路无穷，劳生有限，似此区区长鲜欢。", "微吟罢，凭征鞍无语，往事千端。", "当时共客长安。", "似二陆初来俱少年。", "有笔头千字，胸中万卷，致君尧舜，此事何难。", "用舍由时，行藏在我，袖手何妨闲处看。", "身长健，但优游卒岁，且斗尊前。"]'),
('song-ci-470','劝金船','苏轼','宋','宋词','song-ci','劝金船','[]','无情流水多情客。',104,'宋词/ci.song.1000.json','["无情流水多情客。", "劝我如曾识。", "杯行到手休辞却。", "这公道难得。", "曲水池上，小字更书年月。", "还对茂林修竹，似永和节。", "纤纤素手如霜雪。", "笑把秋花插。", "尊前莫怪歌声咽。", "又还是轻别。", "此去翱翔，遍赏玉堂金阙。", "欲问再来何岁，应有华发。"]'),
('song-ci-471','一丛花','苏轼','宋','宋词','song-ci','一丛花','[]','今年春浅腊侵年。',94,'宋词/ci.song.1000.json','["今年春浅腊侵年。", "冰雪破春妍。", "东风有信无人见，露微意、柳际花边。", "寒夜纵长，孤衾易暖，钟鼓渐清圆。", "朝来初日半含山。", "楼阁淡疏烟。", "游人便作寻芳计，小桃杏、应已争先。", "衰病少情，疏慵自放，惟爱日高眠。"]'),
('song-ci-472','木兰花令','苏轼','宋','宋词','song-ci','木兰花令','["\u897f\u6e56"]','霜馀已失长淮阔。',64,'宋词/ci.song.1000.json','["霜馀已失长淮阔。", "空听潺潺清颍咽。", "佳人犹唱醉翁词，四十三年如电抹。", "草头秋露流珠滑。", "三五盈盈还二八。", "与余同是识翁人，惟有西湖波底月。"]'),
('song-ci-473','木兰花令','苏轼','宋','宋词','song-ci','木兰花令','[]','知君仙骨无寒暑。',64,'宋词/ci.song.1000.json','["知君仙骨无寒暑。", "千载相逢犹旦暮。", "故将别语恼佳人，要看梨花枝上雨。", "落花已逐回风去。", "花本无心莺自诉。", "明朝归路下塘西，不见莺啼花落处。"]'),
('song-ci-474','木兰花令','苏轼','宋','宋词','song-ci','木兰花令','[]','梧桐叶上三更雨。',64,'宋词/ci.song.1000.json','["梧桐叶上三更雨。", "惊破梦魂无觅处。", "夜凉枕簟已知秋，更听寒蛩促机杼。", "梦中历历来时路。", "犹在江亭醉歌舞。", "尊前必有问君人，为道别来心与绪。"]'),
('song-ci-475','西江月','苏轼','宋','宋词','song-ci','西江月','[]','公子眼花乱发，老夫鼻观先通。',58,'宋词/ci.song.1000.json','["公子眼花乱发，老夫鼻观先通。", "领巾飘下瑞香风。", "惊起谪仙春梦。", "后土祠中玉蕊，蓬莱殿后鞓红。", "此花清绝更纤秾。", "把酒何人心动。"]'),
('song-ci-476','西江月','苏轼','宋','宋词','song-ci','西江月','[]','小院朱阑几曲，重城画鼓三通。',58,'宋词/ci.song.1000.json','["小院朱阑几曲，重城画鼓三通。", "更看微月转光风。", "归去香云入梦。", "翠袖争浮大白，皂罗半插斜红。", "灯花零落酒花秾。", "妙语一时飞动。"]'),
('song-ci-477','西江月','苏轼','宋','宋词','song-ci','西江月','[]','怪此花枝怨泣，托君诗句名通。',58,'宋词/ci.song.1000.json','["怪此花枝怨泣，托君诗句名通。", "凭将草木记吴风。", "继取相如云梦。", "点笔袖沾醉墨，谤花面有惭红。", "知君却是为情秾。", "怕见此花撩动。"]'),
('song-ci-478','西江月','苏轼','宋','宋词','song-ci','西江月','[]','闻道双衔凤带，不妨单著鲛绡。',58,'宋词/ci.song.1000.json','["闻道双衔凤带，不妨单著鲛绡。", "夜香知与阿谁烧。", "怅望水沈烟袅。", "云鬓风前绿卷，玉颜醉里红潮。", "莫教空度可怜宵。", "月与佳人共僚。"]'),
('song-ci-479','西江月','苏轼','宋','宋词','song-ci','西江月','[]','点点楼头细雨。',58,'宋词/ci.song.1000.json','["点点楼头细雨。", "重重江外平湖。", "当年戏马会东徐。", "今日凄凉南浦。", "莫恨黄花未吐。", "且教红粉相扶。", "酒阑不必看茱萸。", "俯仰人间今古。"]'),
('song-ci-480','西江月','苏轼','宋','宋词','song-ci','西江月','[]','龙焙今年绝品，谷帘自古珍泉。',58,'宋词/ci.song.1000.json','["龙焙今年绝品，谷帘自古珍泉。", "雪芽双井散神仙。", "苗裔来从北苑。", "汤发云腴酽白，盏浮花乳轻圆。", "人间谁敢更争妍。", "斗取红窗粉面。"]'),
('song-ci-481','西江月','苏轼','宋','宋词','song-ci','西江月','[]','别梦已随流水，泪巾犹裛香泉。',58,'宋词/ci.song.1000.json','["别梦已随流水，泪巾犹裛香泉。", "相如依旧是臞仙。", "人在瑶台阆苑。", "花雾萦风缥缈，歌珠滴水清圆。", "蛾眉新作十分妍。", "走马归来便面。"]'),
('song-ci-482','西江月','苏轼','宋','宋词','song-ci','西江月','[]','世事一场大梦，人生几度秋凉。',58,'宋词/ci.song.1000.json','["世事一场大梦，人生几度秋凉。", "夜来风叶已鸣廊。", "看取眉头鬓上。", "酒贱常愁客少，月明多被云妨。", "中秋谁与共孤光。", "把盏凄然北望。"]'),
('song-ci-483','西江月','苏轼','宋','宋词','song-ci','西江月','[]','莫叹平原落落，且应去鲁迟迟。',58,'宋词/ci.song.1000.json','["莫叹平原落落，且应去鲁迟迟。", "与君各记少年时。", "须信人生如寄。", "白发千茎相送，深杯百罚休辞。", "拍浮何用酒为池。", "我已为君德醉。"]'),
('song-ci-484','西江月','苏轼','宋','宋词','song-ci','西江月','[]','玉骨那愁瘴雾，冰姿自有仙风。',58,'宋词/ci.song.1000.json','["玉骨那愁瘴雾，冰姿自有仙风。", "海仙时遣探芳丛。", "倒挂绿毛么凤。", "素面翻嫌粉涴，洗妆不褪唇红。", "高情已逐晓云空。", "不与梨花同梦。"]'),
('song-ci-485','西江月','苏轼','宋','宋词','song-ci','西江月','[]','照野弥弥浅浪，横空暧暧微霄。',58,'宋词/ci.song.1000.json','["照野弥弥浅浪，横空暧暧微霄。", "障泥未解玉骢骄。", "我欲醉眠芳草。", "可惜一溪明月，莫教踏破琼瑶。", "解鞍敧枕绿杨桥。", "杜宇一声春晓。"]'),
('song-ci-486','西江月','苏轼','宋','宋词','song-ci','西江月','[]','三过平山堂下，半生弹指声中。',58,'宋词/ci.song.1000.json','["三过平山堂下，半生弹指声中。", "十年不见老仙翁。", "壁上龙蛇飞动。", "欲吊文章太守，仍歌杨柳春风。", "休言万事转头空。", "未转头时皆梦。"]'),
('song-ci-487','西江月','苏轼','宋','宋词','song-ci','西江月','[]','昨夜扁舟京口，今朝马首长安。',58,'宋词/ci.song.1000.json','["昨夜扁舟京口，今朝马首长安。", "旧官何物与新官。", "只有湖山公案。", "此景百年几变，个中下语千难。", "使君才气卷波澜。", "与把新诗判断。"]'),
('song-ci-488','临江仙','苏轼','宋','宋词','song-ci','临江仙','[]','细马远驮双侍女，青巾玉带红靴。',70,'宋词/ci.song.1000.json','["细马远驮双侍女，青巾玉带红靴。", "溪山好处便为家。", "谁知巴峡路，却见洛城花。", "面旋落英飞玉蕊，人间春日初斜。", "十年不见紫云车。", "龙丘新洞府，铅鼎养丹砂。"]'),
('song-ci-489','临江仙','苏轼','宋','宋词','song-ci','临江仙','[]','诗句端来磨我钝，钝锥不解生鋩。',70,'宋词/ci.song.1000.json','["诗句端来磨我钝，钝锥不解生鋩。", "欢颜为我解冰霜。", "酒阑清梦觉，春草满池塘。", "应念雪堂坡下老，昔年共采芸香。", "功成名遂早还乡。", "回车来过我，乔木拥千章。"]'),
('song-ci-490','临江仙','苏轼','宋','宋词','song-ci','临江仙','[]','我劝髯张归去好，从来自己忘情。',70,'宋词/ci.song.1000.json','["我劝髯张归去好，从来自己忘情。", "尘心消尽道心平。", "江南与塞北，何处不堪行。", "俎豆庚桑真过矣，凭君说与南荣。", "愿闻吴越报丰登。", "君王如有问，结袜赖王生。"]'),
('song-ci-491','临江仙','苏轼','宋','宋词','song-ci','临江仙','[]','自古相从休务日，何妨低唱微吟。',70,'宋词/ci.song.1000.json','["自古相从休务日，何妨低唱微吟。", "天垂云重作春阴。", "坐中人半醉，帘外雪将深。", "闻道分司狂御史，紫云无路追寻。", "凄风寒雨是骎骎。", "问囚长损气，见鹤忽惊心。"]'),
('song-ci-492','临江仙','苏轼','宋','宋词','song-ci','临江仙','[]','忘却成都来十载，因君未免思量。',70,'宋词/ci.song.1000.json','["忘却成都来十载，因君未免思量。", "凭将清泪洒江阳。", "故山知好在，孤客自悲凉。", "坐上别愁君未见，归来欲断无肠。", "殷勤且更尽离觞。", "此身如传舍，何处是吾乡。"]'),
('song-ci-493','临江仙','苏轼','宋','宋词','song-ci','临江仙','[]','尊酒何人怀李白，草堂遥指江东。',70,'宋词/ci.song.1000.json','["尊酒何人怀李白，草堂遥指江东。", "珠帘十里卷香风。", "花开又花谢，离恨几千重。", "轻舸渡江连夜到，一时惊笑衰容。", "语音犹自带吴侬。", "夜阑对酒处，依旧梦魂中。"]'),
('song-ci-494','临江仙','苏轼','宋','宋词','song-ci','临江仙','[]','九十日春都过了，贪忙何处追游。',70,'宋词/ci.song.1000.json','["九十日春都过了，贪忙何处追游。", "三分春色一分愁。", "雨翻榆荚阵，风转柳花球。", "阆苑先生须自责，蟠桃动是千秋。", "不知人世苦厌求。", "东皇不拘束，肯为使君留。"]'),
('song-ci-495','临江仙','苏轼','宋','宋词','song-ci','临江仙','[]','四大从来都遍满，此间风水何疑。',70,'宋词/ci.song.1000.json','["四大从来都遍满，此间风水何疑。", "故应为我发新诗。", "幽花香涧谷，寒藻舞沦漪。", "借与玉川生两腋，天仙未必相思。", "还凭流水送人归。", "层巅馀落日，草露已沾衣。"]'),
('song-ci-496','临江仙','苏轼','宋','宋词','song-ci','临江仙','[]','一别都门三改火，天涯踏尽红尘。',70,'宋词/ci.song.1000.json','["一别都门三改火，天涯踏尽红尘。", "依然一笑作春温。", "无波真古井，有节是秋筠。", "惆怅孤帆连夜发，送行淡月微云。", "尊前不用翠眉颦。", "人生如逆旅，我亦是行人。"]'),
('song-ci-497','临江仙','苏轼','宋','宋词','song-ci','临江仙','[]','多病休文都瘦损，不堪金带垂腰。',70,'宋词/ci.song.1000.json','["多病休文都瘦损，不堪金带垂腰。", "望湖楼上暗香飘。", "和风春弄袖，明月夜闻箫。", "酒醒梦回清漏永，隐床无限更潮。", "佳人不见董娇饶。", "徘徊花上月，空度可怜宵。"]'),
('song-ci-498','临江仙','苏轼','宋','宋词','song-ci','临江仙','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','夜饮东坡醒复醉，归来仿佛三更。',70,'宋词/ci.song.1000.json','["夜饮东坡醒复醉，归来仿佛三更。", "家童鼻息已雷鸣。", "敲门都不应，倚杖听江声。", "长恨此身非我有，何时忘却营营。", "夜阑风静縠纹平。", "小舟从此逝，江海寄馀生。"]'),
('song-ci-499','临江仙','苏轼','宋','宋词','song-ci','临江仙','[]','冬夜夜寒冰合井，画堂明月侵帏。',70,'宋词/ci.song.1000.json','["冬夜夜寒冰合井，画堂明月侵帏。", "青缸明灭照悲啼。", "青缸挑欲尽，粉泪裛还垂。", "未尽一尊先掩泪，歌声半带清悲。", "情声两尽莫相违。", "欲知肠断处，梁上暗尘飞。"]'),
('song-ci-500','渔家傲','苏轼','宋','宋词','song-ci','渔家傲','[]','千古龙蟠并虎踞。',72,'宋词/ci.song.1000.json','["千古龙蟠并虎踞。", "从公一吊兴亡处。", "渺渺斜风吹细雨。", "芳草渡。", "江南父老留公住。", "公驾飞车凌彩雾。", "红鸾骖乘青鸾驭。", "却讶此洲名白鹭。", "非吾侣。", "翩然欲下还飞去。"]'),
('song-ci-501','渔家傲','苏轼','宋','宋词','song-ci','渔家傲','["\u94b1\u5858\u6c5f"]','送客归来灯火尽。',72,'宋词/ci.song.1000.json','["送客归来灯火尽。", "西楼淡月凉生晕。", "明日潮来无定准。", "潮来稳。", "舟横渡口重城近。", "江水似知孤客恨。", "南风为解佳人愠。", "莫学时流轻久困。", "频寄问。", "钱塘江上须忠信。"]'),
('song-ci-502','渔家傲','苏轼','宋','宋词','song-ci','渔家傲','[]','皎皎牵牛河汉女。',72,'宋词/ci.song.1000.json','["皎皎牵牛河汉女。", "盈盈临水无由语。", "望断碧云空日暮。", "无寻处。", "梦回芳草生春浦。", "鸟散馀花纷似雨。", "汀洲苹老香风度。", "明月多情来照户。", "但揽取。", "清光长送人归去。"]'),
('song-ci-503','渔家傲','苏轼','宋','宋词','song-ci','渔家傲','[]','一曲《阳关》情几许。',74,'宋词/ci.song.1000.json','["一曲《阳关》情几许。", "知君欲向秦川去。", "白马皂貂留不住。", "回首处。", "孤城不见天霖雾。", "到日长安花似雨。", "故关杨柳初飞絮。", "渐见靴刀迎夹路。", "谁得似。", "风流膝上王文度。"]'),
('song-ci-504','鹧鸪天','苏轼','宋','宋词','song-ci','鹧鸪天','[]','林断山明竹隐墙。',64,'宋词/ci.song.1000.json','["林断山明竹隐墙。", "乱蝉衰草小池塘。", "翻空白鸟时时见，照水红蕖细细香。", "村舍外，古城旁。", "杖藜徐步转斜阳。", "殷勤昨夜三更雨，又得浮生一日凉。"]'),
('song-ci-505','鹧鸪天','苏轼','宋','宋词','song-ci','鹧鸪天','[]','笑拈红梅亸翠翘。',66,'宋词/ci.song.1000.json','["笑拈红梅亸翠翘。", "扬州十里最妖饶。", "夜来绮席亲曾见，撮得精神滴滴娇。", "娇后眼，舞时腰。", "刘郎几度欲魂消。", "明朝酒醒知何处，肠断云间《紫玉箫》。"]'),
('song-ci-506','少年游','苏轼','宋','宋词','song-ci','少年游','[]','银塘朱槛曲尘波。',62,'宋词/ci.song.1000.json','["银塘朱槛曲尘波。", "圆绿卷新荷。", "兰条荐浴，菖花酿酒，天气尚清和。", "好将沈醉酬佳节，十分酒、一分歌。", "狱草烟深，讼庭人悄，无吝宴游过。"]'),
('song-ci-507','少年游','苏轼','宋','宋词','song-ci','少年游','[]','去年相送，馀杭门外，飞雪似杨花。',62,'宋词/ci.song.1000.json','["去年相送，馀杭门外，飞雪似杨花。", "今年春尽，杨花似雪，犹不见还家。", "对酒卷帘邀明月，风露透窗纱。", "恰似姮娥怜双燕，分明照、画梁斜。"]'),
('song-ci-508','定风波','苏轼','宋','宋词','song-ci','定风波','[]','两两轻红半晕腮。',73,'宋词/ci.song.1000.json','["两两轻红半晕腮。", "依依独为使君回。", "若道使君无此意。", "何为。", "双花不向别人开。", "但看低昂烟雨里。", "不已。", "劝君休诉十分杯。", "更问尊前狂副使。", "来岁。", "花开时节与谁来。"]'),
('song-ci-509','定风波','苏轼','宋','宋词','song-ci','定风波','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','莫听穿林打叶声。',73,'宋词/ci.song.1000.json','["莫听穿林打叶声。", "何妨吟啸且徐行。", "竹杖芒鞋轻胜马。", "谁怕。", "一蓑烟雨任平生。", "料峭春风吹酒醒。", "微冷。", "山头斜照却相迎。", "回首向来潇洒处。", "归去。", "也无风雨也无晴。"]'),
('song-ci-510','定风波','苏轼','宋','宋词','song-ci','定风波','[]','与客携壶上翠微。',73,'宋词/ci.song.1000.json','["与客携壶上翠微。", "江涵秋影雁初飞。", "尘世难逢开口笑。", "年少。", "菊花须插满头归。", "酩酊但酬佳节了。", "云峤。", "登临不用怨斜晖。", "古往今来谁不老。", "多少。", "牛山何必更沾衣。"]'),
('song-ci-511','定风波','苏轼','宋','宋词','song-ci','定风波','[]','莫怪鸳鸯绣带长。',73,'宋词/ci.song.1000.json','["莫怪鸳鸯绣带长。", "腰轻不胜舞衣裳。", "薄幸只贪游冶去。", "何处。", "垂杨系马恣轻狂。", "花谢絮飞春又尽。", "堪恨。", "断弦尘管伴啼妆。", "不信归来但自看。", "怕见。", "为郎憔悴却羞郎。"]'),
('song-ci-512','定风波','苏轼','宋','宋词','song-ci','定风波','["\u897f\u6e56"]','千古风流阮步兵。',73,'宋词/ci.song.1000.json','["千古风流阮步兵。", "平生游宦爱东平。", "千里远来还不住。", "归去。", "空留风韵照人清。", "红粉尊前深懊恼。", "休道。", "怎生留得许多情。", "记得明年花絮乱。", "须看。", "泛西湖是断肠声。"]'),
('song-ci-513','定风波','苏轼','宋','宋词','song-ci','定风波','[]','雨洗娟娟嫩叶光。',73,'宋词/ci.song.1000.json','["雨洗娟娟嫩叶光。", "风吹细细绿筠香。", "秀色乱侵书帙晚。", "帘卷。", "清阴微过酒尊凉。", "人画竹身肥拥肿。", "何用。", "先生落笔胜萧郎。", "记得小轩岑寂夜。", "廊下。", "月和疏影上东墙。"]'),
('song-ci-514','定风波','苏轼','宋','宋词','song-ci','定风波','[]','好睡慵开莫厌迟。',73,'宋词/ci.song.1000.json','["好睡慵开莫厌迟。", "自怜冰脸不时宜。", "偶作小红桃杏色，闲雅，尚馀孤瘦雪霜姿。", "休把闲心随物态，何事，酒生微晕沁瑶肌。", "诗老不知梅格在，吟咏，更看绿叶与青枝。"]'),
('song-ci-515','定风波','苏轼','宋','宋词','song-ci','定风波','[]','月满苕溪照夜堂。',73,'宋词/ci.song.1000.json','["月满苕溪照夜堂。", "五星一老斗光芒。", "十五年间真梦里。", "何事。", "长庚对月独凄凉。", "绿鬓苍颜同一醉。", "还是。", "六人吟笑水云乡。", "宾主谈锋谁得似。", "看取。", "曹刘今对两苏张。"]'),
('song-ci-516','定风波','苏轼','宋','宋词','song-ci','定风波','[]','常羡人间琢玉郎。',73,'宋词/ci.song.1000.json','["常羡人间琢玉郎。", "天应乞与点酥娘。", "尽道清歌传皓齿。", "风起。", "雪飞炎海变清凉。", "万里归来颜愈少。", "微笑。", "笑时犹带岭梅香。", "试问岭南应不好。", "却道。", "此心安处是吾乡。"]'),
('song-ci-517','南乡子','苏轼','宋','宋词','song-ci','南乡子','[]','晚景落琼杯。',66,'宋词/ci.song.1000.json','["晚景落琼杯。", "照眼云山翠作堆。", "认得岷峨春雪浪，初来。", "万顷蒲萄涨渌醅。", "暮雨暗阳台。", "乱洒高楼湿粉腮。", "一阵东风来卷地，吹回。", "落照江天一半开。"]'),
('song-ci-518','南乡子','苏轼','宋','宋词','song-ci','南乡子','[]','寒雀满疏篱。',66,'宋词/ci.song.1000.json','["寒雀满疏篱。", "争抱寒柯看玉蕤。", "忽见客来花下坐，惊飞。", "蹋散芳英落酒卮。", "痛饮又能诗。", "坐客无毡醉不知。", "花尽酒阑春到也，离离。", "一点微酸已著枝。"]'),
('song-ci-519','南乡子','苏轼','宋','宋词','song-ci','南乡子','[]','不到谢公台。',66,'宋词/ci.song.1000.json','["不到谢公台。", "明月清风好在哉。", "旧日髯孙何处去，重来。", "短李风流更上才。", "秋色渐摧颓。", "满院黄英映酒杯。", "看取桃花春二月，争开。", "尽是刘郎去后栽。"]'),
('song-ci-520','南乡子','苏轼','宋','宋词','song-ci','南乡子','[]','霜降水痕收。',66,'宋词/ci.song.1000.json','["霜降水痕收。", "浅碧鳞鳞露远洲。", "酒力渐消风力软，飕飕。", "破帽多情却恋头。", "佳节若为酬。", "但把清尊断送秋。", "万事到头都是梦，休休。", "明日黄花蝶也愁。"]'),
('song-ci-521','南乡子','苏轼','宋','宋词','song-ci','南乡子','[]','回首乱山横。',66,'宋词/ci.song.1000.json','["回首乱山横。", "不见居人只见城。", "谁似临平山上塔，亭亭。", "迎客西来送客行。", "归路晚风清。", "一枕初寒梦不成。", "今夜残灯斜照处，荧荧。", "秋雨晴时泪不晴。"]'),
('song-ci-522','南乡子','苏轼','宋','宋词','song-ci','南乡子','[]','冰雪透香肌。',66,'宋词/ci.song.1000.json','["冰雪透香肌。", "姑射仙人不似伊。", "濯锦江头新样锦，非宜。", "故著寻常淡薄衣。", "暖日下重帏。", "春睡香凝索起迟。", "曼倩风流缘底事，当时。", "爱被西真唤作儿。"]'),
('song-ci-523','南乡子','苏轼','宋','宋词','song-ci','南乡子','[]','东武望馀杭。',66,'宋词/ci.song.1000.json','["东武望馀杭。", "云海天涯两杳茫。", "何日功成名遂了，还乡。", "醉笑陪公三万场。", "不用诉离觞。", "痛饮从来别有肠。", "今夜送归灯火冷，河塘。", "堕泪羊公却姓杨。"]'),
('song-ci-524','南乡子','苏轼','宋','宋词','song-ci','南乡子','[]','凉簟碧纱厨。',66,'宋词/ci.song.1000.json','["凉簟碧纱厨。", "一枕清风昼睡馀。", "睡听晚衙无一事，徐徐。", "读尽床头几卷书。", "搔首赋归欤。", "自觉功名懒更疏。", "若问使君才与术，何如。", "占得人间一味愚。"]'),
('song-ci-525','南乡子','苏轼','宋','宋词','song-ci','南乡子','[]','裙带石榴红。',66,'宋词/ci.song.1000.json','["裙带石榴红。", "却水殷勤解赠侬。", "应许逐鸡鸡莫怕，相逢。", "一点灵犀必暗通。", "何处遇良工。", "琢刻天真半欲空。", "愿作龙香双凤拨，轻拢。", "长在环儿白雪胸。"]'),
('song-ci-526','南乡子','苏轼','宋','宋词','song-ci','南乡子','[]','旌旆满江湖。',66,'宋词/ci.song.1000.json','["旌旆满江湖。", "诏发楼船万舳舻。", "投笔将军因笑我，迂儒。", "帕首腰刀是丈夫。", "粉泪怨离居。", "喜子垂窗报捷书。", "试问伏波三万语，何如。", "一斛明珠换绿珠。"]'),
('song-ci-527','南乡子','苏轼','宋','宋词','song-ci','南乡子','[]','天与化工知。',66,'宋词/ci.song.1000.json','["天与化工知。", "赐得衣裳总是绯。", "每向华堂深处见，怜伊。", "两个心肠一片儿。", "自小便相随。", "绮席歌筵不暂离。", "苦恨人人分拆破，东西。", "怎得成双似旧时。"]'),
('song-ci-528','南乡子','苏轼','宋','宋词','song-ci','南乡子','[]','寒玉细凝肤。',68,'宋词/ci.song.1000.json','["寒玉细凝肤。", "清歌一曲《倒金壶》。", "冶叶倡条遍相识，争如。", "豆蔻花梢二月初。", "年少即须臾。", "芳时偷得醉工夫。", "罗帐细垂银烛背，欢娱。", "豁得平生俊气无。"]'),
('song-ci-529','南乡子','苏轼','宋','宋词','song-ci','南乡子','[]','怅望送春杯。',66,'宋词/ci.song.1000.json','["怅望送春杯。", "渐老逢春能几回。", "花满楚城愁远别，伤怀。", "何况清丝急管催。", "吟断望乡台。", "万里归心独上来。", "景物登临闲始见，徘徊。", "一寸相思一寸灰。"]'),
('song-ci-530','南乡子','苏轼','宋','宋词','song-ci','南乡子','[]','何处倚阑干。',66,'宋词/ci.song.1000.json','["何处倚阑干。", "弦管高楼月正圆。", "胡蝶梦中家万里，依然。", "老去愁来强自宽。", "明镜借红颜。", "须著人间比梦间。", "蜡烛半笼金翡翠，更阑。", "绣被焚香独自眠。"]'),
('song-ci-531','南歌子','苏轼','宋','宋词','song-ci','南歌子','[]','山与歌眉敛，波同醉眼流。',64,'宋词/ci.song.1000.json','["山与歌眉敛，波同醉眼流。", "游人都上十三楼。", "不羡竹西歌吹、古扬州。", "菰黍连昌歜，琼彝倒玉舟。", "谁家《水调》唱歌头。", "声绕碧山飞去、晚云留。"]'),
('song-ci-532','南歌子','苏轼','宋','宋词','song-ci','南歌子','[]','古岸开青葑，新渠走碧流。',62,'宋词/ci.song.1000.json','["古岸开青葑，新渠走碧流。", "会看光满万家楼。", "记取他年扶路、入西州。", "佳节连梅雨，馀生寄叶舟。", "只将菱角与鸡头。", "更有月明千顷、一时留。"]'),
('song-ci-533','南乡子','苏轼','宋','宋词','song-ci','南乡子','[]','雨暗初疑夜，风回忽报晴。',62,'宋词/ci.song.1000.json','["雨暗初疑夜，风回忽报晴。", "淡云斜照著山明。", "细草软沙溪路、马蹄轻。", "卯酒醒还困，仙材梦不成。", "蓝桥何处觅云英。", "只有多情流水、伴人行。"]'),
('song-ci-534','南歌子','苏轼','宋','宋词','song-ci','南歌子','[]','日出西山雨，无晴又有晴。',62,'宋词/ci.song.1000.json','["日出西山雨，无晴又有晴。", "乱山深处过清明。", "不见彩绳花板、细腰轻。", "尽日行桑野，无人与目成。", "且将新句琢琼英。", "我是世间闲客、此闲行。"]'),
('song-ci-535','南歌子','苏轼','宋','宋词','song-ci','南歌子','[]','带酒冲山雨，和衣睡晚晴。',62,'宋词/ci.song.1000.json','["带酒冲山雨，和衣睡晚晴。", "不知钟鼓报天明。", "梦里栩然蝴蝶、一身轻。", "老去才都尽，归来计未成。", "求田问舍笑豪英。", "自爱湖边沙路、免泥行。"]'),
('song-ci-536','南歌子','苏轼','宋','宋词','song-ci','南歌子','[]','日薄花房绽，风和麦浪轻。',62,'宋词/ci.song.1000.json','["日薄花房绽，风和麦浪轻。", "夜来微雨洗郊坰。", "正是一年春好、近清明。", "已改煎茶火，犹调入粥饧。", "使君高会有馀清。", "此乐无声无味、最难名。"]'),
('song-ci-537','南歌子','苏轼','宋','宋词','song-ci','南歌子','[]','海上乘槎侣，仙人萼绿华。',62,'宋词/ci.song.1000.json','["海上乘槎侣，仙人萼绿华。", "飞升元不用丹砂。", "住在潮头来处、渺天涯。", "雷辊夫差国，云翻海若家。", "坐中安得弄琴牙。", "写取馀声归向、水仙夸。"]'),
('song-ci-538','南歌子','苏轼','宋','宋词','song-ci','南歌子','[]','苒苒中秋过，萧萧两鬓华。',62,'宋词/ci.song.1000.json','["苒苒中秋过，萧萧两鬓华。", "寓身化世一尘沙。", "笑看潮来潮去、了生涯。", "方士三山路，渔人一叶家。", "早知身世两聱牙。", "好伴骑鲸公子、赋雄夸。"]'),
('song-ci-539','南歌子','苏轼','宋','宋词','song-ci','南歌子','[]','师唱谁家曲，宗风嗣阿谁。',62,'宋词/ci.song.1000.json','["师唱谁家曲，宗风嗣阿谁。", "借君拍板与门槌。", "我也逢场作戏、莫相疑。", "溪女方偷眼，山僧莫眨眉。", "却愁弥勒下生迟。", "不见老婆三五、少年时。"]'),
('song-ci-540','南歌子','苏轼','宋','宋词','song-ci','南歌子','[]','欲执河梁手，还升月旦堂。',62,'宋词/ci.song.1000.json','["欲执河梁手，还升月旦堂。", "酒阑人散月侵廊。", "北客明朝归去、雁南翔。", "窈窕高明玉，风流郑季庄。", "一时分散水云乡。", "惟有落花芳草、断人肠。"]'),
('song-ci-541','南歌子','苏轼','宋','宋词','song-ci','南歌子','[]','山雨潇潇过，溪桥浏浏清。',62,'宋词/ci.song.1000.json','["山雨潇潇过，溪桥浏浏清。", "小园幽榭枕苹汀。", "门外月华如水、彩舟横。", "苕岸霜花尽，江湖雪阵平。", "两山遥指海门青。", "回首水云何处、觅孤城。"]'),
('song-ci-542','南歌子','苏轼','宋','宋词','song-ci','南歌子','[]','紫陌寻春去，红尘拂面来。',62,'宋词/ci.song.1000.json','["紫陌寻春去，红尘拂面来。", "无人不道看花回。", "惟见石榴新蕊、一枝开。", "冰簟堆云髻，金尊滟玉醅。", "绿阴青子莫相催。", "留取红巾千点、照池台。"]'),
('song-ci-543','南歌子','苏轼','宋','宋词','song-ci','南歌子','[]','卫霍元勋后，韦平外族贤。',62,'宋词/ci.song.1000.json','["卫霍元勋后，韦平外族贤。", "吹笙只合在缑山。", "闲驾彩峦归去、趁新年。", "烘暖烧香阁，轻寒浴佛天。", "他时一醉画堂前。", "莫忘故人憔悴、老江边。"]'),
('song-ci-544','南歌子','苏轼','宋','宋词','song-ci','南歌子','[]','笑怕蔷薇罥，行忧宝瑟僵。',62,'宋词/ci.song.1000.json','["笑怕蔷薇罥，行忧宝瑟僵。", "美人依约在西厢。", "祗恐暗中迷路、认馀香。", "午夜风翻幔，三更月到床。", "簟纹如水玉肌凉。", "何物与侬归去、有残妆。"]'),
('song-ci-545','南歌子','苏轼','宋','宋词','song-ci','南歌子','[]','寸恨谁云短，绵绵岂易裁。',62,'宋词/ci.song.1000.json','["寸恨谁云短，绵绵岂易裁。", "半年眉绿未曾开。", "明月好风闲处、是人猜。", "春雨消残冻，温风到冷灰。", "尊前一曲为谁哉。", "留取曲终一拍、待君来。"]'),
('song-ci-546','南歌子','苏轼','宋','宋词','song-ci','南歌子','[]','绀绾双蟠髻，云敧小偃巾。',62,'宋词/ci.song.1000.json','["绀绾双蟠髻，云敧小偃巾。", "轻盈红脸小腰身。", "叠鼓忽催花拍、斗精神。", "空阔轻红歇，风和约柳春。", "蓬山才调最清新。", "胜似缠头千锦、共藏珍。"]'),
('song-ci-547','南歌子','苏轼','宋','宋词','song-ci','南歌子','[]','琥珀装腰佩，龙香入领巾。',62,'宋词/ci.song.1000.json','["琥珀装腰佩，龙香入领巾。", "只应飞燕是前身。", "共看剥葱纤手、舞凝神。", "柳絮风前转，梅花雪里春。", "鸳鸯翡翠两争新。", "但得周郎一顾、胜珠珍。"]'),
('song-ci-548','好事近','苏轼','宋','宋词','song-ci','好事近','[]','红粉莫悲啼，俯仰半年离别。',53,'宋词/ci.song.1000.json','["红粉莫悲啼，俯仰半年离别。", "看取雪堂坡下，老农夫凄切。", "明年春水漾桃花，柳岸隘舟楫。", "从此满城歌吹，看黄州阗咽。"]'),
('song-ci-549','好事近','苏轼','宋','宋词','song-ci','好事近','[]','湖上雨晴时，秋水半篙初没。',53,'宋词/ci.song.1000.json','["湖上雨晴时，秋水半篙初没。", "朱槛俯窥寒鉴，照衰颜华发。", "醉中吹堕白纶巾，溪风漾流月。", "独棹小舟归去，任烟波飘兀。"]'),
('song-ci-550','鹊桥仙','苏轼','宋','宋词','song-ci','鹊桥仙','[]','缑山仙子，高情云渺，不学痴牛呆女。',68,'宋词/ci.song.1000.json','["缑山仙子，高情云渺，不学痴牛呆女。", "凤箫声断月明中，举手谢、时人欲去。", "客槎曾犯，银河微浪，尚带天风海雨。", "相逢一醉是前缘，风雨散、飘然何处。"]'),
('song-ci-551','鹊桥仙','苏轼','宋','宋词','song-ci','鹊桥仙','[]','乘槎归去，成都何在，万里江沱汉漾。',68,'宋词/ci.song.1000.json','["乘槎归去，成都何在，万里江沱汉漾。", "与君各赋一篇诗，留织女、鸳鸯机上。", "还将旧曲，重赓新韵，须信吾侪天放。", "人生何处不儿嬉，看乞巧、朱楼彩舫。"]'),
('song-ci-552','望江南・忆江南','苏轼','宋','宋词','song-ci','望江南・忆江南','[]','春已老，春服几时成。',64,'宋词/ci.song.1000.json','["春已老，春服几时成。", "曲水浪低蕉叶稳，舞雩风软纻罗轻。", "酣咏乐升平。", "微雨过，何处不催耕。", "百舌无言桃李尽，柘林深处鹁鸪鸣。", "春色属芜菁。"]'),
('song-ci-553','望江南・忆江南','苏轼','宋','宋词','song-ci','望江南・忆江南','[]','春未老，风细柳斜斜。',64,'宋词/ci.song.1000.json','["春未老，风细柳斜斜。", "试上超然台上看，半壕春水一城花。", "烟雨暗千家。", "寒食后，酒醒却咨嗟。", "休对故人思故国，且将新火试新茶。", "诗酒趁年华。"]'),
('song-ci-554','卜算子','苏轼','宋','宋词','song-ci','卜算子','["\u897f\u6e56"]','蜀客到江南，长忆吴山好。',52,'宋词/ci.song.1000.json','["蜀客到江南，长忆吴山好。", "吴蜀风流自古同，归去应须早。", "还与去年人，共藉西湖草。", "莫惜尊前仔细看，应是容颜老。"]'),
('song-ci-555','卜算子','苏轼','宋','宋词','song-ci','卜算子','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','缺月挂疏桐，漏断人初静。',52,'宋词/ci.song.1000.json','["缺月挂疏桐，漏断人初静。", "时见幽人独往来，缥缈孤鸿影。", "惊起却回头，有恨无人省。", "拣尽寒枝不肯栖，枫落吴江冷。"]'),
('song-ci-556','瑞鹧鸪','苏轼','宋','宋词','song-ci','瑞鹧鸪','[]','碧山影里小红旗。',66,'宋词/ci.song.1000.json','["碧山影里小红旗。", "侬是江南踏浪儿。", "拍手欲嘲山简醉，齐声争唱《浪婆词》。", "西兴渡口帆初落，渔浦山头日未敧。", "侬欲送潮歌底曲，尊前还唱使君诗。"]'),
('song-ci-557','十拍子・破阵子','苏轼','宋','宋词','song-ci','十拍子・破阵子','[]','白酒新开九酝，黄花已过重阳。',72,'宋词/ci.song.1000.json','["白酒新开九酝，黄花已过重阳。", "身外傥来都似梦，醉里无何即是乡。", "东坡日月长。", "玉粉旋烹茶乳，金齑新捣橙香。", "强染霜髭扶翠袖，莫道狂夫不解狂。", "狂夫老更狂。"]'),
('song-ci-558','清平乐','苏轼','宋','宋词','song-ci','清平乐','[]','清淮蜀汴。',54,'宋词/ci.song.1000.json','["清淮蜀汴。", "更在江西岸。", "红旆到时黄叶乱。", "霜入梁王故苑。", "秋原何处携壶。", "停骖访古踟蹰。", "双庙遗风尚在，漆园傲吏应无。"]'),
('song-ci-559','昭君怨','苏轼','宋','宋词','song-ci','昭君怨','[]','谁作桓伊《三弄》。',50,'宋词/ci.song.1000.json','["谁作桓伊《三弄》。", "惊破绿窗幽梦。", "新月与愁烟。", "满江天。", "欲去又还不去。", "明日落花飞絮。", "飞絮送行舟。", "水东流。"]'),
('song-ci-560','戚氏','苏轼','宋','宋词','song-ci','戚氏','[]','玉龟山。',228,'宋词/ci.song.1000.json','["玉龟山。", "东皇灵媲统群仙。", "绛阙岧嶢，翠房深迥，倚霏烟。", "幽闲。", "志萧然。", "金城千里锁婵娟。", "当时穆满巡狩。", "翠华曾到海西边。", "风露明霁，鲸波极目，势浮舆盖方圆。", "正迢迢丽日。", "玄圃清寂，琼草芊绵。", "争解绣勒香鞯。", "鸾辂驻跸，八马戏芝田。", "瑶池近、画楼隐隐，翠鸟翩翩。", "肆华筵。", "间作脆管鸣弦。", "宛若帝所钧天。", "稚颜皓齿，绿发方瞳，圆极恬淡高妍。", "尽倒琼壶酒，献金鼎药，固大椿年。", "缥缈飞琼妙舞，命双成、奏曲醉留连。", "云璈韵响泻寒泉。", "浩歌畅饮，斜月低河汉。", "渐渐绮霞、天际红深浅。", "动归思、回首尘寰。"]'),
('song-ci-561','醉蓬莱','苏轼','宋','宋词','song-ci','醉蓬莱','[]','笑劳生一梦，羁旅三年，又还重九。',119,'宋词/ci.song.1000.json','["笑劳生一梦，羁旅三年，又还重九。", "华发萧萧，对荒园搔首。", "赖有多情，好饮无事，似古人贤守。", "岁岁登高，年年落帽，物华依旧。", "此会应须烂醉，仍把紫菊茱萸，细看重嗅。", "摇落霜风，有手栽双柳。", "来岁今朝，为我西顾，酹羽觞江口。", "会与州人，饮公遗爱，一江醇酎。"]'),
('song-ci-562','贺新郎','苏轼','宋','宋词','song-ci','贺新郎','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','乳燕飞华屋。',140,'宋词/ci.song.1000.json','["乳燕飞华屋。", "悄无人、桐阴转午，晚凉新浴。", "手弄生绡白团扇，扇手一时似玉。", "渐困倚、孤眠清熟。", "帘外谁来推绣户，枉教人、梦断瑶台曲。", "又却是，风敲竹。", "石榴半吐红巾蹙。", "待浮花、浪蕊都尽，伴君幽独。", "秾艳一枝细看取，芳心千重似束。", "又恐被、秋风惊绿。", "若待得君来向此，花前对酒不忍触。", "共粉泪，两蔌蔌。"]'),
('song-ci-563','洞仙歌','苏轼','宋','宋词','song-ci','洞仙歌','[]','江南腊尽，早梅花开后。',103,'宋词/ci.song.1000.json','["江南腊尽，早梅花开后。", "分付新春与垂柳。", "细腰肢、自有入格风流，仍更是、骨体清英雅秀。", "永丰坊那畔，尽日无人，惟见金丝弄晴昼。", "断肠是，飞絮时，绿叶成阴，无个事、一成消瘦。", "又莫是、东风逐君来，便吹散眉间，一点春皱。"]'),
('song-ci-564','洞仙歌','苏轼','宋','宋词','song-ci','洞仙歌','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','冰肌玉骨，自清凉无汗。',101,'宋词/ci.song.1000.json','["冰肌玉骨，自清凉无汗。", "水殿风来暗香满。", "绣帘开、一点明月窥人，人未寝、敧枕钗横鬓乱。", "起来携素手，庭户无声，时见疏星渡河汉。", "试问夜如何，夜已三更，金波淡、玉绳低转。", "但屈指、西风几时来，又不道、流年暗中偷换。"]'),
('song-ci-565','八声甘州','苏轼','宋','宋词','song-ci','八声甘州','["\u94b1\u5858\u6c5f", "\u897f\u6e56"]','有情风、万里卷潮来，无情送潮归。',119,'宋词/ci.song.1000.json','["有情风、万里卷潮来，无情送潮归。", "问钱塘江上，西兴浦口，几度斜晖。", "不用思量今古，俯仰昔人非。", "谁似东坡老，白首忘机。", "记取西湖西畔，正暮山好处，空翠烟霏。", "算诗人相得，如我与君稀。", "约他年、东还海道，愿谢公、雅志莫相违。", "西州路，不应回首，为我沾衣。"]'),
('song-ci-566','三部乐','苏轼','宋','宋词','song-ci','三部乐','[]','美人如月。',120,'宋词/ci.song.1000.json','["美人如月。", "乍见掩暮云，更增妍绝。", "算应无恨，安用阴晴圆缺。", "娇甚空只成愁，待下床又懒，未语先咽。", "数日不来，落尽一庭红叶。", "今朝置酒强起，问为谁减动，一分香雪。", "何事散花却病，维摩无疾。", "却低眉、惨然不答。", "唱金缕、一声怨切。", "堪折便折。", "且惜取、少年花发。"]'),
('song-ci-567','阮郎归','苏轼','宋','宋词','song-ci','阮郎归','[]','绿槐高柳咽新蝉。',56,'宋词/ci.song.1000.json','["绿槐高柳咽新蝉。", "薰风初入弦。", "碧纱窗下水沈烟。", "棋声惊昼眠。", "微雨过，小荷翻。", "榴花开欲然。", "玉盆纤手弄清泉。", "琼珠碎却圆。"]'),
('song-ci-568','阮郎归','苏轼','宋','宋词','song-ci','阮郎归','[]','暗香浮动月黄昏。',56,'宋词/ci.song.1000.json','["暗香浮动月黄昏。", "堂前一树春。", "东风何事入西邻。", "儿家常闭门。", "雪肌冷，玉容真。", "香腮粉未匀。", "折花欲寄岭头人。", "江南日暮云。"]'),
('song-ci-569','阮郎归','苏轼','宋','宋词','song-ci','阮郎归','[]','一年三度过苏台。',56,'宋词/ci.song.1000.json','["一年三度过苏台。", "清尊长是开。", "佳人相问苦相猜。", "这回来不来。", "情未尽，老先催。", "人生真可咍，他年桃李阿谁栽。", "刘郎双鬓衰。"]'),
('song-ci-570','江神子・江城子','苏轼','宋','宋词','song-ci','江神子・江城子','[]','梦中了了醉中醒。',86,'宋词/ci.song.1000.json','["梦中了了醉中醒。", "只渊明。", "是前生。", "走遍人间，依旧却躬耕。", "昨夜东坡春雨足，乌鹊喜，报新晴。", "雪堂西畔暗泉鸣。", "北山倾。", "小溪横。", "南望亭丘，孤秀耸曾城。", "都是斜川当日境，吾老矣，寄馀龄。"]'),
('song-ci-571','江神子・江城子','苏轼','宋','宋词','song-ci','江神子・江城子','[]','翠蛾羞黛怯人看。',86,'宋词/ci.song.1000.json','["翠蛾羞黛怯人看。", "掩霜纨。", "泪偷弹。", "且尽一尊，收泪唱阳关。", "漫道帝城天样远，天易见，见君难。", "画堂新拘近孤山。", "曲阑干。", "为谁安。", "飞絮落花，春色属明年。", "欲棹小舟寻旧事，无处问，水连天。"]'),
('song-ci-572','江神子・江城子','苏轼','宋','宋词','song-ci','江神子・江城子','[]','凤凰山下雨初晴。',86,'宋词/ci.song.1000.json','["凤凰山下雨初晴。", "水风清。", "晚霞明。", "一朵芙蕖，开过尚盈盈。", "何处飞来双白鹭，如有意，慕娉婷。", "忽闻江上弄哀筝。", "苦含情，遣谁听。", "烟敛云收，依约是湘灵。", "欲待曲终寻问取，人不见，数峰青。"]'),
('song-ci-573','江神子・江城子','苏轼','宋','宋词','song-ci','江神子・江城子','[]','老夫聊发少年狂。',86,'宋词/ci.song.1000.json','["老夫聊发少年狂。", "左牵黄。", "右擎苍。", "锦帽貂裘，千骑卷平冈。", "为报倾城随太守，亲射虎，看孙郎。", "酒酣胸胆尚开张。", "鬓微霜。", "又何妨。", "持节云中，何日遣冯唐。", "会挽雕弓如满月，西北望，射天狼。"]'),
('song-ci-574','江神子・江城子','苏轼','宋','宋词','song-ci','江神子・江城子','[]','天涯流落思无穷。',86,'宋词/ci.song.1000.json','["天涯流落思无穷。", "既相逢。", "却匆匆。", "携手佳人，和泪折残红。", "为问东风馀几许，春纵在，与谁同。", "隋堤三月水溶溶。", "背归鸿。", "去吴中。", "回首彭城，清泗与淮通。", "寄我相思千点泪，流不到，楚江东。"]'),
('song-ci-575','江神子・江城子','苏轼','宋','宋词','song-ci','江神子・江城子','[]','相逢不觉又初寒。',86,'宋词/ci.song.1000.json','["相逢不觉又初寒。", "对尊前。", "惜流年。", "风紧离亭，冰结泪珠圆。", "雪意留君君不住，从此去，少清欢。", "转头山下转头看。", "路漫漫。", "玉花翻。", "银海光宽，何处是超然。", "知道故人相念否，携翠袖，倚朱阑。"]'),
('song-ci-576','江神子・江城子','苏轼','宋','宋词','song-ci','江神子・江城子','[]','黄昏犹是雨纤纤。',86,'宋词/ci.song.1000.json','["黄昏犹是雨纤纤。", "晓开帘。", "欲平檐。", "江阔天低，无处认青帘。", "孤坐冻吟谁伴我，揩病目，拈衰髯。", "使君留客醉厌厌。", "水晶盐。", "为谁甜。", "手把梅花，东望忆陶潜。", "雪似故人人似雪，虽可爱，有人嫌。"]'),
('song-ci-577','江神子・江城子','苏轼','宋','宋词','song-ci','江神子・江城子','[]','玉人家在凤凰山。',86,'宋词/ci.song.1000.json','["玉人家在凤凰山。", "水云间。", "掩门关。", "门外行人，立马看弓弯。", "十里春风谁指似，斜日映，绣帘斑。", "多情好事与君还。", "闵新鳏。", "拭馀潸。", "明月空江，香雾著云鬟。", "陌上花开春尽也，闻旧曲，破朱颜。"]'),
('song-ci-578','江神子・江城子','苏轼','宋','宋词','song-ci','江神子・江城子','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','十年生死两茫茫。',86,'宋词/ci.song.1000.json','["十年生死两茫茫。", "不思量。", "自难忘。", "千里孤坟，无处话凄凉。", "纵使相逢应不识，尘满面，鬓如霜。", "夜来幽梦忽还乡。", "小轩窗。", "正梳妆。", "相顾无言，惟有泪千行。", "料得年年断肠处，明月夜，短松冈。"]'),
('song-ci-579','蝶恋花','苏轼','宋','宋词','song-ci','蝶恋花','[]','花褪残红青杏小。',70,'宋词/ci.song.1000.json','["花褪残红青杏小。", "燕子飞时，绿水人家绕。", "枝上柳绵吹又少。", "天涯何处无芳草。", "墙里秋千墙外道。", "墙外行人，墙里佳人笑。", "笑渐不闻声渐悄。", "多情却被无情恼。"]'),
('song-ci-580','蝶恋花','苏轼','宋','宋词','song-ci','蝶恋花','[]','一颗樱桃樊素口。',70,'宋词/ci.song.1000.json','["一颗樱桃樊素口。", "不爱黄金，只爱人长久。", "学画鸦儿犹未就。", "眉间已作伤春皱。", "扑蝶西园随伴走。", "花落花开，渐解相思瘦。", "破镜重圆人在否。", "章台折尽青青柳。"]'),
('song-ci-581','蝶恋花','苏轼','宋','宋词','song-ci','蝶恋花','[]','雨后春容清更丽。',70,'宋词/ci.song.1000.json','["雨后春容清更丽。", "只有离人，幽恨终难洗。", "北固山前三面水。", "碧琼梳拥青螺髻。", "一纸乡书来万里。", "问我何年，真个成归计。", "白首送春拼一醉。", "东风吹破千行泪。"]'),
('song-ci-582','蝶恋花','苏轼','宋','宋词','song-ci','蝶恋花','[]','簌簌无风花自亸。',70,'宋词/ci.song.1000.json','["簌簌无风花自亸。", "寂寞园林，柳老樱桃过。", "落日多情还照坐。", "山青一点横云破。", "路尽河回千转柁。", "系缆渔村，月暗孤灯火。", "凭仗飞魂招楚些。", "我思君处君思我。"]'),
('song-ci-583','蝶恋花','苏轼','宋','宋词','song-ci','蝶恋花','[]','灯火钱塘三五夜。',70,'宋词/ci.song.1000.json','["灯火钱塘三五夜。", "明月如霜，照见人如画。", "帐底吹笙香吐麝。", "此般风味应无价。", "寂寞山城人老也。", "击鼓吹箫，乍入农桑社。", "火冷灯稀霜露下。", "昏昏雪意云垂野。"]'),
('song-ci-584','蝶恋花','苏轼','宋','宋词','song-ci','蝶恋花','[]','帘外东风交雨霰。',72,'宋词/ci.song.1000.json','["帘外东风交雨霰。", "帘里佳人，笑语如莺燕。", "深惜今年正月暖。", "灯光酒色摇金盏。", "掺鼓《渔阳》挝未遍。", "舞褪琼钗，汗湿香罗软。", "今夜何人吟古怨。", "清诗未就冰生砚。"]'),
('song-ci-585','蝶恋花','苏轼','宋','宋词','song-ci','蝶恋花','[]','自古涟漪佳绝地。',70,'宋词/ci.song.1000.json','["自古涟漪佳绝地。", "绕郭荷花，欲把吴兴比。", "倦客尘埃何处洗。", "真君堂下寒泉水。", "左海门前酤酒市。", "夜半潮来，月下孤舟起。", "倾盖相逢拼一醉。", "双凫飞去人千里。"]'),
('song-ci-586','蝶恋花','苏轼','宋','宋词','song-ci','蝶恋花','[]','云水萦回溪上路。',70,'宋词/ci.song.1000.json','["云水萦回溪上路。", "叠叠青山，环绕溪东注。", "月白沙汀翘宿鹭。", "更无一点尘来处。", "溪叟相看私自语。", "底事区区，苦要为官去。", "尊酒不空田百亩。", "归来分得闲中趣。"]'),
('song-ci-587','采桑子','苏轼','宋','宋词','song-ci','采桑子','[]','多情多感仍多病，多景楼中。',52,'宋词/ci.song.1000.json','["多情多感仍多病，多景楼中。", "尊酒相逢。", "乐事回头一笑空。", "停杯且听琵琶语，细拈轻拢。", "醉脸春融。", "斜照江天一抹红。"]'),
('song-ci-588','千秋岁','苏轼','宋','宋词','song-ci','千秋岁','[]','浅霜侵绿。',87,'宋词/ci.song.1000.json','["浅霜侵绿。", "发少仍新沐。", "冠直缝，巾横幅。", "美人怜我老，玉手簪黄菊。", "秋露重，真珠落袖沾馀馥。", "坐上人如玉。", "花映花奴肉。", "蜂蝶乱，飞相逐。", "明年人纵健，此会应难复。", "须细看，晚来月上和银烛。"]'),
('song-ci-589','苏幕遮','苏轼','宋','宋词','song-ci','苏幕遮','[]','暑笼晴，风解愠。',76,'宋词/ci.song.1000.json','["暑笼晴，风解愠。", "雨后馀清，暗袭衣裾润。", "一局选仙逃暑困。", "笑指尊前、谁向青霄近。", "整金盆，轮玉笋。", "凤驾鸾车，谁敢争先进。", "重五休言升最紧。", "纵有碧油，到了输堂印。"]'),
('song-ci-590','永遇乐','苏轼','宋','宋词','song-ci','永遇乐','[]','长忆别时，景疏楼上，明月如水。',128,'宋词/ci.song.1000.json','["长忆别时，景疏楼上，明月如水。", "美酒清歌，留连不住，月随人千里。", "别来三度，孤光又满，冷落共谁同醉。", "卷珠帘，凄然顾影，共伊到明无寐。", "今朝有客，来从淮上，能道使君深意。", "凭仗清淮，分明到海，中有相思泪。", "而今何在，西垣清禁，夜永露华侵被。", "此时看，回廊晓月，也应暗记。"]'),
('song-ci-591','永遇乐','苏轼','宋','宋词','song-ci','永遇乐','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','明月如霜，好风如水，清景无限。',128,'宋词/ci.song.1000.json','["明月如霜，好风如水，清景无限。", "曲港跳鱼，圆荷泻露，寂寞无人见。", "紞如三鼓，铿然一叶，黯黯梦云惊断。", "夜茫茫，重寻无处，觉来小园行遍。", "天涯倦客，山中归路，望断故园心眼。", "燕子楼空，佳人何在，空锁楼中燕。", "古今如梦，何曾梦觉，但有旧欢新怨。", "异时对，黄楼夜景，为余浩叹。"]'),
('song-ci-592','行香子','苏轼','宋','宋词','song-ci','行香子','[]','绮席才终。',84,'宋词/ci.song.1000.json','["绮席才终。", "欢意犹浓。", "酒阑时、高兴无穷。", "共夸君赐，初拆臣封。", "看分香饼，黄金缕，密云龙。", "斗赢一水，功敌千锺。", "觉凉生、两腋清风。", "暂留红袖，少却纱笼。", "放笙歌散，庭馆静，略从容。"]'),
('song-ci-593','行香子','苏轼','宋','宋词','song-ci','行香子','[]','三入承明。',84,'宋词/ci.song.1000.json','["三入承明。", "四至九卿。", "问书生、何辱何荣。", "金张七叶，纨绮貂缨。", "无汗马事，不献赋，不明经。", "成都卜肆，寂莫君平。", "郑子真、岩谷躬耕。", "寒灰炙手，人重人轻。", "除竺乾学，得无念，得无名。"]'),
('song-ci-594','行香子','苏轼','宋','宋词','song-ci','行香子','[]','清夜无尘。',84,'宋词/ci.song.1000.json','["清夜无尘。", "月色如银。", "酒斟时、须满十分。", "浮名浮利，虚苦劳神。", "叹隙中驹，石中火，梦中身。", "虽抱文章，开口谁亲。", "且陶陶、乐尽天真。", "几时归去，作个闲人。", "对一张琴，一壶酒，一溪云。"]'),
('song-ci-595','行香子','苏轼','宋','宋词','song-ci','行香子','[]','昨夜霜风。',84,'宋词/ci.song.1000.json','["昨夜霜风。", "先入梧桐。", "浑无处、回避衰容。", "问公何事，不语书空。", "但一回醉，一回病，一回慵。", "朝来庭下，光阴如箭，似无言、有意伤侬。", "都将万事，付与千锺。", "任酒花白，眼花乱，烛花红。"]'),
('song-ci-596','行香子','苏轼','宋','宋词','song-ci','行香子','[]','携手江村。',84,'宋词/ci.song.1000.json','["携手江村。", "梅雪飘裙。", "情何限、处处消魂。", "故人不见，旧曲重闻。", "向望湖楼，孤山寺，涌金门。", "寻常行处，题诗千首，绣罗衫、与拂红尘。", "别来相忆，知是何人。", "有湖中月，江边柳，陇头云。"]'),
('song-ci-597','行香子','苏轼','宋','宋词','song-ci','行香子','[]','一叶轻舟。',84,'宋词/ci.song.1000.json','["一叶轻舟。", "双桨鸿惊。", "水天清、影湛波平。", "鱼翻藻鉴，鹭点烟汀。", "过沙溪急，霜溪冷，月溪明。", "重重似画，曲曲如屏。", "算当年、虚老岩陵。", "君臣一梦，今古虚名。", "但远山长，云山乱，晓山清。"]'),
('song-ci-598','菩萨蛮','苏轼','宋','宋词','song-ci','菩萨蛮','[]','绣帘高卷倾城出。',52,'宋词/ci.song.1000.json','["绣帘高卷倾城出。", "灯前潋滟横波溢。", "皓齿发清歌。", "春愁入翠蛾。", "凄音休怨乱。", "我已先肠断。", "遗响下清虚。", "累累一串珠。"]'),
('song-ci-599','菩萨蛮','苏轼','宋','宋词','song-ci','菩萨蛮','[]','碧纱微露纤纤玉。',52,'宋词/ci.song.1000.json','["碧纱微露纤纤玉。", "朱唇渐暖参差竹。", "越调变新声。", "龙吟彻骨清。", "夜来残酒醒。", "惟觉霜袍冷。", "不见敛眉人。", "胭脂觅旧痕。"]'),
('song-ci-600','菩萨蛮','苏轼','宋','宋词','song-ci','菩萨蛮','[]','秋风湖上萧萧雨。',52,'宋词/ci.song.1000.json','["秋风湖上萧萧雨。", "使君欲去还留住。", "今日漫留君。", "明朝愁杀人。", "佳人千点泪。", "洒向长河水。", "不用敛双蛾。", "路人啼更多。"]'),
('song-ci-601','菩萨蛮','苏轼','宋','宋词','song-ci','菩萨蛮','[]','玉童西迓浮丘伯。',52,'宋词/ci.song.1000.json','["玉童西迓浮丘伯。", "洞天冷落秋萧瑟。", "不用许飞琼。", "瑶台空月明。", "清香凝夜宴。", "借与韦郎看。", "莫便向姑苏。", "扁舟下五湖。"]'),
('song-ci-602','菩萨蛮','苏轼','宋','宋词','song-ci','菩萨蛮','[]','天怜豪俊腰金晚。',52,'宋词/ci.song.1000.json','["天怜豪俊腰金晚。", "故教月向松江满。", "清景为淹留。", "从君都占秋。", "身闲惟有酒。", "拭问清游首。", "帝梦已遥思。", "匆匆归去时。"]'),
('song-ci-603','菩萨蛮','苏轼','宋','宋词','song-ci','菩萨蛮','[]','娟娟缺月西南落。',54,'宋词/ci.song.1000.json','["娟娟缺月西南落。", "相思拨断琵琶索。", "枕泪梦魂中。", "觉来眉晕重。", "华堂堆烛泪。", "长笛吹《新水》。", "醉客各西东。", "应思陈孟公。"]'),
('song-ci-604','菩萨蛮','苏轼','宋','宋词','song-ci','菩萨蛮','[]','玉笙不受朱唇暖。',52,'宋词/ci.song.1000.json','["玉笙不受朱唇暖。", "离声凄咽胸填满。", "遗痕几千秋。", "恩留人不留。", "他年京国酒。", "泫泪攀枯柳。", "莫唱短因缘。", "长安远似天。"]'),
('song-ci-605','菩萨蛮','苏轼','宋','宋词','song-ci','菩萨蛮','[]','画檐初挂弯弯月。',52,'宋词/ci.song.1000.json','["画檐初挂弯弯月。", "孤光未满先忧缺。", "遥认玉帘钩。", "天孙梳洗楼。", "佳人言语好。", "不顾求新巧。", "此恨固应知。", "愿人无别离。"]'),
('song-ci-606','菩萨蛮','苏轼','宋','宋词','song-ci','菩萨蛮','[]','风回仙驭云开扇。',52,'宋词/ci.song.1000.json','["风回仙驭云开扇。", "更阑月堕星河转。", "枕上梦魂惊。", "晓檐疏雨零。", "相逢虽草草。", "长共天难老。", "终不羡人间。", "人间日似年。"]'),
('song-ci-607','菩萨蛮','苏轼','宋','宋词','song-ci','菩萨蛮','[]','城隅静女谁人见。',52,'宋词/ci.song.1000.json','["城隅静女谁人见。", "先生日夜歌彤管。", "谁识蔡姬贤。", "江南顾彦先。", "先生那久困。", "汤沐须名郡。", "惟有谢夫人。", "从来见拟伦。"]'),
('song-ci-608','菩萨蛮','苏轼','宋','宋词','song-ci','菩萨蛮','[]','买田阳羡吾将老。',52,'宋词/ci.song.1000.json','["买田阳羡吾将老。", "从来只为溪山好。", "来往一虚舟。", "聊随物外游。", "有书仍懒著。", "水调歌归去。", "筋力不辞诗。", "要须风雨时。"]'),
('song-ci-609','菩萨蛮','苏轼','宋','宋词','song-ci','菩萨蛮','[]','落花闲院春衫薄。',52,'宋词/ci.song.1000.json','["落花闲院春衫薄。", "薄衫春院闲花落。", "迟日恨依依。", "依依恨日迟。", "梦回莺舌弄。", "弄舌莺回梦。", "邮便问人羞。", "羞人问便邮。"]'),
('song-ci-610','菩萨蛮','苏轼','宋','宋词','song-ci','菩萨蛮','[]','火云凝汗挥珠颗。',52,'宋词/ci.song.1000.json','["火云凝汗挥珠颗。", "颗珠挥汗凝云火。", "琼暖碧纱轻。", "轻纱碧暖琼。", "晕腮嫌枕印。", "印枕嫌腮晕。", "闲照晚妆残。", "残妆晚照闲。"]'),
('song-ci-611','菩萨蛮','苏轼','宋','宋词','song-ci','菩萨蛮','[]','峤南江浅红梅小。',52,'宋词/ci.song.1000.json','["峤南江浅红梅小。", "小梅红浅江南峤。", "窥我向疏篱。", "篱疏向我窥。", "老人行即到。", "到即行人老。", "离别惜残枝。", "枝残惜别离。"]'),
('song-ci-612','菩萨蛮','苏轼','宋','宋词','song-ci','菩萨蛮','[]','翠鬟斜幔云垂耳。',52,'宋词/ci.song.1000.json','["翠鬟斜幔云垂耳。", "耳垂云幔斜鬟翠。", "春晚睡昏昏。", "昏昏睡晚春。", "细花梨雪坠。", "坠雪梨花细。", "颦浅念谁人。", "人谁念浅颦。"]'),
('song-ci-613','菩萨蛮','苏轼','宋','宋词','song-ci','菩萨蛮','[]','柳庭风静人眠昼。',52,'宋词/ci.song.1000.json','["柳庭风静人眠昼。", "昼眠人静风庭柳。", "香汗薄衫凉。", "凉衫薄汗香。", "手红冰碗藕。", "藕碗冰红手。", "郎笑藕丝长。", "长丝藕笑郎。"]'),
('song-ci-614','菩萨蛮','苏轼','宋','宋词','song-ci','菩萨蛮','[]','井桐双照新妆冷。',52,'宋词/ci.song.1000.json','["井桐双照新妆冷。", "冷妆新照双桐井。", "羞对井花愁。", "愁花井对羞。", "影孤怜夜永。", "永夜怜孤影。", "楼上不宜秋。", "秋宜不上楼。"]'),
('song-ci-615','菩萨蛮','苏轼','宋','宋词','song-ci','菩萨蛮','[]','雪花飞暖融香颊。',52,'宋词/ci.song.1000.json','["雪花飞暖融香颊。", "颊香融暖飞花雪。", "欺雪任单衣。", "衣单任雪欺。", "别时梅子结。", "结子梅时别。", "归不恨开迟。", "迟开恨不归。"]'),
('song-ci-616','生查子','苏轼','宋','宋词','song-ci','生查子','[]','三度别君来，此别真迟暮。',48,'宋词/ci.song.1000.json','["三度别君来，此别真迟暮。", "白尽老髭须，明日淮南去。", "酒罢月随人，泪湿花如雾。", "后月逐君还，梦绕湖边路。"]'),
('song-ci-617','翻香令','苏轼','宋','宋词','song-ci','翻香令','[]','金炉犹暖麝煤残。',68,'宋词/ci.song.1000.json','["金炉犹暖麝煤残。", "惜香更把宝钗翻。", "重闻处，馀薰在，这一番、气味胜从前。", "背人偷盖小蓬山。", "更将沈水暗同然。", "且图得，氤氲久，为情深、嫌怕断头烟。"]'),
('song-ci-618','乌夜啼','苏轼','宋','宋词','song-ci','乌夜啼','["\u897f\u6e56"]','莫怪归心甚速，西湖自有蛾眉。',56,'宋词/ci.song.1000.json','["莫怪归心甚速，西湖自有蛾眉。", "若见故人须细说，白发倍当时。", "小郑非常强记，二南依旧能诗。", "更有鲈鱼堪切脍，儿辈莫教知。"]'),
('song-ci-619','虞美人','苏轼','宋','宋词','song-ci','虞美人','[]','定场贺老今何在。',66,'宋词/ci.song.1000.json','["定场贺老今何在。", "几度新声改。", "怨声坐使旧声阑。", "俗耳只知繁手、不须弹。", "断弦拭问谁能晓。", "七岁文姬小。", "拭教弹作辊雷声。", "应有开元遗老、泪纵横。"]'),
('song-ci-620','虞美人','苏轼','宋','宋词','song-ci','虞美人','[]','归心正似三春草。',66,'宋词/ci.song.1000.json','["归心正似三春草。", "拭著莱衣小。", "橘怀几日向翁开。", "怀祖已瞋文度、不归来。", "禅心已断人间爱。", "只有平交在。", "笑论瓜葛一枰同。", "看取灵光新赋、有家风。"]'),
('song-ci-621','虞美人','苏轼','宋','宋词','song-ci','虞美人','[]','湖山信是东南美。',66,'宋词/ci.song.1000.json','["湖山信是东南美。", "一望弥千里。", "使君能得几回来。", "便使尊前醉倒、且徘徊。", "沙河塘里灯初上。", "水调谁家唱。", "夜阑风静欲归时。", "惟有一江明月、碧琉璃。"]'),
('song-ci-622','虞美人','苏轼','宋','宋词','song-ci','虞美人','[]','波声拍枕长淮晓。',66,'宋词/ci.song.1000.json','["波声拍枕长淮晓。", "隙月窥人小。", "无情汴水自东流。", "只载一船离恨、向西州。", "竹溪花浦曾同醉。", "酒味多於泪。", "谁教风鉴在尘埃。", "酝造一场烦恼、送人来。"]'),
('song-ci-623','河满子','苏轼','宋','宋词','song-ci','河满子','[]','见说岷峨凄怆，旋闻江汉澄清。',86,'宋词/ci.song.1000.json','["见说岷峨凄怆，旋闻江汉澄清。", "但觉秋来归梦好，西南自有长城。", "东府三人最少，西山八国初平。", "莫负花溪纵赏，何妨药市微行。", "拭问当垆人在否，空教是处闻名。", "唱著子渊新曲，应须分外含情。"]'),
('song-ci-624','哨遍','苏轼','宋','宋词','song-ci','哨遍','[]','为米折腰，因酒弃家，口体交相累。',242,'宋词/ci.song.1000.json','["为米折腰，因酒弃家，口体交相累。", "归去来，谁不遣君归。", "觉从前皆非今是。", "露未晞。", "征夫指予归路，门前笑语喧童稚。", "嗟旧菊都荒，新松暗老，吾年今已如此。", "但小窗容膝闭柴扉。", "策杖看孤云暮鸿飞。", "云出无心，鸟倦知还，本非有意。", "噫。", "归去来兮。", "我今忘我兼忘世。", "亲戚无浪语，琴书中有真味。", "步翠麓崎岖，泛溪窈窕，涓涓暗谷流春水。", "观草木欣荣，幽人自感，吾生行且休矣。", "念寓形宇内复几时。", "不自觉皇皇欲何之。", "委吾心、去留谁计。", "神仙知在何处，富贵非吾志。", "但知临水登山啸咏，自引壶觞自醉。", "此生天命更何疑。", "且乘流、遇坎还止。"]'),
('song-ci-625','哨遍','苏轼','宋','宋词','song-ci','哨遍','[]','睡起画堂，银蒜押帘，珠幕云垂地。',241,'宋词/ci.song.1000.json','["睡起画堂，银蒜押帘，珠幕云垂地。", "初雨歇，洗出碧罗天，正溶溶养花天气。", "一霎暖风回芳草，荣光浮动，掩皱银塘水。", "方杏靥匀酥，花鬚吐绣，园林排比红翠。", "见乳燕捎蝶过繁枝。", "忽一线炉香逐游丝。", "昼永人闲，独立斜阳，晚来情味。", "便乘兴携将佳丽。", "深入芳菲里。", "拨胡琴语，轻拢慢捻总伶俐。", "看紧约罗裙，急趣檀板，霓裳入破惊鸿起。", "颦月临眉，醉霞横脸，歌声悠扬云际。", "任满头红雨落花飞。", "渐鳷鹊楼西玉蟾低。", "尚徘徊、未尽欢意。", "君看今古悠悠，浮宦人间世。", "这些百岁，光阴几日，三万六千而已。", "醉乡路稳不妨行，但人生、要适情耳。"]'),
('song-ci-626','点绛唇','苏轼','宋','宋词','song-ci','点绛唇','[]','我辈情锺，古来谁似龙山宴。',50,'宋词/ci.song.1000.json','["我辈情锺，古来谁似龙山宴。", "而今楚甸。", "戏马馀飞观。", "顾谓佳人，不觉秋强半。", "筝声远。", "鬓云吹乱。", "愁入参差雁。"]'),
('song-ci-627','点绛唇','苏轼','宋','宋词','song-ci','点绛唇','[]','不用悲秋，今年身健还高宴。',50,'宋词/ci.song.1000.json','["不用悲秋，今年身健还高宴。", "江村海甸。", "总作空花观。", "尚想横汾，兰菊纷相半。", "楼船远。", "白云飞乱。", "空有年年雁。"]'),
('song-ci-628','点绛唇','苏轼','宋','宋词','song-ci','点绛唇','[]','莫唱阳关，风流公子方终宴。',50,'宋词/ci.song.1000.json','["莫唱阳关，风流公子方终宴。", "秦山禹甸。", "缥缈真奇观。", "北望平原，落日山衔半。", "孤帆远。", "我歌君乱。", "一送西飞雁。"]'),
('song-ci-629','点绛唇','苏轼','宋','宋词','song-ci','点绛唇','[]','醉漾轻舟，信流引到花深处。',50,'宋词/ci.song.1000.json','["醉漾轻舟，信流引到花深处。", "尘缘相误。", "无计花间住。", "烟水茫茫，千里斜阳暮。", "山无数。", "乱红如雨。", "不记来时路。"]'),
('song-ci-630','点绛唇','苏轼','宋','宋词','song-ci','点绛唇','[]','月转乌啼，画堂宫徵生离恨。',50,'宋词/ci.song.1000.json','["月转乌啼，画堂宫徵生离恨。", "美人愁闷。", "不管罗衣褪。", "清泪斑斑，挥断柔肠寸。", "嗔人问。", "背灯偷搵。", "拭尽残妆粉。"]'),
('song-ci-631','人娇','苏轼','宋','宋词','song-ci','人娇','[]','满院桃花，尽是刘郎未见。',84,'宋词/ci.song.1000.json','["满院桃花，尽是刘郎未见。", "於中更、一枝纤软。", "仙家日月，笑人间春晚。", "浓睡起，惊飞乱红千片。", "密意难传，羞容易变。", "平白地、为伊肠断。", "问君终日，怎安排心眼。", "须信道，司空自来见惯。"]'),
('song-ci-632','人娇','苏轼','宋','宋词','song-ci','人娇','[]','白发苍颜，正是维摩境界。',85,'宋词/ci.song.1000.json','["白发苍颜，正是维摩境界。", "空方丈、散花何碍。", "朱唇箸点，更髻鬟生彩。", "这些个，千生万生只在。", "好事心肠，著人情态。", "闲窗下、敛云凝黛。", "明朝端午，待学纫兰为佩。", "寻一首好诗，要书裙带。"]'),
('song-ci-633','人娇','苏轼','宋','宋词','song-ci','人娇','[]','别驾来时，灯火荧煌无数。',84,'宋词/ci.song.1000.json','["别驾来时，灯火荧煌无数。", "向青琐、隙中偷覰。", "元来便是，共采鸾仙侣。", "方见了，管须低声说与。", "百子流苏，千枝宝炬。", "人间有、洞房烟雾。", "春来何事，故抛人别处。", "坐望断，楼中远山归路。"]'),
('song-ci-634','诉衷情','苏轼','宋','宋词','song-ci','诉衷情','[]','钱塘风景古来奇。',54,'宋词/ci.song.1000.json','["钱塘风景古来奇。", "太守例能诗。", "先驱负弩何在，心已誓江西。", "花尽后，叶飞时。", "雨凄凄。", "若为情绪，更问新官，向旧官啼。"]'),
('song-ci-635','诉衷情','苏轼','宋','宋词','song-ci','诉衷情','[]','海棠珠缀一重重。',54,'宋词/ci.song.1000.json','["海棠珠缀一重重。", "清晓近帘栊。", "胭脂谁与匀淡，偏向脸边浓。", "看叶嫩，惜花红。", "意无穷。", "如花似叶，岁岁年年，共占春风。"]'),
('song-ci-636','诉衷情','苏轼','宋','宋词','song-ci','诉衷情','[]','小莲初上琵琶弦。',54,'宋词/ci.song.1000.json','["小莲初上琵琶弦。", "弹破碧云天。", "分明绣阁幽恨，都向曲中传。", "肤莹玉，鬓梳蝉。", "绮窗前。", "素蛾今夜，故故随人，似斗婵娟。"]'),
('song-ci-637','更漏子','苏轼','宋','宋词','song-ci','更漏子','[]','水涵空，山照市。',58,'宋词/ci.song.1000.json','["水涵空，山照市。", "西汉二疏乡里。", "新白发，旧黄金。", "故人恩意深。", "海东头，山尽处。", "自古客槎来去。", "槎有信，赴秋期。", "使君行不归。"]'),
('song-ci-638','华清引','苏轼','宋','宋词','song-ci','华清引','[]','平时十月幸兰汤。',53,'宋词/ci.song.1000.json','["平时十月幸兰汤。", "玉甃琼梁。", "五家车马如水，珠玑满路旁。", "翠华一去掩方床。", "独留烟树苍苍。", "至今清夜月，依前过缭墙。"]'),
('song-ci-639','桃源忆故人','苏轼','宋','宋词','song-ci','桃源忆故人','[]','华胥梦断人何处。',56,'宋词/ci.song.1000.json','["华胥梦断人何处。", "听得莺啼红树。", "几点蔷薇香雨。", "寂寞闲庭户。", "暖风不解留花住。", "片片著人无数。", "楼上望春归去。", "芳草迷归路。"]'),
('song-ci-640','醉落魄・一斛珠','苏轼','宋','宋词','song-ci','醉落魄・一斛珠','[]','醉醒醒醉。',67,'宋词/ci.song.1000.json','["醉醒醒醉。", "凭君会取这滋味。", "浓斟琥珀香浮蚁。", "一到愁肠，别有阳春意。", "须将幕席为天地。", "歌前起舞花前睡。", "从他落魄陶陶里。", "犹胜醒醒，惹得闲憔悴。"]'),
('song-ci-641','醉落魄・一斛珠','苏轼','宋','宋词','song-ci','醉落魄・一斛珠','[]','分携如昨。',67,'宋词/ci.song.1000.json','["分携如昨。", "人生到处萍飘泊。", "偶然相聚还离索。", "多病多愁，须信从来错。", "尊前一笑休辞却。", "天涯同是伤沦落。", "故山犹负平生约。", "西望峨嵋，长羡归飞鹤。"]'),
('song-ci-642','醉落魄・一斛珠','苏轼','宋','宋词','song-ci','醉落魄・一斛珠','[]','苍颜华发。',67,'宋词/ci.song.1000.json','["苍颜华发。", "故山归计何时决。", "旧交新贵音书绝。", "惟有佳人，犹作殷勤别。", "离亭欲去歌声咽。", "潇潇细雨凉吹颊。", "泪珠不用罗巾裛。", "弹在罗衣，图得见时说。"]'),
('song-ci-643','醉落魄・一斛珠','苏轼','宋','宋词','song-ci','醉落魄・一斛珠','[]','轻云微月。',67,'宋词/ci.song.1000.json','["轻云微月。", "二更酒醒船初发。", "孤城回望苍烟合。", "公子佳人，不记归时节。", "巾偏扇坠藤床滑。", "觉来幽梦无人说。", "此生飘荡何时歇。", "家在西南，长作东南别。"]'),
('song-ci-644','谒金门','苏轼','宋','宋词','song-ci','谒金门','[]','秋帷里。',53,'宋词/ci.song.1000.json','["秋帷里。", "长漏伴人无寐。", "低玉枕凉轻绣被。", "一番秋气味。", "晓色又侵窗纸。", "窗外鸡声初起。", "声断几声还到耳。", "已明声未已。"]'),
('song-ci-645','谒金门','苏轼','宋','宋词','song-ci','谒金门','[]','秋池阁。',53,'宋词/ci.song.1000.json','["秋池阁。", "风傍晓庭帘幕。", "霜叶未衰吹未落。", "半惊鸦喜鹊。", "自笑浮名情薄。", "似与世人疏略。", "一片懒心双懒脚。", "好教闲处著。"]'),
('song-ci-646','谒金门','苏轼','宋','宋词','song-ci','谒金门','[]','今夜雨。',53,'宋词/ci.song.1000.json','["今夜雨。", "断送一年残暑。", "坐听潮声来别浦。", "明朝何处去。", "孤负金尊绿醑。", "来岁今宵圆否。", "酒醒梦回愁几许。", "夜阑还独语。"]'),
('song-ci-647','如梦令','苏轼','宋','宋词','song-ci','如梦令','[]','水垢何曾相受。',40,'宋词/ci.song.1000.json','["水垢何曾相受。", "细看两俱无有。", "寄语揩背人，尽日劳君挥肘。", "轻手。", "轻手。", "居士本来无垢。"]'),
('song-ci-648','如梦令','苏轼','宋','宋词','song-ci','如梦令','[]','自净方能净彼。',40,'宋词/ci.song.1000.json','["自净方能净彼。", "我自汗流呀气。", "寄语澡浴人，且共肉身游戏。", "但洗。", "但洗。", "俯为人间一切。"]'),
('song-ci-649','如梦令','苏轼','宋','宋词','song-ci','如梦令','[]','为向东坡传语。',40,'宋词/ci.song.1000.json','["为向东坡传语。", "人在玉堂深处。", "别后有谁来，雪压小桥无路。", "归去。", "归去。", "江上一犁春雨。"]'),
('song-ci-650','如梦令','苏轼','宋','宋词','song-ci','如梦令','[]','手种堂前桃李。',40,'宋词/ci.song.1000.json','["手种堂前桃李。", "无限绿阴青子。", "帘外百舌儿，惊起五更春睡。", "居士。", "居士。", "莫望小桥流水。"]'),
('song-ci-651','阳关曲','苏轼','宋','宋词','song-ci','阳关曲','[]','暮云收尽溢清寒。',32,'宋词/ci.song.1000.json','["暮云收尽溢清寒。", "银汗无声转玉盘。", "此声此夜不长好，明月明年何处看。"]'),
('song-ci-652','阳关曲','苏轼','宋','宋词','song-ci','阳关曲','[]','受降城下紫髯郎。',32,'宋词/ci.song.1000.json','["受降城下紫髯郎。", "戏马台南旧战场。", "恨君不取契丹首，金甲牙旗归故乡。"]'),
('song-ci-653','阳关曲','苏轼','宋','宋词','song-ci','阳关曲','[]','济南春好雪初晴。',34,'宋词/ci.song.1000.json','["济南春好雪初晴。", "才到龙山马足轻。", "使君莫忘霅溪女，还作《阳关》肠断声。"]'),
('song-ci-654','减字木兰花','苏轼','宋','宋词','song-ci','减字木兰花','[]','郑庄好客。',52,'宋词/ci.song.1000.json','["郑庄好客。", "容我尊前先堕帻。", "落笔生风。", "籍籍声名不负公。", "高山白早。", "莹骨冰肤那解老。", "从此南徐。", "良夜清风月满湖。"]'),
('song-ci-655','减字木兰花','苏轼','宋','宋词','song-ci','减字木兰花','[]','云鬟倾倒。',52,'宋词/ci.song.1000.json','["云鬟倾倒。", "醉倚阑干风月好。", "凭仗相扶。", "误入仙家碧玉壶。", "连天衰草。", "下走湖南西去道。", "一舸姑苏。", "便逐鸱夷去得无。"]'),
('song-ci-656','减字木兰花','苏轼','宋','宋词','song-ci','减字木兰花','[]','闽溪珍献。',52,'宋词/ci.song.1000.json','["闽溪珍献。", "过海云帆来似箭。", "玉座金盘。", "不贡奇葩四百年。", "轻红酿白。", "雅称佳人纤手擘。", "骨细肌香。", "恰是当年十八娘。"]'),
('song-ci-657','减字木兰花','苏轼','宋','宋词','song-ci','减字木兰花','[]','贤哉令尹。',52,'宋词/ci.song.1000.json','["贤哉令尹。", "三仕已之无喜愠。", "我独何人。", "犹把虚名玷搢绅。", "不如归去。", "二顷良田无觅处。", "归去来兮。", "待有良田是几时。"]'),
('song-ci-658','减字木兰花','苏轼','宋','宋词','song-ci','减字木兰花','[]','玉觞无味。',52,'宋词/ci.song.1000.json','["玉觞无味。", "中有佳人千点泪。", "学道忘忧。", "一念还成不自由。", "如今未见。", "归去东园花似霰。", "一语相开。", "匹似当初本不来。"]'),
('song-ci-659','减字木兰花','苏轼','宋','宋词','song-ci','减字木兰花','[]','春光亭下。',52,'宋词/ci.song.1000.json','["春光亭下。", "流水如今何在也。", "岁月如梭。", "白首相看拟奈何。", "故人重见。", "世事年来千万变。", "官况阑珊。", "惭愧青松守岁寒。"]'),
('song-ci-660','减字木兰花','苏轼','宋','宋词','song-ci','减字木兰花','[]','惟熊佳梦。',52,'宋词/ci.song.1000.json','["惟熊佳梦。", "释氏老君亲抱送。", "壮气横秋。", "未满三朝已食牛。", "犀钱玉果。", "利市平分沾四坐。", "多谢无功。", "此事如何到得侬。"]'),
('song-ci-661','减字木兰花','苏轼','宋','宋词','song-ci','减字木兰花','[]','晓来风细。',52,'宋词/ci.song.1000.json','["晓来风细。", "不会鹊声来报喜。", "却羡寒梅。", "先觉春风一夜来。", "香笺一纸。", "写尽回文机上意。", "欲卷重开。", "读遍千回与万回。"]'),
('song-ci-662','减字木兰花','苏轼','宋','宋词','song-ci','减字木兰花','[]','天台旧路。',54,'宋词/ci.song.1000.json','["天台旧路。", "应恨刘郎来又去。", "别酒频倾。", "忍听《阳关》第四声。", "刘郎未老。", "怀恋仙乡重得到。", "只恐因循。", "不见如今劝酒人。"]'),
('song-ci-663','减字木兰花','苏轼','宋','宋词','song-ci','减字木兰花','[]','双龙对起。',52,'宋词/ci.song.1000.json','["双龙对起。", "白甲苍髯烟雨里。", "疏影微香。", "下有幽人昼梦长。", "湖风清软。", "双鹊飞来争噪晚。", "翠飐红轻。", "时下凌宵百尺英。"]'),
('song-ci-664','减字木兰花','苏轼','宋','宋词','song-ci','减字木兰花','[]','琵琶绝艺。',52,'宋词/ci.song.1000.json','["琵琶绝艺。", "年纪都来十一二。", "拨弄么弦。", "未解将心指下传。", "主人瞋小。", "欲向东风先醉倒。", "已属君家。", "且更从容等待他。"]'),
('song-ci-665','减字木兰花','苏轼','宋','宋词','song-ci','减字木兰花','[]','春牛春杖。',52,'宋词/ci.song.1000.json','["春牛春杖。", "无限春风来海上。", "便与春工。", "染得桃红似肉红。", "春幡春胜。", "一阵春风吹酒醒。", "不似天涯。", "卷起杨花似雪花。"]'),
('song-ci-666','减字木兰花','苏轼','宋','宋词','song-ci','减字木兰花','[]','云容皓白。',52,'宋词/ci.song.1000.json','["云容皓白。", "破晓玉英纷似织。", "风力无端。", "欲学杨花更耐寒。", "相如未老。", "梁苑犹能陪俊少。", "莫惹闲愁。", "且折江梅上小楼。"]'),
('song-ci-667','减字木兰花','苏轼','宋','宋词','song-ci','减字木兰花','[]','玉房金蕊。',52,'宋词/ci.song.1000.json','["玉房金蕊。", "宜在玉人纤手里。", "淡月朦胧。", "更有微微弄袖风。", "温香熟美。", "醉慢云鬟垂两耳。", "多谢春工。", "不是花红是玉红。"]'),
('song-ci-668','减字木兰花','苏轼','宋','宋词','song-ci','减字木兰花','[]','春庭月午。',52,'宋词/ci.song.1000.json','["春庭月午。", "摇荡香醪光欲舞。", "步转迥廊。", "半落梅花婉娩香。", "轻云薄雾。", "总是少年行乐处。", "不似秋光。", "只与离人照断肠。"]'),
('song-ci-669','减字木兰花','苏轼','宋','宋词','song-ci','减字木兰花','[]','天然宅院。',52,'宋词/ci.song.1000.json','["天然宅院。", "赛了千千并万万。", "说与贤知。", "表德元来是胜之。", "今来十四。", "海里猴儿奴子是。", "要赌休痴。", "六双骰儿六点儿。"]'),
('song-ci-670','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','风卷珠帘自上钩。',48,'宋词/ci.song.1000.json','["风卷珠帘自上钩。", "萧萧乱叶报新秋。", "独携纤手上高楼。", "缺月向人舒窈窕，三星当户照绸缪。", "香生雾縠见纤柔。"]'),
('song-ci-671','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','山下兰芽短浸溪。',48,'宋词/ci.song.1000.json','["山下兰芽短浸溪。", "松间沙路净无泥。", "萧萧暮雨子规啼。", "谁道人生无再少，门前流水尚能西。", "休将白发唱黄鸡。"]'),
('song-ci-672','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','西塞山边白鹭飞。',48,'宋词/ci.song.1000.json','["西塞山边白鹭飞。", "散花洲外片帆微。", "桃花流水鳜鱼肥。", "自庇一身青箬笠，相随到处绿蓑衣。", "斜风细雨不须归。"]'),
('song-ci-673','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','覆块青青麦未苏。',48,'宋词/ci.song.1000.json','["覆块青青麦未苏。", "江南云叶暗随车。", "临皋烟景世间无。", "雨脚半收檐断线，雪林初下瓦疏珠。", "归来冰颗乱黏须。"]'),
('song-ci-674','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','醉梦醺醺晓未苏。',48,'宋词/ci.song.1000.json','["醉梦醺醺晓未苏。", "门前辘辘使君车。", "扶头一盏怎生无。", "废圃寒蔬挑翠羽，小槽春酒冻真珠。", "清香细细嚼梅须。"]'),
('song-ci-675','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','雪里餐毡例姓苏。',48,'宋词/ci.song.1000.json','["雪里餐毡例姓苏。", "使君载酒为回车。", "天寒酒色转头无。", "荐士已闻飞鹗表，报恩应不用蛇珠。", "醉中还许揽桓须。"]'),
('song-ci-676','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','半夜银山上积苏。',48,'宋词/ci.song.1000.json','["半夜银山上积苏。", "朝来九陌带随车。", "涛江烟渚一时无。", "空腹有诗衣有结，湿薪如桂米如珠。", "冻吟谁伴拈髭须。"]'),
('song-ci-677','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','万顷风涛不记苏。',48,'宋词/ci.song.1000.json','["万顷风涛不记苏。", "雪晴江上麦千车。", "但令人饱我愁无。", "翠袖倚风萦柳絮，绛唇得酒烂樱珠。", "尊前呵手镊霜须。"]'),
('song-ci-678','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','珠桧丝杉冷欲霜。',48,'宋词/ci.song.1000.json','["珠桧丝杉冷欲霜。", "山城歌舞助凄凉。", "且餐山色饮湖光。", "共挽朱幡留半日，强揉青蕊作重阳。", "不知明日为谁黄。"]'),
('song-ci-679','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','霜鬓真堪插拒霜。',52,'宋词/ci.song.1000.json','["霜鬓真堪插拒霜。", "哀弦危柱作《伊凉》。", "暂时流转为风光。", "未遣清尊空北海，莫因《长笛》赋山阳。", "金钗玉腕泻鹅黄。"]'),
('song-ci-680','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','傅粉郎君又粉奴。',50,'宋词/ci.song.1000.json','["傅粉郎君又粉奴。", "莫教施粉与施朱。", "自然冰玉照香酥。", "有客能为《神女赋》，凭君送与雪儿书。", "梦魂东去觅桑榆。"]'),
('song-ci-681','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','菊暗荷枯一夜霜。',48,'宋词/ci.song.1000.json','["菊暗荷枯一夜霜。", "新苞绿叶照林光。", "竹篱茅舍出青黄。", "香雾噀人惊半破，清泉流齿怯初尝。", "吴姬三日手犹香。"]'),
('song-ci-682','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','雪颔霜髯不自惊。',48,'宋词/ci.song.1000.json','["雪颔霜髯不自惊。", "更将翦采发春荣。", "羞颜未醉已先赪。", "莫唱黄鸡并白发，且呼张丈唤殷兄。", "有人归去欲卿卿。"]'),
('song-ci-683','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','料峭东风翠幕惊。',48,'宋词/ci.song.1000.json','["料峭东风翠幕惊。", "云何不饮对公荣。", "水晶盘莹玉鳞赪。", "花影莫孤三夜月，朱颜未称五年兄。", "翰林子墨主人卿。"]'),
('song-ci-684','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','照日深红暖见鱼。',48,'宋词/ci.song.1000.json','["照日深红暖见鱼。", "连溪绿暗晚藏乌。", "黄童白叟聚睢盱。", "糜鹿逢人虽未惯，猿揉闻鼓不须呼。", "归家说与采桑姑。"]'),
('song-ci-685','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','旋抹红妆看使君。',48,'宋词/ci.song.1000.json','["旋抹红妆看使君。", "三三五五棘篱门。", "相挨踏破蒨罗裙。", "老幼扶携收麦社，乌鸢翔舞赛神村。", "道逢醉叟卧黄昏。"]'),
('song-ci-686','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','麻叶层层苘叶光。',48,'宋词/ci.song.1000.json','["麻叶层层苘叶光。", "谁家煮蚕一村香。", "隔篱娇语络丝娘。", "垂白杖藜抬醉眼，捋青捣麨软饥肠。", "问言豆叶几时黄。"]'),
('song-ci-687','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','簌簌衣巾落枣花。',48,'宋词/ci.song.1000.json','["簌簌衣巾落枣花。", "村南村北响缲车。", "牛衣古柳卖黄瓜。", "酒困路长惟欲睡，日高人渴漫思茶。", "敲门试问野人家。"]'),
('song-ci-688','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','软草平莎过雨新。',48,'宋词/ci.song.1000.json','["软草平莎过雨新。", "轻沙走马路无尘。", "何时收拾耦耕身。", "日暖桑麻光似泼，风来蒿艾气如薰。", "使君元是此中人。"]'),
('song-ci-689','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','道字娇讹苦未成。',48,'宋词/ci.song.1000.json','["道字娇讹苦未成。", "未应春阁梦多情。", "朝来何事绿鬟倾。", "彩索身轻长趁燕，红窗睡重不闻莺。", "困人天气近清明。"]'),
('song-ci-690','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','缥缈危楼紫翠间。',48,'宋词/ci.song.1000.json','["缥缈危楼紫翠间。", "良辰乐事古难全。", "感时怀旧独凄然。", "璧月琼枝空夜夜，菊花人貌自年年。", "不知来岁与谁看。"]'),
('song-ci-691','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','桃李溪边驻画轮。',48,'宋词/ci.song.1000.json','["桃李溪边驻画轮。", "鹧鸪声里倒清尊。", "夕阳虽好近黄昏。", "香在衣裳妆在臂，水连芳草月连云。", "几时归去不销魂。"]'),
('song-ci-692','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','四面垂杨十里荷。',48,'宋词/ci.song.1000.json','["四面垂杨十里荷。", "问云何处最花多。", "画楼南畔夕阳和。", "天气乍凉人寂寞，光阴须得酒消磨。", "且来花里听笙歌。"]'),
('song-ci-693','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','一别姑苏已四年。',48,'宋词/ci.song.1000.json','["一别姑苏已四年。", "秋风南浦送归船。", "画帘重见水中仙。", "霜鬓不须催我老，杏花依旧驻君颜。", "夜阑相对梦魂间。"]'),
('song-ci-694','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','惟见眉间一点黄。',48,'宋词/ci.song.1000.json','["惟见眉间一点黄。", "诏书催发羽书忙。", "从教娇泪洗红妆。", "上殿云宵生羽翼，论兵齿颊带风霜。", "归来衫袖有天香。"]'),
('song-ci-695','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','长记鸣琴子贱堂。',48,'宋词/ci.song.1000.json','["长记鸣琴子贱堂。", "朱颜绿发映垂杨。", "如今秋鬓数茎霜。", "聚散交游如梦寐，升沈闲事莫思量。", "仲卿终不避桐乡。"]'),
('song-ci-696','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','风压轻云贴水飞。',48,'宋词/ci.song.1000.json','["风压轻云贴水飞。", "乍晴池馆燕争泥。", "沈郎多病不胜衣。", "沙上不闻鸿雁信，竹间时听鹧鸪啼。", "此情惟有落花知。"]'),
('song-ci-697','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','罗袜空飞洛浦尘。',48,'宋词/ci.song.1000.json','["罗袜空飞洛浦尘。", "锦袍不见谪仙人。", "携壶藉草亦天真。", "玉粉轻黄千岁药，雪花浮动万家春。", "醉归江路野梅新。"]'),
('song-ci-698','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','白雪清词出坐间。',48,'宋词/ci.song.1000.json','["白雪清词出坐间。", "爱君才器两俱全。", "异乡风景却依然。", "可恨相逢能几日，不知重会是何年。", "茱萸仔细更重看。"]'),
('song-ci-699','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','细雨斜风作晓寒。',48,'宋词/ci.song.1000.json','["细雨斜风作晓寒。", "淡烟疏柳媚晴滩。", "入淮清洛渐漫漫。", "雪沫乳花浮午盏，蓼茸蒿笋试春盘。", "人间有味是清欢。"]'),
('song-ci-700','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','门外东风雪洒裾。',48,'宋词/ci.song.1000.json','["门外东风雪洒裾。", "山头回首望三吴。", "不应弹铗为无鱼。", "上党从来天下脊，先生元是古之儒。", "时平不用鲁连书。"]'),
('song-ci-701','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','惭愧今年二麦丰。',48,'宋词/ci.song.1000.json','["惭愧今年二麦丰。", "千畦细浪舞晴空。", "化工馀力染夭红。", "归去山公应倒载，阑街拍手笑儿童。", "甚时名作锦薰笼。"]'),
('song-ci-702','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','芍药樱桃两斗新。',48,'宋词/ci.song.1000.json','["芍药樱桃两斗新。", "名园高会送芳辰。", "洛阳初夏广陵春。", "红玉半开菩萨面，丹砂浓点柳枝唇。", "尊前还有个中人。"]'),
('song-ci-703','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','学画鸦儿正妙年。',48,'宋词/ci.song.1000.json','["学画鸦儿正妙年。", "阳城下蔡困嫣然。", "凭君莫唱短因缘。", "雾帐吹笙香袅袅，霜庭按舞月娟娟。", "曲终红袖落双缠。"]'),
('song-ci-704','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','一梦江湖费五年。',48,'宋词/ci.song.1000.json','["一梦江湖费五年。", "归来风物故依然。", "相逢一醉是前缘。", "迁客不应常眊矂，使君为出小婵娟。", "翠鬟聊著小诗缠。"]'),
('song-ci-705','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','轻汗微微透碧纨。',48,'宋词/ci.song.1000.json','["轻汗微微透碧纨。", "明朝端午浴芳兰。", "流香涨腻满晴川。", "彩线轻缠红玉臂，小符斜挂绿云鬟。", "佳人相见一千年。"]'),
('song-ci-706','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','徐邈能中酒圣贤。',48,'宋词/ci.song.1000.json','["徐邈能中酒圣贤。", "刘伶席地幕青天。", "潘郎白璧为谁连。", "无可奈何新白发，不如归去旧青山。", "恨无人借买山钱。"]'),
('song-ci-707','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','倾盖相逢胜白头。',48,'宋词/ci.song.1000.json','["倾盖相逢胜白头。", "故山空复梦松楸。", "此心安处是菟裘。", "卖剑买牛吾欲老，乞浆得酒更何求。", "愿为辞社宴春秋。"]'),
('song-ci-708','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','炙手无人傍屋头。',48,'宋词/ci.song.1000.json','["炙手无人傍屋头。", "萧萧晚雨脱梧楸。", "谁怜季子敞貂裘。", "顾我已无当世望，似君须向古人求。", "岁寒松柏肯惊秋。"]'),
('song-ci-709','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','画隼横江喜再游。',48,'宋词/ci.song.1000.json','["画隼横江喜再游。", "老鱼跳槛识清讴。", "流年未肯付东流。", "黄菊篱边无怅望，白云乡里有温柔。", "挽回霜鬓莫教休。"]'),
('song-ci-710','双荷叶・忆秦娥','苏轼','宋','宋词','song-ci','双荷叶・忆秦娥','[]','双溪月。',56,'宋词/ci.song.1000.json','["双溪月。", "清光遍照双荷叶。", "双荷叶。", "红心未偶，绿衣偷结。", "背风迎雨流珠滑。", "轻舟短棹先秋折。", "先秋折。", "烟鬟未上，玉杯微缺。"]'),
('song-ci-711','皂罗特髻','苏轼','宋','宋词','song-ci','皂罗特髻','[]','采菱拾翠，算似此佳名，阿谁消得。',101,'宋词/ci.song.1000.json','["采菱拾翠，算似此佳名，阿谁消得。", "采菱拾翠，称使君知客。", "千金买、采菱拾翠，更罗裙、满把珍珠结。", "采菱拾翠，正髻鬟初合。", "真个、采菱拾翠，但深怜轻拍。", "一双手、采菱拾翠，绣衾下、抱著俱香滑。", "采菱拾翠，待到京寻觅。"]'),
('song-ci-712','调笑令','苏轼','宋','宋词','song-ci','调笑令','[]','渔父。',40,'宋词/ci.song.1000.json','["渔父。", "渔父。", "江上微风细雨。", "青蓑黄箬裳衣。", "红酒白鱼暮归。", "归暮。", "归暮。", "长笛一声何处。"]'),
('song-ci-713','调笑令','苏轼','宋','宋词','song-ci','调笑令','[]','归雁。',40,'宋词/ci.song.1000.json','["归雁。", "归雁。", "饮啄江南南岸。", "将飞却下盘桓。", "塞外春来苦寒。", "寒苦。", "寒苦。", "藻荇欲生且住。"]'),
('song-ci-714','荷华媚','苏轼','宋','宋词','song-ci','荷华媚','[]','霞苞电荷碧。',74,'宋词/ci.song.1000.json','["霞苞电荷碧。", "天然地、别是风流标格。", "重重青盖下，千娇照水，好红红白白。", "每怅望、明月清风夜，甚低迷不语，妖邪无力。", "终须放、船儿去，清香深处住，看伊颜色。"]'),
('song-ci-715','青玉案','苏轼','宋','宋词','song-ci','青玉案','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u897f\u6e56"]','三年枕上吴中路。',80,'宋词/ci.song.1000.json','["三年枕上吴中路。", "遣黄耳、随君去。", "若到松江呼小渡。", "莫惊鸥鹭，四桥尽是，老子经行处。", "辋川图上看春暮。", "常记高人右丞句。", "作个归期天已许。", "春衫犹是，小蛮针线，曾湿西湖雨。"]'),
('song-ci-716','渔家傲','苏轼','宋','宋词','song-ci','渔家傲','[]','些小白须何用染。',72,'宋词/ci.song.1000.json','["些小白须何用染。", "几人得见星星点。", "作郡浮光虽似箭。", "君莫厌。", "也应胜我三年贬。", "我欲自嗟还不敢。", "向来三郡宁非忝。", "婚嫁事稀年冉冉。", "知有渐。", "千钧重担从头减。"]'),
('song-ci-717','江城子','苏轼','宋','宋词','song-ci','江城子','[]','前瞻马耳九仙山。',86,'宋词/ci.song.1000.json','["前瞻马耳九仙山。", "碧连天。", "晚云闲。", "城上高台，真个是超然。", "莫使匆匆云雨散，今夜里，月婵娟。", "小溪鸥鹭静联拳。", "去翩翩。", "点轻烟。", "人事凄凉，回首便他年。", "莫忘使君歌笑处，垂柳下，矮槐前。"]'),
('song-ci-718','江城子','苏轼','宋','宋词','song-ci','江城子','[]','墨云拖雨过西楼。',86,'宋词/ci.song.1000.json','["墨云拖雨过西楼。", "水东流。", "晚烟收。", "柳外残阳，回照动帘钩。", "今夜巫山真个好，花未落，酒新篘。", "美人微笑转星眸。", "月华羞。", "捧金瓯。", "歌扇萦风，吹散一春愁。", "拭问江南诸伴侣，谁似我，醉扬州。"]'),
('song-ci-719','南乡子','苏轼','宋','宋词','song-ci','南乡子','[]','未倦长卿游。',66,'宋词/ci.song.1000.json','["未倦长卿游。", "漫舞夭歌烂不收。", "不是使君能矫世，谁留。", "教有琼梳脱麝油。", "香粉镂金球。", "花艳红笺笔欲流。", "从此丹唇并皓齿，清柔。", "唱遍山东一百州。"]'),
('song-ci-720','南乡子','苏轼','宋','宋词','song-ci','南乡子','[]','绣鞅玉环游。',66,'宋词/ci.song.1000.json','["绣鞅玉环游。", "灯晃帘疏笑却收。", "久立香车催欲上，还留。", "更且檀唇点杏油。", "花遍六么球。", "面旋回风带雪流。", "春入腰肢金缕细，轻柔。", "种柳应须柳柳州。"]'),
('song-ci-721','菩萨蛮','苏轼','宋','宋词','song-ci','菩萨蛮','[]','娟娟侵鬓妆痕浅。',52,'宋词/ci.song.1000.json','["娟娟侵鬓妆痕浅。", "双颦相媚弯如翦。", "一瞬百般宜。", "无论笑与啼。", "酒阑思翠被。", "特故腾腾地。", "生怕促归轮。", "微波先注人。"]'),
('song-ci-722','菩萨蛮','苏轼','宋','宋词','song-ci','菩萨蛮','[]','涂香莫惜莲承步。',52,'宋词/ci.song.1000.json','["涂香莫惜莲承步。", "长愁罗袜凌波去。", "只见舞迥风。", "都无行处踪。", "偷穿宫样稳。", "并立双趺困。", "纤妙说应难。", "须从掌上看。"]'),
('song-ci-723','菩萨蛮','苏轼','宋','宋词','song-ci','菩萨蛮','[]','玉环坠耳黄金饰。',52,'宋词/ci.song.1000.json','["玉环坠耳黄金饰。", "轻衫罩体香罗碧。", "缓步困春醪。", "春融脸上桃。", "花钿从委地。", "谁与郎为意。", "常爱月华清。", "此时憎月明。"]'),
('song-ci-724','蝶恋花','苏轼','宋','宋词','song-ci','蝶恋花','[]','别酒劝君君一醉。',70,'宋词/ci.song.1000.json','["别酒劝君君一醉。", "清润潘郎，又是何郎婿。", "记取钗头新利市。", "莫将分付东邻子。", "回首长安佳丽地。", "三十年前，我是风流帅。", "为向青楼寻旧事。", "花枝缺处馀名字。"]'),
('song-ci-725','蝶恋花','苏轼','宋','宋词','song-ci','蝶恋花','[]','泛泛东风初破五。',70,'宋词/ci.song.1000.json','["泛泛东风初破五。", "江柳微黄，万万千千缕。", "佳气郁葱来绣户。", "当年江上生奇女。", "一盏寿觞谁与举。", "三个明珠，膝上王文度。", "放尽穷鳞看圉圉。", "天公为下曼陀雨。"]'),
('song-ci-726','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','入袂轻风不破尘。',48,'宋词/ci.song.1000.json','["入袂轻风不破尘。", "玉簪犀璧醉佳辰。", "一番红粉为谁新。", "团扇只堪题往事，新丝那解系行人。", "酒阑滋味思残春。"]'),
('song-ci-727','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','几共查梨到雪霜。',48,'宋词/ci.song.1000.json','["几共查梨到雪霜。", "一经题品便生光。", "木奴何处避雌黄。", "北客有来初未识，南金无价喜新尝。", "含滋嚼句齿牙香。"]'),
('song-ci-728','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','山色横侵蘸晕霞。',48,'宋词/ci.song.1000.json','["山色横侵蘸晕霞。", "湘川风静吐寒花。", "远林屋散尚啼鸦。", "梦到故园多少路，酒醒南望隔天涯。", "月明千里照平沙。"]'),
('song-ci-729','减字木兰花','苏轼','宋','宋词','song-ci','减字木兰花','[]','神闲意定。',52,'宋词/ci.song.1000.json','["神闲意定。", "万籁收声天地静。", "玉指冰弦。", "未动宫商意已传。", "悲风流水。", "写处寥寥千古意。", "归去无眠。", "一夜馀音在耳边。"]'),
('song-ci-730','减字木兰花','苏轼','宋','宋词','song-ci','减字木兰花','[]','银铮旋品。',54,'宋词/ci.song.1000.json','["银铮旋品。", "不用缠头千尺锦。", "妙思如泉。", "一洗闲愁十五年。", "为公少止。", "起舞属公《公莫》起。", "风里银山。", "摆撼鱼龙我自闲。"]'),
('song-ci-731','减字木兰花','苏轼','宋','宋词','song-ci','减字木兰花','[]','柔和性气。',52,'宋词/ci.song.1000.json','["柔和性气。", "雅称佳名呼懿懿。", "解舞能讴。", "绝妙年中有品流。", "眉长眼细。", "淡淡梳妆新绾髻。", "懊恼风情。", "春著花枝百态生。"]'),
('song-ci-732','减字木兰花','苏轼','宋','宋词','song-ci','减字木兰花','[]','莺初解语。',52,'宋词/ci.song.1000.json','["莺初解语。", "最是一年春好处。", "微雨如酥。", "草色遥看近却无。", "休辞醉倒。", "花不看开人易老。", "莫待春回。", "颠倒红英间绿苔。"]'),
('song-ci-733','减字木兰花','苏轼','宋','宋词','song-ci','减字木兰花','[]','江南游女。',52,'宋词/ci.song.1000.json','["江南游女。", "问我何年归得去。", "雨细风微。", "雨足如霜挽纻衣。", "江亭夜语。", "喜见京华新样舞。", "莲步轻飞。", "迁客今朝始是归。"]'),
('song-ci-734','减字木兰花','苏轼','宋','宋词','song-ci','减字木兰花','[]','娇多媚。',51,'宋词/ci.song.1000.json','["娇多媚。", "体柳轻盈千万态。", "殢主尤宾。", "敛黛含嚬喜又嗔。", "徐君乐饮。", "笑谑从伊情意恁。", "脸嫩敷红。", "花倚朱阑裹住风。"]'),
('song-ci-735','减字木兰花','苏轼','宋','宋词','song-ci','减字木兰花','[]','双鬟绿坠。',52,'宋词/ci.song.1000.json','["双鬟绿坠。", "娇眼横波眉黛翠。", "妙舞蹁跹。", "掌上身轻意态妍。", "曲穷力困。", "笑倚人旁香喘喷。", "老大逢欢。", "昏眼犹能仔细看。"]'),
('song-ci-736','减字木兰花','苏轼','宋','宋词','song-ci','减字木兰花','[]','天真雅丽。',52,'宋词/ci.song.1000.json','["天真雅丽。", "容态温柔心性慧。", "响亮歌喉。", "遏住行云翠不收。", "妙词佳曲。", "啭出新声能断续。", "重客多情。", "满劝金卮玉手擎。"]'),
('song-ci-737','南歌子','苏轼','宋','宋词','song-ci','南歌子','[]','见说东园好，能消北客愁。',62,'宋词/ci.song.1000.json','["见说东园好，能消北客愁。", "虽非吾土且登楼。", "行尽江南南岸、此淹留。", "短日明枫缬，清霜暗菊逑。", "流年回首付东流。", "凭仗挽回潘鬓、莫教秋。"]'),
('song-ci-738','如梦令','苏轼','宋','宋词','song-ci','如梦令','[]','城上层楼叠巘。',40,'宋词/ci.song.1000.json','["城上层楼叠巘。", "城下清淮古汴。", "举手揖吴云，人与暮天俱远。", "魂断。", "魂断。", "后夜松江月满。"]'),
('song-ci-739','瑞鹧鸪','苏轼','宋','宋词','song-ci','瑞鹧鸪','[]','城头月落尚啼乌。',64,'宋词/ci.song.1000.json','["城头月落尚啼乌。", "朱舰红船早满湖。", "鼓吹未容迎五马，水云先已漾双凫。", "映山黄帽螭头舫，夹岸青烟鹊尾炉。", "老病逢春只思睡，独求僧榻寄须臾。"]'),
('song-ci-740','临江仙','苏轼','宋','宋词','song-ci','临江仙','[]','谁道东阳都瘦损，凝然点漆精神。',70,'宋词/ci.song.1000.json','["谁道东阳都瘦损，凝然点漆精神。", "瑶林终自隔风尘，试看披鹤氅，仍是谪仙人。", "省可清言挥玉麈，真须保器全真。", "风流何似道家纯。", "不应同蜀客，惟爱卓文君。"]'),
('song-ci-741','少年游','苏轼','宋','宋词','song-ci','少年游','[]','玉肌铅粉傲秋霜。',62,'宋词/ci.song.1000.json','["玉肌铅粉傲秋霜。", "准拟凤呼凰。", "伶伦不见，清香未吐，且糠秕吹扬。", "到处成双君独只，空无数、烂文章。", "一点香檀，谁能借箸，无复似张良。"]'),
('song-ci-742','一斛珠','苏轼','宋','宋词','song-ci','一斛珠','[]','洛城春晚。',67,'宋词/ci.song.1000.json','["洛城春晚。", "垂杨乱掩红楼半。", "小池轻浪纹如篆。", "烛下花前，曾醉离歌宴。", "自惜风流云雨散。", "关山有限情无限。", "待君重见寻芳伴。", "为说相思、目断西楼燕。"]'),
('song-ci-743','点绛唇','苏轼','宋','宋词','song-ci','点绛唇','[]','闲倚胡床，庾公楼外峰千朵。',50,'宋词/ci.song.1000.json','["闲倚胡床，庾公楼外峰千朵。", "与谁同坐。", "明月清风我。", "别乘一来，有唱应须和。", "还知麽。", "自从添个。", "风月平分破。"]'),
('song-ci-744','点绛唇','苏轼','宋','宋词','song-ci','点绛唇','[]','红杏飘香，柳含烟翠拖轻缕。',50,'宋词/ci.song.1000.json','["红杏飘香，柳含烟翠拖轻缕。", "水边朱户。", "尽卷黄昏雨。", "烛影摇风，一枕伤春绪。", "归不去。", "凤楼何处。", "芳草迷归路。"]'),
('song-ci-745','虞美人','苏轼','宋','宋词','song-ci','虞美人','[]','持杯遥劝天边月。',66,'宋词/ci.song.1000.json','["持杯遥劝天边月。", "愿月圆无缺。", "持杯复更劝花枝。", "且愿花枝长在、莫离披。", "持杯月下花前醉。", "休问荣枯事。", "此欢能有几人知。", "对酒逢花不饮、待何时。"]'),
('song-ci-746','天仙子','苏轼','宋','宋词','song-ci','天仙子','[]','走马探花花发未。',80,'宋词/ci.song.1000.json','["走马探花花发未。", "人与化工俱不易。", "千回来绕百回看，蜂作婢。", "莺为使。", "谷雨清明空屈指。", "白发卢郎情未已。", "一夜翦刀收玉蕊。", "尊前还对断肠红，人有泪。", "花无意。", "明日酒醒应满地。"]'),
('song-ci-747','满庭芳','苏轼','宋','宋词','song-ci','满庭芳','[]','归去来兮，清溪无底，上有千仞嵯峨。',118,'宋词/ci.song.1000.json','["归去来兮，清溪无底，上有千仞嵯峨。", "画楼东畔，天远夕阳多。", "老去君恩未报，空回首、弹铗悲歌。", "船头转，长风万里，归马驻平坡。", "无何。", "何处有，银潢尽处，天女停梭。", "问何事人间，久戏风波。", "顾谓同来稚子，应烂汝、腰下长柯。", "青衫破，群仙笑我，千缕挂烟蓑。"]'),
('song-ci-748','南乡子','苏轼','宋','宋词','song-ci','南乡子','[]','千骑试春游。',66,'宋词/ci.song.1000.json','["千骑试春游。", "小雨如酥落便收。", "能使江东归老客，迟留。", "白酒无声滑泻油。", "飞火乱星逑。", "浅黛横波翠欲流。", "不似白云乡外冷，温柔。", "此去淮南第一州。"]'),
('song-ci-749','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','缥缈红妆照浅溪。',48,'宋词/ci.song.1000.json','["缥缈红妆照浅溪。", "薄云疏雨不成泥。", "送君何处古台西。", "废沼夜来秋水满，茂林深处晚莺啼。", "行人肠断草凄迷。"]'),
('song-ci-750','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','["\u897f\u6e56"]','阳羡姑苏已买田。',48,'宋词/ci.song.1000.json','["阳羡姑苏已买田。", "相逢谁信是前缘。", "莫教便唱水如天。", "我作洞霄君作守，白头相对故依然。", "西湖知有几同年。"]'),
('song-ci-751','减字木兰花','苏轼','宋','宋词','song-ci','减字木兰花','[]','空床响琢。',52,'宋词/ci.song.1000.json','["空床响琢。", "花上春禽冰上雹。", "醉梦尊前。", "惊起湖风入坐寒。", "转关镬索。", "春水流弦霜入拨。", "月堕更阑。", "更请宫高奏独弹。"]'),
('song-ci-752','减字木兰花','苏轼','宋','宋词','song-ci','减字木兰花','[]','回风落景。',52,'宋词/ci.song.1000.json','["回风落景。", "散乱东墙疏竹影。", "满坐清微。", "入袖寒泉不湿衣。", "梦回酒醒。", "百尺飞澜鸣碧井。", "雪洒冰麾。", "散落佳人白玉肌。"]'),
('song-ci-753','减字木兰花','苏轼','宋','宋词','song-ci','减字木兰花','[]','海南奇宝。',52,'宋词/ci.song.1000.json','["海南奇宝。", "铸出团团如栲栳。", "曾到昆仑。", "乞得山头玉女盆。", "绛州王老。", "百岁痴顽推不倒。", "海口如门。", "一派黄流已电奔。"]'),
('song-ci-754','行香子','苏轼','宋','宋词','song-ci','行香子','[]','北望平川。',84,'宋词/ci.song.1000.json','["北望平川。", "野水荒湾。", "共寻春、飞步孱颜。", "和风弄袖，香雾萦鬟。", "正酒酣时，人语笑，白云间。", "飞鸿落照，相将归去，澹娟娟、玉宇清闲。", "何人无事，宴坐空山。", "望长桥上，灯火乱，使君还。"]'),
('song-ci-755','画堂春','苏轼','宋','宋词','song-ci','画堂春','[]','柳花飞处麦摇波。',57,'宋词/ci.song.1000.json','["柳花飞处麦摇波。", "晚湖净鉴新磨。", "小舟飞棹去如梭。", "齐唱采菱歌。", "平野水云溶漾，小楼风日晴和。", "济南何在暮云多。", "归去奈愁何。"]'),
('song-ci-756','浣溪沙','苏轼','宋','宋词','song-ci','浣溪沙','[]','花满银塘水漫流。',50,'宋词/ci.song.1000.json','["花满银塘水漫流。", "犀槌玉板奏《凉州》。", "顺风环佩过秦楼。", "远汉碧云轻漠漠，今宵人在鹊桥头。", "一声敲彻绛河秋。"]'),
('song-ci-757','好事近','苏轼','宋','宋词','song-ci','好事近','[]','烟外倚危楼，初见远灯明灭。',53,'宋词/ci.song.1000.json','["烟外倚危楼，初见远灯明灭。", "却跨玉虹归去，看洞天星月。", "当时张范风流在，况一尊浮雪。", "莫问世间何事，与剑头微吷。"]'),
('song-ci-758','占春芳','苏轼','宋','宋词','song-ci','占春芳','[]','红杏了，夭桃尽，独自占春芳。',56,'宋词/ci.song.1000.json','["红杏了，夭桃尽，独自占春芳。", "不比人间兰麝，自然透骨生香。", "对酒莫相忘。", "似佳人、兼合明光。", "只忧长笛吹花落，除是宁王。"]'),
('song-ci-759','南歌子','苏轼','宋','宋词','song-ci','南歌子','[]','云鬓裁新绿，霞衣曳晓红。',62,'宋词/ci.song.1000.json','["云鬓裁新绿，霞衣曳晓红。", "待歌凝立翠筵中。", "一朵彩云何事、下巫峰。", "趁拍鸾飞镜，回身燕漾空。", "莫翻红袖过帘栊。", "怕被杨花句引、嫁东风。"]'),
('song-ci-760','浪淘沙','苏轼','宋','宋词','song-ci','浪淘沙','[]','昨日出东城。',64,'宋词/ci.song.1000.json','["昨日出东城。", "拭探春情。", "墙头红杏暗如倾。", "槛内群芳芽未吐，早已回春。", "绮陌敛香尘。", "雪霁前村。", "东君用意不辞辛。", "料想春光先到处，吹绽梅英。"]'),
('song-ci-761','木兰花令','苏轼','宋','宋词','song-ci','木兰花令','[]','元宵似是欢游好。',64,'宋词/ci.song.1000.json','["元宵似是欢游好。", "何况公庭民讼少。", "万家游赏上春台，十里神仙迷海岛。", "平原不似高阳傲。", "促席雍容陪语笑。", "坐中有客醉多情，不惜玉山拼醉倒。"]'),
('song-ci-762','木兰花令','苏轼','宋','宋词','song-ci','木兰花令','[]','经旬未识东君信。',64,'宋词/ci.song.1000.json','["经旬未识东君信。", "一夕薰风来解愠。", "红绡衣薄麦秋寒，绿绮韵低梅雨润。", "瓜头绿染山光嫩。", "弄色金桃新傅粉。", "日高慵卷水晶帘，犹带春醪红玉困。"]'),
('song-ci-763','木兰花令','苏轼','宋','宋词','song-ci','木兰花令','[]','高平四面开雄垒。',66,'宋词/ci.song.1000.json','["高平四面开雄垒。", "三月风光初觉媚。", "园中桃李使君家，城上亭台游客醉。", "歌翻《杨柳》金尊沸。", "饮散凭阑无限意。", "云深不见玉关遥，草细山重残照里。"]'),
('song-ci-764','虞美人','苏轼','宋','宋词','song-ci','虞美人','[]','冰肌自是生来瘦。',66,'宋词/ci.song.1000.json','["冰肌自是生来瘦。", "那更分飞后。", "日长帘暮望黄昏。", "及至黄昏时候、转销魂。", "君还知道相思苦。", "怎忍抛奴去。", "不辞迢递过关山。", "只恐别郎容易、见郎难。"]'),
('song-ci-765','虞美人','苏轼','宋','宋词','song-ci','虞美人','[]','深深庭院清明过。',66,'宋词/ci.song.1000.json','["深深庭院清明过。", "桃李初红破。", "柳丝搭在玉阑干。", "帘外潇潇微雨、做轻寒。", "晚晴台榭增明媚。", "已拼花前醉。", "更阑人静月侵廊。", "独自行来行去、好思量。"]'),
('song-ci-766','临江仙','苏轼','宋','宋词','song-ci','临江仙','[]','昨夜渡江何处宿，望中疑是秦淮。',70,'宋词/ci.song.1000.json','["昨夜渡江何处宿，望中疑是秦淮。", "月明谁起笛中哀。", "多情王谢女，相逐过江来。", "云雨未成还又散，思量好事难谐。", "凭陵急桨两相催。", "想伊归去后，应似我情怀。"]'),
('song-ci-767','蝶恋花','苏轼','宋','宋词','song-ci','蝶恋花','[]','春事阑珊芳草歇。',70,'宋词/ci.song.1000.json','["春事阑珊芳草歇。", "客里风光，又过清明节。", "小院黄昏人忆别。", "落红处处闻啼鴂。", "咫尺江山分楚越。", "目断魂销，应是音尘绝。", "梦破五更心欲折。", "角声吹落梅花月。"]'),
('song-ci-768','蝶恋花','苏轼','宋','宋词','song-ci','蝶恋花','[]','记得画屏初会遇。',70,'宋词/ci.song.1000.json','["记得画屏初会遇。", "好梦惊回，望断高唐路。", "燕子双飞来又去。", "纱窗几度春光暮。", "那日绣帘相见处。", "低眼佯行，笑整香云缕。", "敛尽春山羞不语。", "人前深意难轻诉。"]'),
('song-ci-769','蝶恋花','苏轼','宋','宋词','song-ci','蝶恋花','[]','昨夜秋风来万里。',70,'宋词/ci.song.1000.json','["昨夜秋风来万里。", "月上屏帏，冷透人衣袂。", "有客抱衾愁不寐。", "那堪玉漏长如岁。", "羁舍留连归计未。", "梦断魂销，一枕相思泪。", "衣带渐宽无别意。", "新书报我添憔悴。"]'),
('song-ci-770','蝶恋花','苏轼','宋','宋词','song-ci','蝶恋花','[]','雨霰疏疏经泼火。',70,'宋词/ci.song.1000.json','["雨霰疏疏经泼火。", "巷陌秋千。", "犹未清明过。", "杏子梢头香蕾破。", "淡红褪白胭脂涴。", "苦被多情相折挫。", "病绪厌厌，浑似年时个。", "绕遍回廊还独坐。", "月笼云暗重门锁。"]'),
('song-ci-771','蝶恋花','苏轼','宋','宋词','song-ci','蝶恋花','[]','蝶懒莺慵春过半。',70,'宋词/ci.song.1000.json','["蝶懒莺慵春过半。", "花落狂风，小院残红满。", "午醉未醒红日晚。", "黄昏帘暮无人卷。", "云鬓蓬松眉黛浅。", "总是愁媒，欲诉谁消遣。", "未信此情难系绊。", "杨花犹有东风管。"]');
